	private int culWildPoint(SceneBattle_Chara chara)
	{
		int wildPoint = chara.wildPoint;
		int num = 0;
		foreach (SceneBattle_Buff sceneBattle_Buff in chara.buff)
		{
			if (sceneBattle_Buff.buffType == CharaDef.ActionBuffType.ADD_PLASM)
			{
				num += sceneBattle_Buff.increment;
			}
		}
		List<SceneBattle_Chara> list = new List<SceneBattle_Chara>(this._playerList);
		list.AddRange(this._emyWaveList);
		list.AddRange(this._versusList);
		foreach (SceneBattle_Chara sceneBattle_Chara in list)
		{
			foreach (int num2 in sceneBattle_Chara.abilityBuffKey)
			{
				CharaBuffParamAbility charaBuffParamAbility = this._abilityBuffList[num2];
				if (charaBuffParamAbility.giveupReuseNum <= 0 && charaBuffParamAbility.turn <= 0 && charaBuffParamAbility.buffType == CharaDef.ActionBuffType.ADD_PLASM)
				{
					int num3 = this.CheckAbility(CharaDef.ActionBuffType.ADD_PLASM, sceneBattle_Chara, num2, chara);
					while (num3-- > 0)
					{
						num += charaBuffParamAbility.increment;
					}
				}
			}
		}
		if (wildPoint + num < 0)
		{
			return 0;
		}
		return wildPoint + num;
	}

	private float seqDmg(int c)
	{
		return this._battleParam.sequenceDamage[(c < this._battleParam.sequenceDamage.Length) ? c : (this._battleParam.sequenceDamage.Length - 1)];
	}

	private float seqHel(int c)
	{
		return this._battleParam.sequenceHeal[(c < this._battleParam.sequenceHeal.Length) ? c : (this._battleParam.sequenceHeal.Length - 1)];
	}

	private float chainDmg(int c)
	{
		return this._battleParam.chainBeat[((c <= this._battleParam.chainBeat.Length) ? c : this._battleParam.chainBeat.Length) - 1];
	}

	private int chainKp(int c)
	{
		return this._battleParam.chainAction[((c <= this._battleParam.chainAction.Length) ? c : this._battleParam.chainAction.Length) - 1];
	}

	private int chainWild(int c)
	{
		return this._battleParam.chainTry[((c <= this._battleParam.chainTry.Length) ? c : this._battleParam.chainTry.Length) - 1];
	}

	private int chainAct(int c)
	{
		return this._battleParam.chainBowl[((c - 1 <= this._battleParam.chainBowl.Length) ? (c - 1) : this._battleParam.chainBowl.Length) - 1];
	}

	private int touchCard
	{
		get
		{
			for (int i = 0; i < this._guiData.TouchChara.Count; i++)
			{
				if (this._currentTouch == this._guiData.TouchChara[i] && (this._tutorialStep == SceneBattle.TutorialStep.NONE || this._tutorialCard == i + 1))
				{
					return i + 1;
				}
			}
			return 0;
		}
	}

	private int touchArts
	{
		get
		{
			for (int i = 0; i < this._guiData.TouchArts.Count; i++)
			{
				if (this._currentTouch == this._guiData.TouchArts[i] && (this._tutorialStep == SceneBattle.TutorialStep.NONE || this._tutorialCard == i + 1 || this._tutorialArts == i + 1))
				{
					return i + 1;
				}
			}
			return 0;
		}
	}

	private bool touchAddAction
	{
		get
		{
			return this._currentTouch == this._guiData.TouchActGage && (this._tutorialStep == SceneBattle.TutorialStep.NONE || this._tutorialAdd);
		}
	}

	private int touchTarget
	{
		get
		{
			foreach (SceneBattle_Enemy sceneBattle_Enemy in this._emyWaveList)
			{
				if (this._currentTouch == sceneBattle_Enemy.touchGage && this._tutorialStep == SceneBattle.TutorialStep.NONE)
				{
					SoundManager.Play("prd_se_click", false, false);
					return sceneBattle_Enemy.idx;
				}
			}
			foreach (SceneBattle_Friends sceneBattle_Friends in this._versusList)
			{
				if (this._currentTouch == sceneBattle_Friends.touchGage && this._tutorialStep == SceneBattle.TutorialStep.NONE)
				{
					SoundManager.Play("prd_se_click", false, false);
					return sceneBattle_Friends.idx;
				}
			}
			return 9999;
		}
	}

	private bool btnSkill
	{
		get
		{
			return (this._tutorialStep == SceneBattle.TutorialStep.NONE || this._tutorialSkill) && this._currentBtn == this._guiData.BtnPlayerSkill;
		}
	}

	private bool btnInfo
	{
		get
		{
			return (this._tutorialStep == SceneBattle.TutorialStep.NONE || this._tutorialSkill) && this._currentBtn == this._guiData.BtnInfoSkill;
		}
	}

	private bool btnCancel
	{
		get
		{
			return this._tutorialStep == SceneBattle.TutorialStep.NONE && this.cancelCardBtn;
		}
	}

	public static long GetRestart(out bool pvp, out bool training, out bool practice)
	{
		pvp = false;
		training = false;
		practice = false;
		long num = 0L;
		if (PlayerPrefs.HasKey(SceneBattle.battleRestartKey))
		{
			SceneBattle_SceneBattleRestartArgs sceneBattle_SceneBattleRestartArgs = PrjJson.FromJson<SceneBattle_SceneBattleRestartArgs>(PlayerPrefs.GetString(SceneBattle.battleRestartKey));
			if (sceneBattle_SceneBattleRestartArgs == null || sceneBattle_SceneBattleRestartArgs.battleArgs == null)
			{
				PlayerPrefs.DeleteKey(SceneBattle.battleRestartKey);
			}
			else
			{
				pvp = sceneBattle_SceneBattleRestartArgs.battleArgs.oppUser != null;
				training = !pvp && sceneBattle_SceneBattleRestartArgs.battleArgs.trainingTurn > 0;
				practice = training && sceneBattle_SceneBattleRestartArgs.battleArgs.isPractice;
				num = sceneBattle_SceneBattleRestartArgs.getHash();
			}
		}
		return num;
	}

	public static bool IsRestart()
	{
		return PlayerPrefs.HasKey(SceneBattle.battleRestartKey);
	}

	public static void DeleteRestart()
	{
		PlayerPrefs.DeleteKey(SceneBattle.battleRestartKey);
	}

	public static void SetRestart(SceneBattleArgs args)
	{
		new SceneBattle_SceneBattleRestartArgs(args);
	}

