	public override bool OnCreateSceneWait()
	{
		bool flag = true;
		if (this._effectListDictionary.ContainsKey(0))
		{
			foreach (string text in this._effectListDictionary[0])
			{
				flag &= EffectManager.IsLoadFinishEffect(text);
			}
		}
		if (this._seLoad.MoveNext())
		{
			flag = false;
		}
		return flag;
	}

