	private List<float> CalcPosition(List<float> widthList)
	{
		List<float> list = new List<float>();
		if (widthList.Count > 2)
		{
			float num = 0f;
			foreach (float num2 in widthList)
			{
				num += num2;
			}
			float num3 = SceneBattle.widthAlign;
			if (num3 < num)
			{
				num3 = num;
			}
			float num4 = (num3 - num) / (float)(widthList.Count - 1);
			float num5 = -num3 * 0.5f;
			using (List<float>.Enumerator enumerator = widthList.GetEnumerator())
			{
				while (enumerator.MoveNext())
				{
					float num6 = enumerator.Current;
					list.Add(num5 + num6 * 0.5f);
					num5 += num6 + num4;
				}
				return list;
			}
		}
		if (widthList.Count > 1)
		{
			float num7 = SceneBattle.widthAlign * 0.5f;
			if (num7 < widthList[0])
			{
				num7 = widthList[0];
			}
			list.Add(-num7 * 0.5f);
			num7 = SceneBattle.widthAlign * 0.5f;
			if (num7 < widthList[1])
			{
				num7 = widthList[1];
			}
			list.Add(num7 * 0.5f);
		}
		else if (widthList.Count > 0)
		{
			list.Add(0f);
		}
		return list;
	}

	private void SetGuts(List<SceneBattle_Chara> chrList, Dictionary<SceneBattle_Chara, List<CharaGutsParamAbility>> gutsList)
	{
		foreach (KeyValuePair<SceneBattle_Chara, List<CharaGutsParamAbility>> keyValuePair in gutsList)
		{
			foreach (CharaGutsParamAbility charaGutsParamAbility in keyValuePair.Value)
			{
