					{
						if (this.IsTargetAttribute(keyValuePair.Key, keyValuePair.Key, charaGutsParamAbility.attributeMask, charaGutsParamAbility.invertAttributeMask))
						{
							keyValuePair.Key.guts += charaGutsParamAbility.numOfTimes;
						}
					}
					else
					{
						if (charaGutsParamAbility.targetType == CharaDef.ActionTargetType.MY_SIDE_ALL)
						{
							using (List<SceneBattle_Chara>.Enumerator enumerator3 = chrList.GetEnumerator())
							{
								while (enumerator3.MoveNext())
								{
									SceneBattle_Chara sceneBattle_Chara = enumerator3.Current;
									if (this.IsTargetAttribute(keyValuePair.Key, sceneBattle_Chara, charaGutsParamAbility.attributeMask, charaGutsParamAbility.invertAttributeMask))
									{
										sceneBattle_Chara.guts += charaGutsParamAbility.numOfTimes;
									}
								}
								continue;
							}
						}
						if (charaGutsParamAbility.targetType == CharaDef.ActionTargetType.WITHOUT_SELF)
						{
							List<SceneBattle_Chara> list = new List<SceneBattle_Chara>();
							foreach (SceneBattle_Chara sceneBattle_Chara2 in chrList)
							{
								if (sceneBattle_Chara2 != keyValuePair.Key && this.IsTargetAttribute(keyValuePair.Key, sceneBattle_Chara2, charaGutsParamAbility.attributeMask, charaGutsParamAbility.invertAttributeMask))
								{
									list.Add(sceneBattle_Chara2);
								}
							}
							if (list.Count > 0)
							{
								list[Random.Range(0, list.Count)].guts += charaGutsParamAbility.numOfTimes;
							}
						}
