								}
							}
						}
					}
				}
			}
		}
	}

	private void LoadEffect(CharaStaticAction param, int lvl)
	{
		if (param == null)
		{
			return;
		}
		this.LoadEffect(param.motionParam.charaEffectName, lvl);
		if (param.damageList != null)
		{
			foreach (CharaDamageParam charaDamageParam in param.damageList)
			{
				this.LoadEffect(charaDamageParam.actionEffect, lvl);
			}
		}
		if (param.buffList != null)
		{
			foreach (CharaBuffParam charaBuffParam in param.buffList)
			{
				this.LoadEffect(charaBuffParam.actionEffect, lvl);
			}
		}
	}

	private void LoadEffect(ActionEffectParam param, int lvl)
	{
		if (param == null)
		{
			return;
		}
		this.LoadEffect(param.effectName, lvl);
		this.LoadEffect(param.hitEffectName, lvl);
	}

	private void LoadEffect(string eff, int lvl)
	{
		if (string.IsNullOrEmpty(eff))
		{
			return;
		}
		if (!this._effectListDictionary.ContainsKey(lvl))
		{
			this._effectListDictionary[lvl] = new List<string>();
		}
		else if (this._effectListDictionary[lvl].Contains(eff))
		{
			return;
		}
		this._effectListDictionary[lvl].Add(eff);
		EffectManager.ReqLoadEffect(eff, AssetManager.OWNER.Battle, 0, null);
	}

