	private bool ChkWaveEnemy(CharaDef.EnemyMask msk, bool invertMask, CharaDef.Type typ, int emy, CharaDef.ConditionType emyTyp, int my, CharaDef.ConditionType myTyp, bool now)
	{
		if (!this.IsConditionMask(invertMask, (long)this._waveEnemy, (long)msk))
		{
			return false;
		}
		int num = 0;
		int num2 = 0;
		foreach (SceneBattle_Friends sceneBattle_Friends in this._playerList)
		{
			if ((now ? sceneBattle_Friends.nowHp : sceneBattle_Friends.newHp) > sceneBattle_Friends.escapeHp)
			{
				num++;
			}
		}
		foreach (SceneBattle_Enemy sceneBattle_Enemy in this._emyWaveList)
		{
			if ((now ? sceneBattle_Enemy.nowHp : sceneBattle_Enemy.newHp) > sceneBattle_Enemy.escapeHp && sceneBattle_Enemy.chara != null)
			{
				num2++;
			}
		}
		foreach (SceneBattle_Friends sceneBattle_Friends2 in this._versusList)
		{
			if ((now ? sceneBattle_Friends2.nowHp : sceneBattle_Friends2.newHp) > sceneBattle_Friends2.escapeHp)
			{
				num2++;
			}
		}
		if (emy > 0)
		{
			int num3 = ((typ == CharaDef.Type.FRIENDS) ? num2 : num);
			if (emyTyp == CharaDef.ConditionType.UPPER)
			{
				if (num3 < emy)
				{
					return false;
				}
			}
			else if (emyTyp == CharaDef.ConditionType.LOWER)
			{
				if (num3 > emy)
				{
					return false;
				}
			}
			else if (num3 != emy)
			{
				return false;
			}
		}
		if (my > 0)
		{
			int num4 = ((typ == CharaDef.Type.FRIENDS) ? num : num2);
			if (myTyp == CharaDef.ConditionType.UPPER)
			{
				if (num4 < my)
				{
					return false;
				}
			}
			else if (myTyp == CharaDef.ConditionType.LOWER)
			{
				if (num4 > my)
				{
					return false;
				}
			}
			else if (num4 != my)
			{
				return false;
			}
		}
		return true;
	}

	private void ReviveTrainingBoss(SceneBattle_Enemy bos)
	{
		bos.maxHp = (int)((float)bos.maxHp * ((float)this._resultArgs.battleArgs.trainingHp / 1000f));
		bos.atkPwr = (int)((float)bos.atkPwr * ((float)this._resultArgs.battleArgs.trainingAtk / 1000f));
		bos.defPwr = (int)((float)bos.defPwr * ((float)this._resultArgs.battleArgs.trainingDef / 1000f));
	}

	private void ReviveTraining()
	{
		this._trainingRevive++;
		this._menuGui.numWave.text = this._trainingRevive.ToString();
		if (this._trainingRevive >= this._trainingMission + this._trainingMissionNum)
		{
			this._trainingMission += this._trainingMissionNum;
			if (this._trainingMissionList.Count > 0)
			{
				this._trainingMissionStep = 1;
			}
		}
	}

	private void ResetStatus()
	{
		List<SceneBattle_Chara> list = new List<SceneBattle_Chara>(this._playerList);
		list.AddRange(this._emyWaveList);
		list.AddRange(this._versusList);
		foreach (SceneBattle_Chara sceneBattle_Chara in list)
		{
			sceneBattle_Chara.newBuff = new List<SceneBattle_Buff>();
			foreach (SceneBattle_Buff sceneBattle_Buff in sceneBattle_Chara.buff)
			{
				sceneBattle_Chara.newBuff.Add((sceneBattle_Buff.giveupNum > 0) ? sceneBattle_Buff : sceneBattle_Buff.clone());
			}
			sceneBattle_Chara.newGuts = sceneBattle_Chara.guts;
			sceneBattle_Chara.newHp = sceneBattle_Chara.nowHp;
			sceneBattle_Chara.newKp = sceneBattle_Chara.nowKp;
			sceneBattle_Chara.newRecover = new List<int>(sceneBattle_Chara.recover);
		}
	}

	private bool ReflectStatus(string typ)
	{
		this.CheckGuts();
		this.CheckIce(null, false);
		this.CheckSleep();
		bool flag = true;
		List<SceneBattle_Chara> list = new List<SceneBattle_Chara>(this._playerList);
		list.AddRange(this._emyWaveList);
		list.AddRange(this._versusList);
		foreach (SceneBattle_Chara sceneBattle_Chara in list)
		{
			int num = sceneBattle_Chara.nowHp;
			if (num < sceneBattle_Chara.escapeHp)
			{
				num = sceneBattle_Chara.escapeHp;
			}
			int num2 = sceneBattle_Chara.newHp;
			if (num2 < sceneBattle_Chara.escapeHp)
			{
				num2 = sceneBattle_Chara.escapeHp;
			}
			if (sceneBattle_Chara.buff.Count != sceneBattle_Chara.newBuff.Count || sceneBattle_Chara.guts != sceneBattle_Chara.newGuts || num != num2 || sceneBattle_Chara.nowKp != sceneBattle_Chara.newKp || sceneBattle_Chara.recover.Count != sceneBattle_Chara.newRecover.Count)
			{
				flag = false;
			}
		}
		return flag;
	}

	private void EntryFriends(List<SceneBattle_Friends> friendsList)
	{
		using (List<SceneBattle_Friends>.Enumerator enumerator = friendsList.GetEnumerator())
		{
			while (enumerator.MoveNext())
			{
				SceneBattle_Friends friends = enumerator.Current;
				List<SceneBattle_Friends> tfBeforeList = this._tfBeforeList;
				SceneBattle_Friends sceneBattle_Friends = ((tfBeforeList != null) ? tfBeforeList.Find((SceneBattle_Friends itm) => itm.number == friends.number) : null);
				if (sceneBattle_Friends == null)
				{
					if (!friends.chara.IsPlaying() && friends.entNum > 0)
					{
						SceneBattle_Friends friends2 = friends;
						int num = friends2.entNum - 1;
						friends2.entNum = num;
						if (num > 0)
						{
							friends.chara.PlayAnimation(CharaMotionDefine.ActKey.ENTRY_LP, false, 1f, 0f, 0f, false);
							Vector3 pos = friends.pos;
							if (friends.entNum > 0)
							{
								pos.z += friends.entEn + friends.entLp * (float)(friends.entNum - 1);
							}
							friends.chara.SetPosition(pos);
						}
						else
						{
							friends.chara.PlayAnimation(CharaMotionDefine.ActKey.ENTRY_EN, false, 1f, 0f, 0f, false);
							Vector3 pos2 = friends.pos;
							if (friends.entNum > 0)
							{
								pos2.z += friends.entEn + friends.entLp * (float)(friends.entNum - 1);
							}
							friends.chara.SetPosition(pos2);
						}
					}
				}
				else if (!sceneBattle_Friends.chara.IsPlaying() && sceneBattle_Friends.entNum > 0)
				{
					SceneBattle_Friends sceneBattle_Friends2 = sceneBattle_Friends;
					int num = sceneBattle_Friends2.entNum - 1;
					sceneBattle_Friends2.entNum = num;
					if (num > 0)
					{
						friends.entNum--;
						sceneBattle_Friends.chara.PlayAnimation(CharaMotionDefine.ActKey.ENTRY_LP, false, 1f, 0f, 0f, false);
						friends.chara.PlayAnimation(CharaMotionDefine.ActKey.ENTRY_LP, false, 1f, 0f, 0f, false);
						Vector3 pos3 = sceneBattle_Friends.pos;
						Vector3 pos4 = friends.pos;
						if (sceneBattle_Friends.entNum > 0)
						{
							pos3.z += sceneBattle_Friends.entEn + sceneBattle_Friends.entLp * (float)(sceneBattle_Friends.entNum - 1);
						}
						if (friends.entNum > 0)
						{
							pos4.z += friends.entEn + friends.entLp * (float)(friends.entNum - 1);
						}
						sceneBattle_Friends.chara.SetPosition(pos3);
						friends.chara.SetPosition(pos4);
					}
					else
					{
						friends.entNum--;
						sceneBattle_Friends.chara.PlayAnimation(CharaMotionDefine.ActKey.ENTRY_EN, false, 1f, 0.2f, 0.1f, false);
						friends.chara.PlayAnimation(CharaMotionDefine.ActKey.ENTRY_EN, false, 1f, 0f, 0f, false);
						Vector3 pos5 = sceneBattle_Friends.pos;
						Vector3 pos6 = friends.pos;
						if (sceneBattle_Friends.entNum > 0)
						{
							pos5.z += sceneBattle_Friends.entEn + sceneBattle_Friends.entLp * (float)(sceneBattle_Friends.entNum - 1);
						}
						if (friends.entNum > 0)
						{
							pos6.z += friends.entEn + friends.entLp * (float)(friends.entNum - 1);
						}
						sceneBattle_Friends.chara.SetPosition(pos5);
						friends.chara.SetPosition(pos6);
					}
				}
				else if (!sceneBattle_Friends.chara.IsPlaying() && sceneBattle_Friends.entNum <= 0)
				{
					sceneBattle_Friends.chara.SetModelActive(false);
				}
			}
		}
	}

	private void PlayVoice(SceneBattle_Chara chr, CharaVoiceCombi.SitType st, VOICE_TYPE vt)
	{
		List<SceneBattle_Friends> friendsList = new List<SceneBattle_Friends>();
		if (chr.type == CharaDef.Type.FRIENDS)
		{
			friendsList = this._playerList;
		}
		else if (chr.type == CharaDef.Type.INVALID)
		{
			friendsList = this._versusList;
		}
		List<CharaVoiceCombi> list = DataManager.DmChara.GetCharaVoiceCombiList(st, chr.charaId).FindAll((CharaVoiceCombi itm) => friendsList.Find((SceneBattle_Friends itm2) => itm2.charaId == itm.secondCharaId && itm2.nowHp > itm2.escapeHp && !this.IsStun(itm2, false) && !this.IsSleep(itm2, false)) != null);
		if (st == CharaVoiceCombi.SitType.CHARA_CHAIN)
		{
			List<SceneBattle_FriendsCommand> list2 = new List<SceneBattle_FriendsCommand>();
			int num = 0;
			if (chr.type == CharaDef.Type.FRIENDS)
			{
				list2 = this._plyCmdList;
				num = this._plyCmdCtr;
			}
			else if (chr.type == CharaDef.Type.INVALID)
			{
				list2 = this._vssCmdList;
				num = this._vssCmdCtr;
			}
			List<int> charaIdList = new List<int>();
			int num2 = num + 1;
			while (num2 < list2.Count && list2[num2].chain > 0)
			{
				charaIdList.Add(list2[num2].chara.charaId);
				num2++;
			}
			List<CharaVoiceCombi> list3 = list.FindAll((CharaVoiceCombi itm) => charaIdList.Contains(itm.secondCharaId));
			if (list3.Count > 0)
			{
				list = list3;
			}
		}
		if (list.Count > 0)
		{
			CharaVoiceCombi charaVoiceCombi = list[Random.Range(0, list.Count)];
			string text = charaVoiceCombi.firstVoiceName;
			if (string.IsNullOrEmpty(text))
			{
				text = SoundManager.CreateVoiceNameByType(chr.chara.loadVoiceCueSheetName, vt);
			}
			float num3 = 0f;
			if (!string.IsNullOrEmpty(text))
			{
				SoundManager.PlayVoice(chr.chara.loadVoiceCueSheetName, text);
				num3 = SoundManager.GetVoiceLength(chr.chara.loadVoiceCueSheetName, text);
			}
			SceneBattle_Friends sceneBattle_Friends = friendsList.Find((SceneBattle_Friends itm) => itm.charaId == charaVoiceCombi.secondCharaId);
			if (sceneBattle_Friends != null)
			{
				text = charaVoiceCombi.secondVoiceName;
				if (string.IsNullOrEmpty(text))
				{
					text = SoundManager.CreateVoiceNameByType(sceneBattle_Friends.chara.loadVoiceCueSheetName, vt);
				}
				if (!string.IsNullOrEmpty(text))
				{
					this._combiVoiceList.Add(new SceneBattle_CombiVoice
					{
						delay = num3,
						sheet = sceneBattle_Friends.chara.loadVoiceCueSheetName,
						voice = text
					});
					return;
				}
			}
		}
		else if (chr.chara == null)
		{
			SceneBattle_Enemy sceneBattle_Enemy = chr as SceneBattle_Enemy;
			if (sceneBattle_Enemy != null && sceneBattle_Enemy.body != null)
			{
				SoundManager.PlayVoice(sceneBattle_Enemy.body.chara.loadVoiceCueSheetName, vt);
				return;
			}
		}
		else
		{
			SoundManager.PlayVoice(chr.chara.loadVoiceCueSheetName, vt);
		}
	}

	public override bool OnEnableSceneWait()
	{
		bool flag = true;
		foreach (string text in this._pvpAuthNameList)
		{
			flag &= AssetManager.IsLoadFinishAssetData(text);
		}
		foreach (SceneBattle_Friends sceneBattle_Friends in this._playerList)
		{
			if (sceneBattle_Friends.chara.IsFinishInitialize())
			{
				if (sceneBattle_Friends.entNum < 0)
				{
					sceneBattle_Friends.entNum = -sceneBattle_Friends.entNum;
					sceneBattle_Friends.chara.transform.position = Vector3.zero;
					sceneBattle_Friends.chara.PlayAnimationByAuth(CharaMotionDefine.ActKey.ENTRY_EN.ToString(), 0f, 0f, false);
					flag = false;
				}
				else if (sceneBattle_Friends.entEn > 0f)
				{
					if ((sceneBattle_Friends.entEn = sceneBattle_Friends.chara.GetHaraPos().z) > -0.1f)
					{
						sceneBattle_Friends.entEn = -0.1f;
					}
					sceneBattle_Friends.chara.transform.position = Vector3.zero;
					sceneBattle_Friends.chara.PlayAnimationByAuth(CharaMotionDefine.ActKey.ENTRY_LP.ToString(), 0f, 0f, false);
					flag = false;
				}
				else if (sceneBattle_Friends.entLp > 0f && (sceneBattle_Friends.entLp = sceneBattle_Friends.chara.GetHaraPos().z) > -0.1f)
				{
					sceneBattle_Friends.entLp = -0.1f;
				}
			}
			else
			{
				flag = false;
			}
			if (sceneBattle_Friends.icon == null)
			{
				if (AssetManager.IsLoadFinishAssetData(sceneBattle_Friends.iconName))
				{
					sceneBattle_Friends.icon = AssetManager.GetAssetData(sceneBattle_Friends.iconName) as Texture2D;
				}
				else
				{
					flag = false;
				}
			}
		}
		using (List<SceneBattle_Friends>.Enumerator enumerator2 = this._playerList.GetEnumerator())
		{
			while (enumerator2.MoveNext())
			{
				SceneBattle_Friends ply = enumerator2.Current;
				List<SceneBattle_Friends> tfBeforeList = this._tfBeforeList;
				SceneBattle_Friends sceneBattle_Friends2 = ((tfBeforeList != null) ? tfBeforeList.Find((SceneBattle_Friends itm) => itm.number == ply.number) : null);
				if (sceneBattle_Friends2 != null)
				{
					if (sceneBattle_Friends2.chara.IsFinishInitialize())
					{
						if (sceneBattle_Friends2.entNum < 0)
						{
							sceneBattle_Friends2.entNum = -sceneBattle_Friends2.entNum;
							sceneBattle_Friends2.chara.transform.position = Vector3.zero;
							sceneBattle_Friends2.chara.PlayAnimationByAuth(CharaMotionDefine.ActKey.ENTRY_EN.ToString(), 0f, 0f, false);
							flag = false;
						}
