						sceneBattle_Friends7.chara.transform.localPosition = sceneBattle_Friends7.pos + new Vector3(0f, 0f, sceneBattle_Friends7.entEn + sceneBattle_Friends7.entLp * (float)(sceneBattle_Friends7.entNum - 1));
					}
					if (!string.IsNullOrEmpty(ply.entEff))
					{
						EffectData effectData4 = EffectManager.InstantiateEffect(ply.entEff, this._effect, SceneBattle.effectLayer, 1f);
						effectData4.effectObject.transform.localPosition = ply.pos;
						effectData4.PlayEffect(false);
						this.SetCamouflageEffect(effectData4);
						this._effectDataList.Add(effectData4);
						ply.entEff = null;
					}
				}
				ply.hpGage.SetActive(false);
				if (!flag)
				{
					ply.nowHp = ply.maxHp;
				}
			}
		}
		foreach (SceneBattle_Enemy sceneBattle_Enemy4 in this._emyWaveList)
		{
			if (sceneBattle_Enemy4.chara != null && sceneBattle_Enemy4.chara.IsFinishInitialize() && sceneBattle_Enemy4.chara.IsModelActive())
			{
				sceneBattle_Enemy4.chara.SetEnableUpdateOffscreen();
				sceneBattle_Enemy4.chara.FadeIn(0f);
			}
			sceneBattle_Enemy4.hpGage.SetActive(false);
		}
		foreach (SceneBattle_Friends sceneBattle_Friends8 in this._versusList)
		{
			sceneBattle_Friends8.chara.SetEnableUpdateOffscreen();
			sceneBattle_Friends8.chara.FadeIn(0f);
			if (flag)
			{
				sceneBattle_Friends8.chara.PlayAnimation((sceneBattle_Friends8.nowHp > sceneBattle_Friends8.escapeHp) ? CharaMotionDefine.ActKey.IDLING : CharaMotionDefine.ActKey.PVP_DEATH_LP, false, 1f, 0f, 0f, false);
				sceneBattle_Friends8.chara.transform.localPosition = (sceneBattle_Friends8.hpPos = (sceneBattle_Friends8.pos += new Vector3(0f, 0f, sceneBattle_Friends8.offZ)));
			}
			else if (SceneBattle.pvpTraining == 0)
			{
				sceneBattle_Friends8.chara.transform.localPosition = (sceneBattle_Friends8.hpPos = (sceneBattle_Friends8.pos += new Vector3(0f, 0f, sceneBattle_Friends8.offZ)));
			}
			else
			{
				sceneBattle_Friends8.chara.PlayAnimation(CharaMotionDefine.ActKey.ENTRY_LP, false, 1f, 0f, 0f, false);
				sceneBattle_Friends8.chara.transform.localPosition = sceneBattle_Friends8.pos + new Vector3(0f, 0f, sceneBattle_Friends8.entEn + sceneBattle_Friends8.entLp * (float)(sceneBattle_Friends8.entNum - 1));
				if (!string.IsNullOrEmpty(sceneBattle_Friends8.entEff))
				{
					EffectData effectData5 = EffectManager.InstantiateEffect(sceneBattle_Friends8.entEff, this._effect, SceneBattle.effectLayer, 1f);
					effectData5.effectObject.transform.localPosition = sceneBattle_Friends8.pos;
					effectData5.PlayEffect(false);
					this.SetCamouflageEffect(effectData5);
					this._effectDataList.Add(effectData5);
					sceneBattle_Friends8.entEff = null;
				}
			}
			sceneBattle_Friends8.hpGage.SetActive(false);
			if (!flag)
			{
				sceneBattle_Friends8.nowHp = sceneBattle_Friends8.maxHp;
			}
		}
		if (!flag && ((SceneBattle.pvpBattle && SceneBattle.pvpTraining == 0) || SceneBattle.friendsBattle || SceneBattle.trainingBattle))
		{
			this.PlayPvpAuth(0);
			int num = 1;
			foreach (SceneBattle_Friends sceneBattle_Friends9 in this._playerList)
			{
				this._pvpAuthChr.Add(num++, sceneBattle_Friends9.chara);
			}
			if (SceneBattle.trainingBattle)
			{
				foreach (CharaModelHandle charaModelHandle in this._pvpAuthLcy.Values)
				{
					charaModelHandle.SetModelActive(true);
				}
				this._pvpAuthLcy[6].PlayAnimation(CharaMotionDefine.ActKey.BIRD_IN, true, 1f, 0f, 0f, false);
				this._pvpAuthLcy[7].PlayAnimation(CharaMotionDefine.ActKey.BIRD_IN, true, 1f, 0f, 0f, false);
				this._pvpAuthFlg = 10;
				this._camera.fieldCamera.cullingMask &= ~(1 << SceneBattle.enemyLayer) & ~(1 << SceneBattle.enemyShadowLayer) & ~(1 << SceneBattle.enemyBloomLayer);
				this.SetTrainingVoice(0, 0.3f);
			}
			else
			{
				num = 6;
				foreach (SceneBattle_Friends sceneBattle_Friends10 in this._versusList)
				{
					this._pvpAuthChr.Add(num++, sceneBattle_Friends10.chara);
				}
			}
		}
		this.SetTrainingScore(true);
		this.DispCardInfo();
	}

	private void SetTrainingVoice(int typ, float dly)
	{
		for (int i = 0; i < SceneBattle.trainingVoiceList.GetLength(1); i++)
		{
			string text = SceneBattle.trainingVoiceList[typ, i];
			this._combiVoiceList.Add(new SceneBattle_CombiVoice
			{
				delay = dly,
				sheet = SceneBattle.trainingVoiceSheet,
				voice = text
			});
			dly += SoundManager.GetVoiceLength(SceneBattle.trainingVoiceSheet, text);
		}
	}

	public override void OnStartSceneFadeWait()
	{
		if (!SceneBattle.pvpBattle && !SceneBattle.friendsBattle && !SceneBattle.trainingBattle)
		{
			this.EntryFriends(this._playerList);
		}
		else if (SceneBattle.pvpTraining != 0)
		{
			this.EntryFriends(this._playerList);
			this.EntryFriends(this._versusList);
		}
		this.HugeModelDisp();
		this.SetCamera();
	}

	public override void OnStartControl()
	{
		Screen.sleepTimeout = ((this._autoOrder > 0 || this._noCaptain || SceneBattle.pvpTraining != 0) ? (-1) : (-2));
		TimeManager.TimeScale = ((this._step == SceneBattle.STEP.ReStart || SceneBattle.trainingBattle) ? 1f : (this._superSpeed ? 10f : ((this._timeScale > 0) ? 2f : 1f)));
		if (!SceneBattle.pvpBattle && !SceneBattle.friendsBattle && !SceneBattle.trainingBattle)
		{
			this.EntryFriends(this._playerList);
		}
		else if (SceneBattle.pvpTraining != 0)
		{
			this.EntryFriends(this._playerList);
			this.EntryFriends(this._versusList);
		}
		this.HugeModelDisp();
		this.SetCamera();
		this._tutorialPanelSkip.SetActive(true);
	}

	private void OnClickButton(PguiButtonCtrl button)
	{
		if (this._continueStep == 0 && this._debugStep == 0 && !this._debugPanel.activeSelf && this._menuStep == 0 && this._trainingMissionStep == 0 && this._tacticsStep == 0 && this._tutorialSkip == 0 && !this._menuPanel.activeSelf && this._step > SceneBattle.STEP.ReStart && this._step < SceneBattle.STEP.GameClear && !this._authPlayer.gameObject.activeSelf)
		{
			if (button == this._guiData.BtnMenu)
			{
				if (this._guiData.BtnMenu.gameObject.activeSelf && this._guiData.BtnMenu.ActEnable && this._tutorialStep == SceneBattle.TutorialStep.NONE && !this._tutorialPanel.activeSelf)
				{
					this._menuStep = 1;
					return;
				}
			}
			else
			{
				this._currentBtn = button;
			}
		}
	}

	private void OnClickCancelCard(PguiButtonCtrl button)
	{
		this.cancelCardBtn = true;
	}

	private void ClearBtn()
	{
		this._currentBtn = null;
		this.cancelCardBtn = false;
	}

	private bool OnClickToggle(PguiToggleButtonCtrl toggle, int index)
	{
		bool flag = false;
		if (this._tutorialStep == SceneBattle.TutorialStep.NONE && this._continueStep == 0 && this._debugStep == 0 && !this._debugPanel.activeSelf && this._menuStep == 0 && this._trainingMissionStep == 0 && this._tacticsStep == 0 && this._tutorialSkip == 0 && !this._menuPanel.activeSelf && this._step > SceneBattle.STEP.ReStart && this._step < SceneBattle.STEP.GameClear && !this._authPlayer.gameObject.activeSelf && ((this._step != SceneBattle.STEP.PlayerTurn && this._step != SceneBattle.STEP.VersusTurn) || this._subStep != SceneBattle.SUBSTEP.Arts))
		{
			if (toggle == this._guiData.BtnAuto)
			{
				if (this._autoOrder >= 0 && !this._noCaptain && SceneBattle.pvpTraining == 0)
				{
					this._autoOrder = ((index == 0) ? 1 : 0);
					flag = true;
					Screen.sleepTimeout = ((this._autoOrder > 0) ? (-1) : (-2));
				}
			}
			else if (toggle == this._guiData.BtnFast && this._timeScale >= 0)
			{
				this._timeScale = ((index == 0) ? 1 : 0);
				flag = true;
				TimeManager.TimeScale = (this._superSpeed ? 10f : ((this._timeScale > 0) ? 2f : 1f));
				if (this._step >= SceneBattle.STEP.PlayerTurn)
				{
					EffectData playingAttackEffect = this._playingAttackEffect;
					if (playingAttackEffect != null)
					{
						playingAttackEffect.UpdateEffectSESpeed(this._timeScale > 0);
					}
				}
			}
		}
		if (flag)
		{
			SoundManager.Play("prd_se_click", false, false);
		}
		return flag;
	}

	private void OnClickTouch(Transform touch)
	{
		this._currentTouch = touch;
	}

	private void ClearTouch()
	{
		this._currentTouch = null;
	}

	private void OnClickMenu(PguiButtonCtrl button)
	{
		if (this._menuStep > 0 && this._retireStep == 0 && this._infoStep == 0)
		{
			if (button == this._menuGui.btnInfo)
			{
				this._infoStep = 1;
				return;
			}
			if (button == this._menuGui.btnRetire)
			{
				this._retireStep = 1;
				return;
			}
			this._menuStep = -1;
		}
	}

	private bool RetireWindow(int index)
	{
		if (this._menuStep > 0 && this._retireStep < 0 && index == 1)
		{
			this._step = SceneBattle.STEP.Retire;
			this._subStep = SceneBattle.SUBSTEP.Init;
			this._stepCtr = 0;
			this._menuStep = -1;
		}
		this._retireStep = 0;
		return true;
	}

	private void OnClickInfo(PguiButtonCtrl button)
	{
		if (this._menuStep > 0 && this._infoStep > 0)
		{
			if (button == this._infoGui.btnLeft)
			{
				this.SetCharaInfo(this._infoNo - 1);
				this._infoGui.anim.ExPlayAnimation(SimpleAnimation.ExPguiStatus.START_SUB, null);
				return;
			}
			if (button == this._infoGui.btnRight)
			{
				this.SetCharaInfo(this._infoNo + 1);
				this._infoGui.anim.ExPlayAnimation(SimpleAnimation.ExPguiStatus.START_SUB, null);
				return;
			}
			this._infoStep = -1;
		}
	}

	private bool OnClickInfoTab(int index)
	{
		if (this._menuStep > 0 && this._infoStep > 0 && this._infoTyp != index)
		{
			this._infoTyp = index;
			this._infoGui.infStatus.SetActive(this._infoTyp == 0);
			this._infoGui.infSkill.SetActive(this._infoTyp == 1);
			this._infoGui.infBuff.SetActive(this._infoTyp == 2);
			return true;
		}
		return false;
	}

