	private void SetupInfoBuff(int index, GameObject go)
	{
		SceneBattle_InfoBuff sceneBattle_InfoBuff = ((index >= 0 && index < this._infoBuffList.Count) ? this._infoBuffList[index] : new SceneBattle_InfoBuff(CharaDef.ActionBuffType.INVALID, 0L, (CharaDef.AttributeMask)0, (CharaDef.HealthMask)0, (CharaDef.EnemyMask)0, -1, -1, false, 0, ""));
		this.SetupInfoBuff(sceneBattle_InfoBuff, go.transform);
	}

	private void SetupInfoBuff(SceneBattle_InfoBuff inf, Transform tmp)
	{
		string text = this.GetBuffName(inf.Type);
		string text2 = text;
		int num = SceneBattle.GetBuffIcon(inf.Type, inf.Attribute, inf.Health);
		int num2 = inf.Turn;
		string text3 = "ターン";
		bool flag = false;
		int num3 = 0;
		int num4 = inf.Updw;
		switch (inf.Type)
		{
		case CharaDef.ActionBuffType.POISON:
			text2 = "ターン終了時にダメージを受ける";
			break;
		case CharaDef.ActionBuffType.STUN:
			text2 = "行動不能になる";
			break;
		case CharaDef.ActionBuffType.ADD_DAMAGE:
			text2 = "与えるダメージが";
			if (num4 > 0)
			{
				text += "アップ";
				text2 += "上昇";
			}
			else
			{
				text += "ダウン";
				text2 += "減少";
			}
			break;
		case CharaDef.ActionBuffType.RCV_DAMAGE:
			text2 = "受けるダメージ";
			if (num4 > 0)
			{
				text += "軽減";
				text2 += "を軽減";
			}
			else
			{
				text += "増加";
				text2 += "が増加";
			}
			break;
