	private string GetInfoBuffMessage(CharaDef.ActionBuffType type, int isBuff)
	{
		string text = this.GetBuffName(type);
		if (type <= CharaDef.ActionBuffType.RCV_ALLDAMAGE)
		{
			switch (type)
			{
			case CharaDef.ActionBuffType.ADD_DAMAGE:
				if (isBuff > 0)
				{
					text += "アップ";
				}
				else
				{
					text += "ダウン";
				}
				break;
			case CharaDef.ActionBuffType.RCV_DAMAGE:
				if (isBuff > 0)
				{
					text += "軽減";
				}
				else
				{
					text += "増加";
				}
				break;
			case CharaDef.ActionBuffType.INVALID_atk:
			case CharaDef.ActionBuffType.INVALID_def:
			case CharaDef.ActionBuffType.HEAL:
			case CharaDef.ActionBuffType.TURN_HEAL:
			case CharaDef.ActionBuffType.ABSORB:
			case CharaDef.ActionBuffType.PLASM_DURATION:
			case CharaDef.ActionBuffType.SLEEP:
			case CharaDef.ActionBuffType.SEAL:
			case CharaDef.ActionBuffType.RECOVER:
			case CharaDef.ActionBuffType.RESIST:
			case CharaDef.ActionBuffType.RESURRECT:
				break;
			case CharaDef.ActionBuffType.MP:
				if (isBuff > 0)
				{
					text += "増加";
				}
				else
				{
					text += "減少";
				}
				break;
			case CharaDef.ActionBuffType.AVOID:
				text = "回避";
				if (isBuff > 0)
				{
					text += "アップ";
				}
				else
				{
					text += "ダウン";
				}
				break;
			case CharaDef.ActionBuffType.HATE:
				if (isBuff > 0)
				{
					text = "いかく";
				}
				else
				{
					text = "かくれみ";
				}
				break;
			case CharaDef.ActionBuffType.BEAT_DAMAGE:
			case CharaDef.ActionBuffType.ACTION_DAMAGE:
			case CharaDef.ActionBuffType.TRY_DAMAGE:
				if (isBuff > 0)
				{
					text += "アップ";
				}
				else
				{
					text += "ダウン";
				}
				break;
			case CharaDef.ActionBuffType.TURN_MP:
				if (isBuff > 0)
				{
					text += "増加";
				}
				else
				{
					text += "減少";
				}
				break;
			case CharaDef.ActionBuffType.HIT_RATE:
				text = "命中";
				if (isBuff > 0)
				{
					text += "アップ";
				}
				else
				{
					text += "ダウン";
				}
				break;
			case CharaDef.ActionBuffType.SP_ADD_DAMAGE:
				if (isBuff > 0)
				{
					text += "アップ";
				}
				else
				{
					text += "ダウン";
				}
				break;
			case CharaDef.ActionBuffType.SP_HIT_RATE:
				text = "命中";
				if (isBuff > 0)
				{
					text += "アップ";
				}
				else
				{
					text += "ダウン";
				}
				break;
			case CharaDef.ActionBuffType.SP_RCV_DAMAGE:
				if (isBuff > 0)
				{
					text += "軽減";
				}
				else
				{
					text += "増加";
				}
				break;
			case CharaDef.ActionBuffType.SP_AVOID:
				text = "回避";
				if (isBuff > 0)
				{
					text += "アップ";
				}
				else
				{
					text += "ダウン";
				}
				break;
			default:
				if (type == CharaDef.ActionBuffType.RCV_ALLDAMAGE)
				{
					text = "全体攻撃による被ダメージ";
					if (isBuff > 0)
					{
						text += "軽減";
					}
					else
					{
						text += "増加";
					}
				}
				break;
			}
		}
		else if (type != CharaDef.ActionBuffType.HATE_HALF)
		{
			if (type != CharaDef.ActionBuffType.HEAL_AMOUNT)
			{
				if (type == CharaDef.ActionBuffType.MP_AMOUNT)
				{
					text = "たいりょくの回復量";
					if (isBuff > 0)
					{
						text += "アップ";
					}
					else
					{
						text += "ダウン";
					}
				}
			}
			else
			{
				text = "たいりょくの回復量";
				if (isBuff > 0)
				{
					text += "アップ";
				}
				else
				{
					text += "ダウン";
				}
			}
		}
		else
		{
			text = "いかく、かくれみ効果半減";
		}
		return text;
	}

	private static int GetBuffIcon(CharaDef.ActionBuffType bt, CharaDef.AttributeMask atr, CharaDef.HealthMask hel)
	{
		SceneBattle_Recover sceneBattle_Recover = SceneBattle.recoverList.Find((SceneBattle_Recover itm) => itm.Type.Contains(bt));
		int num = ((sceneBattle_Recover == null) ? (-1) : sceneBattle_Recover.Icn);
		if (bt == CharaDef.ActionBuffType.SP_ADD_DAMAGE)
		{
			if (atr != (CharaDef.AttributeMask)0)
			{
				num = (int)(40 + CharaDef.AttributeMask2Type(atr));
			}
			else if (hel != (CharaDef.HealthMask)0)
			{
				num = 50 + SceneBattle.<GetBuffIcon>g__HealthMask2Icon|449_1(hel);
			}
		}
		else if (bt == CharaDef.ActionBuffType.SP_HIT_RATE)
		{
			if (atr != (CharaDef.AttributeMask)0)
			{
				num = (int)(70 + CharaDef.AttributeMask2Type(atr));
			}
			else if (hel != (CharaDef.HealthMask)0)
			{
				num = 80 + SceneBattle.<GetBuffIcon>g__HealthMask2Icon|449_1(hel);
			}
		}
		else if (bt == CharaDef.ActionBuffType.SP_RCV_DAMAGE)
		{
			if (atr != (CharaDef.AttributeMask)0)
			{
				num = (int)(100 + CharaDef.AttributeMask2Type(atr));
			}
			else if (hel != (CharaDef.HealthMask)0)
			{
				num = 110 + SceneBattle.<GetBuffIcon>g__HealthMask2Icon|449_1(hel);
			}
		}
		else if (bt == CharaDef.ActionBuffType.SP_AVOID)
		{
			if (atr != (CharaDef.AttributeMask)0)
			{
				num = (int)(130 + CharaDef.AttributeMask2Type(atr));
			}
			else if (hel != (CharaDef.HealthMask)0)
			{
				num = 140 + SceneBattle.<GetBuffIcon>g__HealthMask2Icon|449_1(hel);
			}
		}
		return num;
	}

	private void SetStatIcon(Transform obj, int icn, int ud, bool rst, int num, bool giv)
	{
		Transform transform = obj.Find("Img_UpDown");
		if (ud >= 0)
		{
			transform.GetComponent<PguiReplaceSpriteCtrl>().Replace(ud);
		}
		transform.gameObject.SetActive(ud >= 0 && icn >= 0 && !giv);
		transform = obj.Find("Icon");
		if (icn >= 0)
		{
			transform.GetComponent<PguiReplaceSpriteCtrl>().Replace(icn);
		}
		transform.gameObject.SetActive(icn >= 0);
		obj.Find("Icon_Resist").gameObject.SetActive(rst);
		transform = obj.Find("Count_Num");
		transform.gameObject.SetActive(num > 0 || giv);
		transform.GetComponent<PguiTextCtrl>().text = (giv ? "G" : num.ToString());
	}

	private void OnClickContinue(PguiButtonCtrl button)
	{
		if (this._continueStep > 0 && this._continueStep < 10)
		{
			if (button == this._continueGui.btnYes)
			{
				if (this._continueGui.notStone.activeSelf && !this._resultArgs.debug)
				{
					CanvasManager.HdlSelPurchaseStoneWindowCtrl.Setup(PurchaseProductOne.TabType.Invalid);
					this._continueStep = 11;
					return;
				}
				this._continueStep = -1;
				if (!this._resultArgs.debug)
				{
					DataManager.DmQuest.RequestActionBattleContinue(this._resultArgs.quest.staticOneData.questOne.questId, this._currentWave, this._continueCount + 1, this._okawari, this._maxChain, this._chainExec, 0, this._maxDmg, 0, 0, 0);
				}
				this._continueGui.anim.ExPlayAnimation("Close", null);
				return;
			}
			else
			{
				this._continueStep = -11;
				this._continueGui.anim.ExPlayAnimation("Close", null);
			}
		}
	}

	private bool CheckHuge(SceneBattle_Chara chr)
	{
		SceneBattle_Enemy sceneBattle_Enemy = chr as SceneBattle_Enemy;
		return sceneBattle_Enemy != null && sceneBattle_Enemy.huge > 0;
	}

	private bool CheckHugeFoot(SceneBattle_Chara chr)
	{
		SceneBattle_Enemy sceneBattle_Enemy = chr as SceneBattle_Enemy;
		return sceneBattle_Enemy != null && sceneBattle_Enemy.huge > 1;
	}

	private bool CheckHugeInvalidBuff(CharaDef.ActionBuffType typ)
	{
		return typ == CharaDef.ActionBuffType.STUN || typ == CharaDef.ActionBuffType.SLEEP || typ == CharaDef.ActionBuffType.COVER_LOWER || typ == CharaDef.ActionBuffType.COVER_RANDOM;
	}

	private void PlayPvpAuth(int typ)
	{
		GameObject gameObject = this._pvpAuthObjList[typ];
		Transform[] componentsInChildren = gameObject.transform.GetComponentsInChildren<Transform>();
		this._pvpAuthCamPos = null;
		this._pvpAuthCamItr = null;
		this._pvpAuthCamFov = null;
		this._pvpAuthCamRol = null;
		this._pvpAuthPos = new Dictionary<int, Transform>();
		foreach (Transform transform in componentsInChildren)
		{
			if (transform.name.StartsWith("CAM_camera1___"))
			{
				this._pvpAuthCamPos = transform;
			}
			else if (transform.name.StartsWith("CAM_camera1_aim___"))
			{
				this._pvpAuthCamItr = transform;
			}
			else if (transform.name.StartsWith("CAM_camera1_focallength___"))
			{
				this._pvpAuthCamFov = transform;
			}
			else if (transform.name.StartsWith("CAM_camera1_twist___"))
			{
				this._pvpAuthCamRol = transform;
			}
			else if (transform.name.StartsWith("CHARA_"))
			{
				string[] array2 = transform.name.Split('_', StringSplitOptions.None);
				this._pvpAuthPos.Add(int.Parse(array2[1]), transform);
			}
		}
		this._pvpAuthAnim = gameObject.GetComponentInChildren<SimpleAnimation>();
		this._pvpAuthAnim.ExPlayAnimation(this._pvpAuthAnim.clip.name, null);
		this._pvpAuthFlg = 0;
	}

	private bool IsPlayingPvpAuth()
	{
		return this._pvpAuthAnim != null && this._pvpAuthAnim.ExIsPlaying();
	}

	private void StopPvpAuth()
	{
		if (this._pvpAuthAnim != null)
		{
			this._pvpAuthAnim.ExStop(true);
		}
		this._pvpAuthAnim = null;
		this._pvpAuthCamPos = null;
		this._pvpAuthCamItr = null;
		this._pvpAuthCamFov = null;
		this._pvpAuthCamRol = null;
		this._pvpAuthPos = new Dictionary<int, Transform>();
		for (int i = 1; i < this._effectPvpList.Count; i++)
		{
			this._effectPvpList[i].effectObject.transform.SetParent(this._effect, false);
		}
		foreach (CharaModelHandle charaModelHandle in this._pvpAuthLcy.Values)
		{
			charaModelHandle.SetModelActive(false);
		}
	}

	private float GetPvpAuthTime()
	{
		if (!(this._pvpAuthAnim == null))
		{
			return this._pvpAuthAnim[this._pvpAuthAnim.clip.name].time;
		}
		return 0f;
	}

