	public override void Update()
	{
		if (Singleton<SceneManager>.Instance.returnBackground)
		{
			this.OnClickButton(this._guiData.BtnMenu);
		}
		if (this._retireStep > 0)
		{
			string text = "リタイアしますか？";
			if (SceneBattle.trainingBattle && !this._resultArgs.battleArgs.isPractice)
			{
				text += "\n\n<color=red>ここまでのスコアを記録します\n本日中の再挑戦は出来ません</color>";
			}
			else if (!this._resultArgs.battleArgs.isPractice)
			{
				text = text + "\n\n<color=red>獲得した経験値・" + DataManager.DmItem.GetItemStaticBase(30101).GetName() + "・アイテムは\n入手できなくなります</color>";
			}
			CanvasManager.HdlOpenWindowBasic.Setup("リタイア確認", text, PguiOpenWindowCtrl.GetButtonPreset(PguiOpenWindowCtrl.PresetType.NO_YES), true, new PguiOpenWindowCtrl.Callback(this.RetireWindow), null, false);
			CanvasManager.HdlOpenWindowBasic.Open();
			this._retireStep = -1;
		}
		if (this._infoStep > 0)
		{
			if (!this._infoPanel.activeSelf)
			{
				this.SetCharaInfo(0);
				this._infoGui.tabInfo.Setup(0, new PguiTabGroupCtrl.OnSelectTab(this.OnClickInfoTab));
				this._infoTyp = -1;
				this.OnClickInfoTab(0);
				this._infoPanel.SetActive(true);
				this._infoGui.anim.gameObject.SetActive(true);
				this._infoGui.anim.ExPlayAnimation(SimpleAnimation.ExPguiStatus.START, null);
				this._infoGui.animAE.PlayAnimation(PguiAECtrl.AmimeType.START, null);
				this._infoGui.closeAE.gameObject.SetActive(false);
				SoundManager.Play("prd_se_friends_profile_open", false, false);
			}
			else if (this._camera.gameObject.activeSelf)
			{
				if ((this._infoGui.animAE.m_AEImage.playTime += 0.033333335f) > this._infoGui.animAE.m_AEImage.playOutTime)
				{
					this._infoGui.animAE.PlayAnimation(PguiAECtrl.AmimeType.LOOP, null);
					this._camera.gameObject.SetActive(false);
					this._frontPanel.SetActive(false);
					this._backPanel.SetActive(false);
				}
			}
			else if ((this._infoGui.animAE.m_AEImage.playTime += 0.033333335f) > this._infoGui.animAE.m_AEImage.playOutTime)
			{
				this._infoGui.animAE.m_AEImage.playTime += this._infoGui.animAE.m_AEImage.playInTime - this._infoGui.animAE.m_AEImage.playOutTime;
			}
		}
		else if (this._infoStep < 0)
		{
			this._infoGui.closeAE.gameObject.SetActive(true);
			this._infoGui.closeAE.PlayAnimation(PguiAECtrl.AmimeType.END, null);
			this._infoGui.animAE.PauseAnimationLastFrame(PguiAECtrl.AmimeType.END);
			this._infoGui.anim.ExPauseAnimationLastFrame(SimpleAnimation.ExPguiStatus.START_SUB);
			this._infoGui.anim.gameObject.SetActive(false);
			this._camera.gameObject.SetActive(true);
			this._frontPanel.SetActive(true);
			this._backPanel.SetActive(true);
			this._infoStep = 0;
		}
		else if (this._infoPanel.activeSelf && (this._infoGui.closeAE.m_AEImage.playTime += 0.033333335f) > this._infoGui.closeAE.m_AEImage.playOutTime)
		{
			this._infoPanel.SetActive(false);
		}
		if (this._menuStep > 0)
		{
			if (!this._menuPanel.activeSelf)
			{
				this._menuPanel.SetActive(true);
				this._menuGui.anim.ExPlayAnimation("Open", null);
				TimeManager.Pause = true;
				Screen.sleepTimeout = -2;
			}
			return;
		}
		if (this._menuStep < 0)
		{
			this._menuGui.anim.ExPlayAnimation("Close", null);
			TimeManager.Pause = false;
			this.AnimeRestart();
			this._menuStep = 0;
			Screen.sleepTimeout = ((this._autoOrder > 0 || this._noCaptain || SceneBattle.pvpTraining != 0) ? (-1) : (-2));
			return;
		}
		if (this._menuPanel.activeSelf && !this._menuGui.anim.ExIsPlaying())
		{
			this._menuPanel.SetActive(false);
		}
		if (this._tutorialSkip > 0)
		{
			if (CanvasManager.HdlOpenWindowServerError.FinishedClose())
			{
				this._tutorialSkip = (TimeManager.Pause ? 1 : 2);
				string text2 = "このチュートリアルバトルを\nスキップしてよろしいですか？\n\n";
				text2 += "<color=red><size=24>※次のチュートリアルまでスキップされます\n※このチュートリアルバトルは後からプレイすることは出来ません</size></color>";
				CanvasManager.HdlOpenWindowServerError.Setup("確認", text2, PguiOpenWindowCtrl.GetButtonPreset(PguiOpenWindowCtrl.PresetType.NO_YES), true, delegate(int idx)
				{
					if (this._tutorialSkip > 0)
					{
						this._tutorialSkip = ((idx == 1) ? (-11) : (-this._tutorialSkip));
					}
					return true;
				}, null, false);
				CanvasManager.HdlOpenWindowServerError.Open();
				TimeManager.Pause = true;
			}
			return;
		}
		if (this._tutorialSkip < 0)
		{
			if (CanvasManager.HdlOpenWindowServerError.FinishedClose())
			{
				if (this._tutorialSkip < -10)
				{
					TimeManager.TimeScale = 1f;
					TutorialUtil.RequestNextSequence(this._resultArgs.battleArgs.tutorialSequence);
					if (!CanvasManager.HdlOpenWindowBasic.FinishedClose())
					{
						CanvasManager.HdlOpenWindowBasic.ForceClose();
					}
				}
				if (this._tutorialSkip < -1)
				{
					TimeManager.Pause = false;
					this.AnimeRestart();
				}
				this._tutorialSkip = 0;
			}
			return;
		}
		if (this._trainingMissionStep > 0)
		{
			if (this._trainingMissionList.Count > 0)
			{
				this._guiData.TrainingMissionAE1.playTime = 0f;
				this._guiData.TrainingMissionAE2.playTime = 0f;
				SoundManager.Play("prd_se_info_mission_complete", false, false);
				TimeManager.Pause = true;
				this._trainingMissionStep = -1;
				return;
			}
			this._trainingMissionStep = 0;
		}
		else if (this._trainingMissionStep < 0)
		{
			if (this._guiData.TrainingMissionAE1.end)
			{
				TimeManager.Pause = false;
				this.AnimeRestart();
				this._trainingMissionStep = 0;
				foreach (TrainingStaticData.DayOfWeekData.MissionBonus missionBonus in this._trainingMissionList)
				{
					if (missionBonus.type == TrainingStaticData.DayOfWeekData.MissionBonus.Type.MASTER_SKILL)
					{
						if ((this._playerSkillCount -= missionBonus.val) < 0)
						{
							this._playerSkillCount = 0;
						}
					}
					else
					{
						if (missionBonus.type == TrainingStaticData.DayOfWeekData.MissionBonus.Type.WAIT_SKILL)
						{
							using (List<SceneBattle_Friends>.Enumerator enumerator2 = this._playerList.GetEnumerator())
							{
								while (enumerator2.MoveNext())
								{
									SceneBattle_Friends sceneBattle_Friends = enumerator2.Current;
									if (sceneBattle_Friends.nowHp > sceneBattle_Friends.escapeHp && (sceneBattle_Friends.waitCount -= missionBonus.val) < 0)
									{
										sceneBattle_Friends.waitCount = 0;
									}
								}
								continue;
							}
						}
						if (missionBonus.type == TrainingStaticData.DayOfWeekData.MissionBonus.Type.OKAWARI)
						{
							if ((this._addAction += SceneBattle.addActionUse * missionBonus.val) > SceneBattle.addActionMax)
							{
								this._addAction = SceneBattle.addActionMax;
							}
						}
						else
						{
							if (missionBonus.type == TrainingStaticData.DayOfWeekData.MissionBonus.Type.HP)
							{
								using (List<SceneBattle_Friends>.Enumerator enumerator2 = this._playerList.GetEnumerator())
								{
									while (enumerator2.MoveNext())
									{
										SceneBattle_Friends sceneBattle_Friends2 = enumerator2.Current;
										if (sceneBattle_Friends2.nowHp > sceneBattle_Friends2.escapeHp && !this.IsUnheal(sceneBattle_Friends2, false))
										{
											int num = sceneBattle_Friends2.maxHp * missionBonus.val / 100;
											float num2 = 1f;
											int num3 = 0;
											if (num > 0)
											{
												this.GetBuffParam(CharaDef.ActionBuffType.HEAL_AMOUNT, sceneBattle_Friends2, (CharaDef.AttributeMask)0, (CharaDef.HealthMask)0, (CharaDef.EnemyMask)0, out num2, out num3);
											}
											num = (int)Mathf.Ceil((float)num * num2);
											if ((sceneBattle_Friends2.nowHp += num) > sceneBattle_Friends2.maxHp)
											{
												sceneBattle_Friends2.nowHp = sceneBattle_Friends2.maxHp;
											}
											this.SetHeal(sceneBattle_Friends2, num, true);
										}
									}
									continue;
								}
							}
							if (missionBonus.type == TrainingStaticData.DayOfWeekData.MissionBonus.Type.MP)
							{
								foreach (SceneBattle_Friends sceneBattle_Friends3 in this._playerList)
								{
									float num4 = 1f;
									int num5 = 0;
									if (missionBonus.val > 0)
									{
										this.GetBuffParam(CharaDef.ActionBuffType.MP_AMOUNT, sceneBattle_Friends3, (CharaDef.AttributeMask)0, (CharaDef.HealthMask)0, (CharaDef.EnemyMask)0, out num4, out num5);
									}
									if (sceneBattle_Friends3.nowHp > sceneBattle_Friends3.escapeHp && !this.IsNoMP(sceneBattle_Friends3, false))
									{
										sceneBattle_Friends3.nowKp = Mathf.Clamp(sceneBattle_Friends3.nowKp + (int)Mathf.Ceil((float)missionBonus.val * num4), 0, this.MaxMP(sceneBattle_Friends3, false));
									}
								}
							}
						}
					}
				}
			}
			return;
		}
		if ((this._tacticsStep & 8) != 0)
		{
			if (this._guiData.TacticsAE.end)
			{
				TimeManager.Pause = false;
				this.AnimeRestart();
				this._tacticsStep &= -9;
			}
			return;
		}
		if ((this._tacticsStep & 1) != 0)
		{
			this._guiData.TacticsPlayerAE.transform.Find("Txt").GetComponent<PguiTextCtrl>().text = this._resultArgs.deck.tacticsSkill.skillName;
			this._guiData.TacticsPlayerAE.playTime = 0f;
			this._guiData.TacticsAE.playTime = 0f;
			TimeManager.Pause = true;
			this._tacticsStep &= -2;
			this._tacticsStep |= 8;
			SoundManager.Play("prd_se_training_operation", false, false);
			return;
		}
		if ((this._tacticsStep & 2) != 0)
		{
			this._guiData.TacticsVersusAE.transform.Find("Txt").GetComponent<PguiTextCtrl>().text = this._resultArgs.pvpDeck.tacticsSkill.skillName;
			this._guiData.TacticsVersusAE.playTime = 0f;
			this._guiData.TacticsAE.playTime = 0f;
			TimeManager.Pause = true;
			this._tacticsStep &= -3;
			this._tacticsStep |= 8;
			SoundManager.Play("prd_se_training_operation", false, false);
			return;
		}
		if (this._tacticsEffList.Count > 0)
		{
			foreach (KeyValuePair<SceneBattle_Chara, string> keyValuePair in this._tacticsEffList)
			{
				if (keyValuePair.Key == null)
				{
					this._wildPowerBF = int.Parse(this._guiData.NumYaseiTotal.text);
					this.SetNumYaseiTotal(this._wildPower / 10);
				}
				else
				{
					if (keyValuePair.Value == "Ef_info_revival")
					{
						EffectData effectData = EffectManager.InstantiateEffect(keyValuePair.Value, this._effect, keyValuePair.Key.chara.GetLayer(), 1f);
						effectData.effectObject.transform.localPosition = keyValuePair.Key.chara.transform.localPosition;
						effectData.PlayEffect(false);
						this._effectDataList.Add(effectData);
					}
					else
					{
						EffectData effectData2 = EffectManager.InstantiateEffect(keyValuePair.Value, this._effect, keyValuePair.Key.chara.GetLayer(), 1f);
						effectData2.PlayEffect(false);
						keyValuePair.Key.chara.SetEffect(effectData2);
					}
					this.StatDisp(keyValuePair.Key);
					if (keyValuePair.Key.type == CharaDef.Type.FRIENDS)
					{
						this.DispWaitAction(keyValuePair.Key as SceneBattle_Friends);
					}
				}
			}
			this._tacticsEffList = new List<KeyValuePair<SceneBattle_Chara, string>>();
		}
		this.Continue();
		this._timer -= TimeManager.DeltaTime;
		SceneBattle.STEP step = this._step;
		SceneBattle.SUBSTEP subStep = this._subStep;
		if (this._tutorial != SceneBattle.Tutorial.NONE)
		{
			this.UpdateTutorial();
		}
		else if (this._step == SceneBattle.STEP.ReStart)
		{
			this.ReStart();
		}
		else if (this._step == SceneBattle.STEP.GameStart)
		{
			this.GameStart();
		}
		else if (this._step == SceneBattle.STEP.WaveStart)
		{
			this.WaveStart();
		}
		else if (this._step == SceneBattle.STEP.CommandSelect)
		{
			this.CommandSelect();
		}
		else if (this._step == SceneBattle.STEP.PlayerTurn)
		{
			this.PlayerTurn();
		}
		else if (this._step == SceneBattle.STEP.EnemyTurn)
		{
			this.EnemyTurn();
		}
		else if (this._step == SceneBattle.STEP.VersusTurn)
		{
			this.VersusTurn();
		}
		else if (this._step == SceneBattle.STEP.WaveClear)
		{
			this.WaveClear();
		}
		else if (this._step == SceneBattle.STEP.GameClear)
		{
			this.GameClear(DataManagerQuest.BattleEndStatus.CLEAR);
		}
		else if (this._step == SceneBattle.STEP.GameLose)
		{
			this.GameLose();
		}
		else if (this._step == SceneBattle.STEP.Retire)
		{
			this.Retire();
		}
		if (!SceneBattle.trainingBattle && this._step >= SceneBattle.STEP.WaveStart && this._step <= SceneBattle.STEP.WaveClear && (this._step != SceneBattle.STEP.PlayerTurn || this._subStep >= SceneBattle.SUBSTEP.EndBuf) && ((this._step != SceneBattle.STEP.EnemyTurn && this._step != SceneBattle.STEP.VersusTurn) || this._subStep >= SceneBattle.SUBSTEP.TurnEnd))
		{
			bool flag = true;
			foreach (SceneBattle_Enemy sceneBattle_Enemy in this._enemyList)
			{
				if (sceneBattle_Enemy.nowHp >= sceneBattle_Enemy.escapeHp && sceneBattle_Enemy.body == null)
				{
					flag = false;
				}
			}
			foreach (SceneBattle_Friends sceneBattle_Friends4 in this._versusList)
			{
				if (sceneBattle_Friends4.nowHp >= sceneBattle_Friends4.escapeHp)
				{
					flag = false;
				}
			}
			if (flag)
			{
				this._step = SceneBattle.STEP.GameClear;
			}
		}
		if (step != this._step)
		{
			this._subStep = SceneBattle.SUBSTEP.Init;
			this._stepCtr = 0;
		}
		else if (subStep != this._subStep)
		{
			this._stepCtr = 0;
		}
		this.ClearBtn();
		this.ClearTouch();
		if (this._tutorial == SceneBattle.Tutorial.NONE)
		{
			this.UpdateEffect();
		}
		this.HugeModelDisp();
		this.SetCamera();
		if ((this._tacticsStep & 3) == 0)
		{
			this.DispGui();
		}
		if (!string.IsNullOrEmpty(this._resultArgs.resultVoiceSecondSheet) && !string.IsNullOrEmpty(this._resultArgs.resultVoiceSecond) && string.IsNullOrEmpty(this._resultArgs.resultVoiceFirst) && this._resultArgs.resultVoiceSecondTime <= TimeManager.SystemNow)
		{
			SoundManager.PlayVoice(this._resultArgs.resultVoiceSecondSheet, this._resultArgs.resultVoiceSecond);
			this._resultArgs.resultVoiceSecond = "";
		}
		this.CheckPopupInfo();
		this.CheckBloomLayer();
		if (this._requestNextScene != SceneManager.SceneName.None)
		{
			if (this._requestNextScene == SceneManager.SceneName.SceneBattleResult)
			{
				this._resultArgs.resultField = this._result;
				this._resultArgs.clearTurn = this._turnCount;
				this._resultArgs.trainingRevive = this._trainingRevive;
				this._resultArgs.trainingScore = this._trainingScore;
				this._resultArgs.battleStartTime = this._battleStartTime;
				Singleton<SceneManager>.Instance.SetNextScene(this._requestNextScene, this._resultArgs);
			}
			else if (this._resultArgs.debug)
			{
				Singleton<SceneManager>.Instance.SetNextScene(SceneManager.SceneName.SceneBattle, this._resultArgs.battleArgs);
			}
			else if (this._resultArgs.restart)
			{
				Singleton<SceneManager>.Instance.SetNextScene(SceneManager.SceneName.SceneHome, null);
			}
			else if (this._requestNextScene == SceneManager.SceneName.SceneQuest)
			{
				if (this._resultArgs.battleArgs.resultNextSceneName != SceneManager.SceneName.None)
				{
					Singleton<SceneManager>.Instance.SetNextScene(this._resultArgs.battleArgs.resultNextSceneName, this._resultArgs.battleArgs.resultNextSceneArgs);
				}
				else if (SceneBattle.trainingBattle)
				{
					Singleton<SceneManager>.Instance.SetNextScene(SceneManager.SceneName.SceneTraining, new SceneTraining.Args());
				}
				else
				{
					Singleton<SceneManager>.Instance.SetNextScene(SceneManager.SceneName.SceneQuest, new SceneQuest.Args
					{
						selectQuestOneId = this._resultArgs.quest.staticOneData.questOne.questId,
						justBeforeBattle = new SceneQuest.Args.JustBeforeBattle
						{
							playQuestId = this._resultArgs.quest.staticOneData.questOne.questId,
							endStatus = this._resultArgs.battleEndStatus
						}
					});
				}
			}
			else
			{
				Singleton<SceneManager>.Instance.SetNextScene(this._requestNextScene, null);
			}
			TimeManager.TimeScale = 1f;
		}
	}

