						CharaBuffParamAbility charaBuffParamAbility = this._abilityBuffList[key];
						CharaDef.ActionBuffType buffType = charaBuffParamAbility.buffType;
						if (buffType <= CharaDef.ActionBuffType.HEAL)
						{
							if (buffType - CharaDef.ActionBuffType.POISON <= 1 || buffType == CharaDef.ActionBuffType.MP || buffType == CharaDef.ActionBuffType.HEAL)
							{
								continue;
