							case CharaDef.ActionBuffType.DEBUFF_INVALID:
							case CharaDef.ActionBuffType.TICKLING:
							case CharaDef.ActionBuffType.MP_DOUBLE:
							case CharaDef.ActionBuffType.HEAL_AMOUNT:
							case CharaDef.ActionBuffType.MP_AMOUNT:
								break;
							default:
								if (buffType == CharaDef.ActionBuffType.IMPATIENCE)
								{
									continue;
								}
								break;
							}
						}
						if (charaBuffParamAbility.giveupReuseNum <= 0 && (charaBuffParamAbility.buffType != CharaDef.ActionBuffType.REFLECT || charaBuffParamAbility.increment <= 0) && charaBuffParamAbility.turn <= 0)
						{
