								{
									num = 0;
								}
								else
								{
									int num2 = sceneBattle_Chara.nowHp * 100;
									int num3 = sceneBattle_Chara.maxHp * charaBuffParamAbility.conditionHpRate;
									if (charaBuffParamAbility.condition == CharaDef.ConditionType.UPPER)
