						goto IL_0577;
					}
				}
				if (this._step >= SceneBattle.STEP.EnemyTurn && this._step <= SceneBattle.STEP.WaveClear)
				{
					foreach (SceneBattle_PopUpData sceneBattle_PopUpData3 in this._popupDataList)
					{
