				if (sceneBattle_PopUpData != null)
				{
					this._popupType = sceneBattle_PopUpData.typ;
					this._PopUpInfo.transform.SetParent((this._popupType == DataManagerQuest.WaveTextInfoData.DispType.PLAYER) ? this._guiData.PopUpInfoCard : this._guiData.PopUpInfoAction, false);
