	private int CheckAbilityInfo(CharaDef.ActionBuffType buffType, SceneBattle_Chara chara, int key, SceneBattle_Chara tag)
	{
		CharaBuffParamAbility charaBuffParamAbility = this._abilityBuffList[key];
		if (charaBuffParamAbility.buffType != buffType)
		{
			return 0;
		}
		int num = chara.abilityBuff[key];
		if (num < 0)
		{
			num = 1 - num;
			int num2 = charaBuffParamAbility.waveReuseNum + 1;
			if (num2 > 0 && num > num2)
			{
				num = num2;
			}
		}
		else if (num == 0)
		{
			num = 1;
			bool flag = !this.IsConditionMask(charaBuffParamAbility.invertTraitsTerrainMask, (long)this._traitsTerrain, (long)charaBuffParamAbility.traitsTerrain);
			bool flag2 = !this.IsConditionMask(charaBuffParamAbility.invertTraitsTimezoneMask, (long)this._traitsTimezone, (long)charaBuffParamAbility.traitsTimezone);
			if (flag)
			{
				num = 0;
			}
			else if (flag2)
			{
				num = 0;
			}
			else if (!this.ChkWaveEnemy(charaBuffParamAbility.waveEnemyMask, charaBuffParamAbility.invertWaveEnemyMask, chara.type, charaBuffParamAbility.enemyNum, charaBuffParamAbility.conditionEnemyNum, charaBuffParamAbility.mysideNum, charaBuffParamAbility.conditionMysideNum, true))
			{
				num = 0;
			}
			else
			{
				int num3 = chara.nowHp * 100;
				int num4 = chara.maxHp * charaBuffParamAbility.conditionHpRate;
				if (charaBuffParamAbility.condition == CharaDef.ConditionType.UPPER)
				{
					if (num3 < num4)
					{
						num = 0;
					}
				}
				else if (charaBuffParamAbility.condition == CharaDef.ConditionType.LOWER)
				{
					if (num3 > num4)
					{
						num = 0;
					}
				}
				else if (num3 != num4)
				{
					num = 0;
				}
				if (num > 0 && charaBuffParamAbility.waveReuseNum > 0)
				{
					chara.abilityBuff[key] = num;
				}
			}
		}
		if (num > 0)
		{
			List<SceneBattle_Chara> tagListInfo = this.GetTagListInfo(chara, charaBuffParamAbility.targetType, charaBuffParamAbility.attributeMask, charaBuffParamAbility.invertAttributeMask, charaBuffParamAbility.healthMask, charaBuffParamAbility.invertHealthMask, charaBuffParamAbility.targetMask, charaBuffParamAbility.invertTargetMask, charaBuffParamAbility.healthMaskType);
			if (tagListInfo == null || tagListInfo.Count <= 0 || !tagListInfo.Contains(tag))
			{
				num = 0;
			}
			else if (this.NoPartsBuff(buffType, tag))
			{
				num = 0;
			}
		}
		if (num > 0 && tag.recover.Contains(key))
		{
			num = 0;
		}
		if (num > 0)
		{
			bool flag3 = false;
			bool flag4 = false;
			if (buffType != CharaDef.ActionBuffType.BUFF_INVALID && buffType != CharaDef.ActionBuffType.DEBUFF_INVALID)
			{
				flag3 = this.IsBufInv(tag, false);
				flag4 = this.GetBuffParamInfo(CharaDef.ActionBuffType.DEBUFF_INVALID, tag, (CharaDef.AttributeMask)0, (CharaDef.HealthMask)0, (CharaDef.EnemyMask)0);
			}
			SceneBattle_Recover sceneBattle_Recover = SceneBattle.recoverList.Find((SceneBattle_Recover itm) => itm.Type.Contains(buffType) && itm.Prm < 0);
			if (sceneBattle_Recover != null)
			{
				if (sceneBattle_Recover.Prm == -1)
				{
					if (charaBuffParamAbility.coefficient > 1f)
					{
						if (flag3)
						{
							num = 0;
						}
					}
					else if (charaBuffParamAbility.coefficient < 1f && flag4)
					{
						num = 0;
					}
				}
				else if (sceneBattle_Recover.Prm == -2)
				{
					if (charaBuffParamAbility.coefficient < 1f)
					{
						if (flag3)
						{
							num = 0;
						}
					}
					else if (charaBuffParamAbility.coefficient > 1f && flag4)
					{
						num = 0;
					}
				}
				else if (sceneBattle_Recover.Prm == -4)
				{
					if (charaBuffParamAbility.increment > 0)
					{
						if (flag3)
						{
							num = 0;
						}
					}
					else if (charaBuffParamAbility.increment < 0 && flag4)
					{
						num = 0;
					}
				}
			}
		}
		return num;
	}

