			{
				if (sceneBattle_Recover != null)
				{
					if (sceneBattle_Recover.Prm == -1)
					{
						if (sceneBattle_Buff.coefficient > 1.0)
						{
							if (flag3)
							{
								continue;
							}
						}
						else if (sceneBattle_Buff.coefficient < 1.0 && flag4)
						{
							continue;
						}
					}
					else if (sceneBattle_Recover.Prm == -2)
					{
						if (sceneBattle_Buff.coefficient < 1.0)
						{
							if (flag3)
							{
								continue;
							}
						}
						else if (sceneBattle_Buff.coefficient > 1.0 && flag4)
						{
							continue;
						}
