						{
							if (flag3)
							{
								continue;
							}
						}
						else if (sceneBattle_Buff.increment < 0 && flag4)
						{
							continue;
						}
					}
				}
				flag = true;
			}
		}
		List<SceneBattle_Chara> list = new List<SceneBattle_Chara>(this._playerList);
		list.AddRange(this._emyWaveList);
		list.AddRange(this._versusList);
		foreach (SceneBattle_Chara sceneBattle_Chara in list)
		{
			foreach (int num in sceneBattle_Chara.abilityBuffKey)
			{
				CharaBuffParamAbility charaBuffParamAbility = this._abilityBuffList[num];
				if (charaBuffParamAbility.giveupReuseNum <= 0 && (charaBuffParamAbility.buffType != CharaDef.ActionBuffType.REFLECT || charaBuffParamAbility.increment <= 0) && charaBuffParamAbility.turn <= 0)
