	public override void LateUpdate()
	{
		if (this._cameraType != SceneBattle.CameraType.Command && this._backDeckAll.activeSelf && this._guiData.DeckAllAE.autoPlay)
		{
			float num = 1f;
			Transform transform = this._guiData.Chara[0].transform.Find("Card");
			num = transform.GetComponent<CanvasGroup>().alpha;
			float num2 = transform.GetComponent<RectTransform>().localPosition.y - this._deckPosY;
			foreach (GameObject gameObject in this._backBlankList)
			{
				gameObject.GetComponent<RectTransform>().localPosition = new Vector3(0f, num2, 0f);
				gameObject.GetComponent<PguiImageCtrl>().m_Image.color = new Color(1f, 1f, 1f, num);
			}
			foreach (RawImage rawImage in this.backBg)
			{
				rawImage.GetComponent<RectTransform>().localPosition = new Vector3(0f, num2, 0f);
				rawImage.color = new Color(1f, 1f, 1f, num);
			}
		}
		CharaModelHandle charaModelHandle = ((this._dispHuge != null && this._dispHuge.chara.IsFinishInitialize()) ? this._dispHuge.chara : null);
		if (this._hugeEffR != null)
		{
			Vector3 position = new Vector3(0f, -100f, 0f);
			if (charaModelHandle != null)
			{
				int num3 = this._dispHuge.charaId / 10;
				Transform nodeTransform = charaModelHandle.GetNodeTransform((num3 == 2128) ? "j_leg_d_f_r" : "j_leg_g_f_r");
				if (nodeTransform != null)
				{
					position = nodeTransform.position;
				}
			}
			this._hugeEffR.effectObject.transform.position = position;
		}
		if (this._hugeEffL != null)
		{
			Vector3 position2 = new Vector3(0f, -100f, 0f);
			if (charaModelHandle != null)
			{
				int num4 = this._dispHuge.charaId / 10;
				Transform nodeTransform2 = charaModelHandle.GetNodeTransform((num4 == 2128) ? "j_leg_d_f_l" : "j_leg_g_f_l");
				if (nodeTransform2 != null)
				{
					position2 = nodeTransform2.position;
				}
			}
			this._hugeEffL.effectObject.transform.position = position2;
		}
	}

	private void HugeModelDisp()
	{
		this._dispHuge = null;
		if (this._step == SceneBattle.STEP.PlayerTurn)
		{
			if (this._plyCmdCtr >= 0 && this._plyCmdCtr < this._plyCmdList.Count)
			{
				this._dispHuge = this._emyWaveList.Find((SceneBattle_Enemy itm) => itm.huge > 0 && this._plyCmdList[this._plyCmdCtr].target == itm && itm.chara.IsModelActive() && itm.chara.IsFinishInitialize());
			}
		}
		else if (this._step == SceneBattle.STEP.EnemyTurn && this._emyCmdCtr >= 0 && this._emyCmdCtr < this._emyCmdList.Count)
		{
			SceneBattle_Enemy sceneBattle_Enemy = this._emyCmdList[this._emyCmdCtr].chara as SceneBattle_Enemy;
			if (sceneBattle_Enemy.huge > 0 && sceneBattle_Enemy.chara.IsModelActive() && sceneBattle_Enemy.chara.IsFinishInitialize())
			{
				this._dispHuge = sceneBattle_Enemy;
			}
		}
		if (this._dispHuge == null)
		{
			foreach (SceneBattle_Enemy sceneBattle_Enemy2 in this._emyWaveList)
			{
				if (sceneBattle_Enemy2.huge > 0)
				{
					if (sceneBattle_Enemy2.huge == 1)
					{
						if (this._dispHuge == null)
						{
							this._dispHuge = sceneBattle_Enemy2;
						}
					}
					else if (sceneBattle_Enemy2.chara.IsModelActive() && sceneBattle_Enemy2.chara.IsFinishInitialize())
					{
						this._dispHuge = sceneBattle_Enemy2;
						if (sceneBattle_Enemy2.nowHp <= sceneBattle_Enemy2.escapeHp)
						{
							break;
						}
					}
				}
			}
		}
		if (this._dispHuge != null)
		{
			foreach (SceneBattle_Enemy sceneBattle_Enemy3 in this._emyWaveList)
			{
				if (sceneBattle_Enemy3.huge > 0 && sceneBattle_Enemy3.chara.IsFinishInitialize())
				{
					SkinnedMeshRenderer[] componentsInChildren = sceneBattle_Enemy3.chara.transform.GetComponentsInChildren<SkinnedMeshRenderer>(true);
					for (int i = 0; i < componentsInChildren.Length; i++)
					{
						componentsInChildren[i].gameObject.SetActive(this._dispHuge == sceneBattle_Enemy3);
					}
				}
			}
		}
		foreach (SceneBattle_Enemy sceneBattle_Enemy4 in this._emyWaveList)
		{
			if (sceneBattle_Enemy4.body != null)
			{
				if (sceneBattle_Enemy4.parts == null)
				{
					if (sceneBattle_Enemy4.body.chara.IsFinishInitialize())
					{
						sceneBattle_Enemy4.parts = sceneBattle_Enemy4.body.chara.GetNodeTransform(sceneBattle_Enemy4.partsName);
						if (sceneBattle_Enemy4.parts == null)
						{
							sceneBattle_Enemy4.parts = sceneBattle_Enemy4.body.chara.transform;
						}
						if (sceneBattle_Enemy4.body.chara.GetNodeTransform(sceneBattle_Enemy4.partsModelName) != null)
						{
							sceneBattle_Enemy4.partModel = sceneBattle_Enemy4.body.chara.GetNodeTransform(sceneBattle_Enemy4.partsModelName).gameObject;
							sceneBattle_Enemy4.modelHandle = sceneBattle_Enemy4.partModel.AddComponent<ModelHandle>();
							sceneBattle_Enemy4.modelHandle.Initialize(SceneBattle.enemyLayer);
							if (sceneBattle_Enemy4.death)
							{
								sceneBattle_Enemy4.modelHandle.SetMatCap(1f);
								sceneBattle_Enemy4.modelHandle.FadeOut(0.25f);
							}
						}
						sceneBattle_Enemy4.basPos.y = -999f;
					}
				}
				else if (sceneBattle_Enemy4.basPos.y < -100f && sceneBattle_Enemy4.body.chara.IsCurrentAnimation(CharaMotionDefine.ActKey.IDLING) && sceneBattle_Enemy4.body.chara.GetMotionTime(false) > 1f)
				{
					sceneBattle_Enemy4.basPos = new Vector3(sceneBattle_Enemy4.parts.position.x, sceneBattle_Enemy4.body.basPos.y, sceneBattle_Enemy4.body.basPos.z);
					sceneBattle_Enemy4.hpPos = (sceneBattle_Enemy4.pos = sceneBattle_Enemy4.basPos);
				}
			}
		}
	}

