	private string BonusString(int bns)
	{
		string text = "";
		if (bns > 0)
		{
			bns += 1000;
			text = text + "x" + (bns / 1000).ToString();
			if ((bns %= 1000) > 0)
			{
				text += ".";
				int num = 100;
				while (bns > 0 && num > 0)
				{
					text += (bns / num).ToString();
					bns %= num;
					num /= 10;
				}
			}
		}
		return text;
	}

	private void OnClickPhoto(IconPhotoCtrl ipc)
	{
		for (int i = 0; i < this._infoGui.icsPhoto.Count; i++)
		{
			if (!(this._infoGui.icsPhoto[i] == null) && !(this._infoGui.icnPhoto[i] == null))
			{
				Transform transform = this._infoGui.icsPhoto[i].Find("Current");
				if (transform != null)
				{
					transform.gameObject.SetActive(ipc == this._infoGui.icnPhoto[i]);
				}
			}
		}
		CharaStaticAbility charaStaticAbility = ((ipc == null || ipc.photoPackData == null) ? null : ipc.photoPackData.GetCurrentAbility());
		this._infoGui.staPhoto.Find("Txt_Name").GetComponent<PguiTextCtrl>().text = ((ipc == null || ipc.photoPackData == null) ? "" : ipc.photoPackData.staticData.baseData.photoName);
		this._infoGui.staPhoto.Find("Txt_Info").GetComponent<PguiTextCtrl>().text = ((charaStaticAbility == null) ? "" : charaStaticAbility.abilityEffect);
		PrjUtil.ParamPreset paramPreset = ((ipc == null || ipc.photoPackData == null) ? null : PrjUtil.CalcParamByPhoto(ipc.photoPackData));
		this._infoGui.staPhoto.Find("Param01/Num_Param").GetComponent<PguiTextCtrl>().text = ((paramPreset == null) ? "" : paramPreset.hp.ToString());
		this._infoGui.staPhoto.Find("Param02/Num_Param").GetComponent<PguiTextCtrl>().text = ((paramPreset == null) ? "" : paramPreset.atk.ToString());
		this._infoGui.staPhoto.Find("Param03/Num_Param").GetComponent<PguiTextCtrl>().text = ((paramPreset == null) ? "" : paramPreset.def.ToString());
	}

	private void Continue()
	{
		if (this._menuStep == 0 && this._trainingMissionStep == 0 && this._tacticsStep == 0 && this._tutorialSkip == 0 && this._debugStep == 0)
		{
			if (this._resultArgs.battleArgs.tutorialSequence != TutorialUtil.Sequence.INVALID)
			{
				if (this._continueStep == 1)
				{
					TimeManager.TimeScale = 1f;
					this._continueStep = 2;
					CanvasManager.HdlTutorialMaskCtrl.SetEnable(true);
					CanvasManager.HdlTutorialMaskCtrl.SetBlackMask(true);
					CanvasManager.HdlTutorialMaskCtrl.SetFrame(0, false, null, true, null);
					CanvasManager.HdlTutorialMaskCtrl.SetFrame(1, false, null, true, null);
					CanvasManager.HdlTutorialMaskCtrl.SetStickCursor(false, null, null, null);
					TutorialMaskCtrl.CharaInfoParameter charaInfoParameter = new TutorialMaskCtrl.CharaInfoParameter();
					charaInfoParameter.dispType = TutorialMaskCtrl.CharaDispType.IN;
					charaInfoParameter.postion = new Vector2?(new Vector2(200f, 500f));
					charaInfoParameter.dispInfoChara = true;
					charaInfoParameter.enableTouchNext = true;
					charaInfoParameter.charaImagePath = "/Icon_ChaTexture2Dra/Chara/icon_chara_0022";
					charaInfoParameter.messageList = new List<string> { "負けてはいけませんの！" };
					charaInfoParameter.finishCallBack = delegate
					{
						this._continueStep = 3;
					};
					CanvasManager.HdlTutorialMaskCtrl.SetCharaInfo(charaInfoParameter);
					Screen.sleepTimeout = -2;
					return;
				}
				if (this._continueStep != 2)
				{
					if (this._continueStep == 3)
					{
						this._continueStep = 4;
						this.SetTimer(0.5f);
						CanvasManager.HdlTutorialMaskCtrl.SetCharaInfo(new TutorialMaskCtrl.CharaInfoParameter
						{
							dispType = TutorialMaskCtrl.CharaDispType.OUT
						});
						return;
					}
					if (this._continueStep > 0)
					{
						if (this.IsTimeOut())
						{
							CanvasManager.HdlTutorialMaskCtrl.SetEnable(false);
							this.Revive();
							return;
						}
					}
					else if (this._continueStep < 0)
					{
						bool flag = true;
						using (List<SceneBattle_Friends>.Enumerator enumerator = this._playerList.GetEnumerator())
						{
							while (enumerator.MoveNext())
							{
								if (enumerator.Current.inBack < 0)
								{
									flag = false;
								}
							}
						}
						if (flag)
						{
							this._continueStep = 0;
							return;
						}
					}
				}
			}
			else if (this._continueStep > 0)
			{
				if (SceneBattle.pvpBattle || SceneBattle.trainingBattle || this._resultArgs.quest.staticOneData.questOne.ContinueImpossible)
				{
					this._step = SceneBattle.STEP.GameLose;
					this._subStep = SceneBattle.SUBSTEP.Init;
					this._stepCtr = 0;
					this._continueStep = 0;
					return;
				}
				if (!this._continuePanel.activeSelf)
				{
					TimeManager.TimeScale = 1f;
					this.ContinueCost();
					this._continuePanel.SetActive(true);
					this._continueGui.anim.ExPlayAnimation("Open", null);
					int j;
					int i;
					for (i = 0; i < this._charaCameraList.Count; i = j + 1)
					{
						if (this._backCharaList[i].activeSelf)
						{
							SceneBattle_Friends sceneBattle_Friends = this._playerList.Find((SceneBattle_Friends itm) => itm.number == i + 1);
							if (sceneBattle_Friends != null)
							{
								FieldCameraScaler fieldCameraScaler = this._charaCameraList[i];
								if (fieldCameraScaler.gameObject.activeSelf)
								{
									fieldCameraScaler.transform.position = sceneBattle_Friends.commandCameraPos + new Vector3(0f, 2f, sceneBattle_Friends.offZ);
									fieldCameraScaler.transform.eulerAngles = sceneBattle_Friends.commandCameraRot;
									fieldCameraScaler.transform.LookAt(sceneBattle_Friends.chara.GetHaraPos());
									this._bgCameraList[i].targetTexture = null;
								}
							}
						}
						j = i;
					}
					Screen.sleepTimeout = -2;
					return;
				}
				if (this._continueStep > 10 && !CanvasManager.HdlSelPurchaseStoneWindowCtrl.IsActiveWindow())
				{
					this.ContinueCost();
					this._continueStep = 1;
					return;
				}
			}
			else if (this._continuePanel.activeSelf)
			{
				if (!this._continueGui.anim.ExIsPlaying() && !DataManager.IsServerRequesting())
				{
					this._continuePanel.SetActive(false);
					if (this._continueStep < -10)
					{
						this._step = SceneBattle.STEP.GameLose;
						this._subStep = SceneBattle.SUBSTEP.Init;
						this._stepCtr = 0;
						this._continueStep = 0;
						return;
					}
					this.Revive();
					return;
				}
			}
			else if (this._continueStep < 0)
			{
				bool flag2 = true;
				using (List<SceneBattle_Friends>.Enumerator enumerator = this._playerList.GetEnumerator())
				{
					while (enumerator.MoveNext())
					{
						if (enumerator.Current.inBack < 0)
						{
							flag2 = false;
						}
					}
				}
				if (flag2)
				{
					this._continueStep = 0;
				}
			}
		}
	}

	private void ContinueCost()
	{
		int num = DataManager.DmItem.GetUserItemData(30100).num;
		this._continueGui.numBefore.text = num.ToString();
		if ((num -= DataManager.DmQuest.GetContinueStoneNum()) < 0)
		{
			this._continueGui.numAfter.gameObject.SetActive(false);
			this._continueGui.notStone.SetActive(true);
			this._continueGui.buyStone.SetActive(true);
		}
		else
		{
			this._continueGui.numAfter.gameObject.SetActive(true);
			this._continueGui.notStone.SetActive(false);
			this._continueGui.buyStone.SetActive(false);
		}
		this._continueGui.numAfter.text = num.ToString();
	}

	private void Revive()
	{
		foreach (SceneBattle_Friends sceneBattle_Friends in this._playerList)
		{
			sceneBattle_Friends.buff = new List<SceneBattle_Buff>();
			sceneBattle_Friends.recover = new List<int>();
			sceneBattle_Friends.newBuff = new List<SceneBattle_Buff>();
			sceneBattle_Friends.newRecover = new List<int>();
			sceneBattle_Friends.nowHp = sceneBattle_Friends.maxHp;
			sceneBattle_Friends.nowKp = Mathf.Clamp(sceneBattle_Friends.nowKp + 20, 0, this.MaxMP(sceneBattle_Friends, false));
			sceneBattle_Friends.newHp = sceneBattle_Friends.nowHp;
			sceneBattle_Friends.newKp = sceneBattle_Friends.nowKp;
			sceneBattle_Friends.newGuts = sceneBattle_Friends.guts;
		}
		this._playerSkillCount = 0;
		if ((this._addAction += SceneBattle.addActionUse) > SceneBattle.addActionMax)
		{
			this._addAction = SceneBattle.addActionMax;
		}
		if (this._noCaptain)
		{
			this._addAction = 0;
		}
		int i;
		int j;
		for (i = 0; i < this._charaCameraList.Count; i = j + 1)
		{
			if (this._backCharaList[i].activeSelf)
			{
				SceneBattle_Friends sceneBattle_Friends2 = this._playerList.Find((SceneBattle_Friends itm) => itm.number == i + 1);
				if (sceneBattle_Friends2 != null)
				{
					FieldCameraScaler fieldCameraScaler = this._charaCameraList[i];
					if (fieldCameraScaler.gameObject.activeSelf)
					{
						fieldCameraScaler.transform.position = sceneBattle_Friends2.commandCameraPos + new Vector3(0f, 0f, sceneBattle_Friends2.offZ);
						fieldCameraScaler.transform.eulerAngles = sceneBattle_Friends2.commandCameraRot;
						this._bgCameraList[i].targetTexture = null;
					}
				}
			}
			j = i;
		}
		TimeManager.TimeScale = (this._superSpeed ? 10f : ((this._timeScale > 0) ? 2f : 1f));
		Screen.sleepTimeout = ((this._autoOrder > 0 || this._noCaptain || SceneBattle.pvpTraining != 0) ? (-1) : (-2));
		this._continueCount++;
	}

	private void UpdateTutorial()
	{
		if (this._tutorial != SceneBattle.Tutorial.INIT)
		{
			if (this._tutorial == SceneBattle.Tutorial.INFO_PANEL)
			{
				if ((this._tutorialTime += TimeManager.DeltaTime) >= 0.5f && this._currentTouch != null && this._currentTouch == this._tutorialPanel.transform)
				{
					this._tutorialPanelImage.SetActive(false);
					this._tutorialPanelTouch.SetActive(false);
					this._tutorial = SceneBattle.Tutorial.INIT;
					SoundManager.Play("prd_se_click", false, false);
					return;
				}
			}
			else if (this._tutorial == SceneBattle.Tutorial.INFO_MASK)
			{
				if (this._tutorialStep == SceneBattle.TutorialStep.INFO3_6_1 && (this._currentTouch == this._guiData.TouchChara[2] || this._currentTouch == this._guiData.TouchArts[2]))
				{
					CanvasManager.HdlTutorialMaskCtrl.OnTouchMask(null);
				}
				if (this._tutorialMask)
				{
					if (this._tutorialStep != SceneBattle.TutorialStep.INFO3_1_4)
					{
						CanvasManager.HdlTutorialMaskCtrl.SetCharaInfo(new TutorialMaskCtrl.CharaInfoParameter
						{
							dispType = TutorialMaskCtrl.CharaDispType.OUT
						});
					}
					if (this._tutorialStep == SceneBattle.TutorialStep.INFO1_3_1 || this._tutorialStep == SceneBattle.TutorialStep.INFO1_3_2 || this._tutorialStep == SceneBattle.TutorialStep.INFO1_3_3)
					{
						CanvasManager.HdlTutorialMaskCtrl.SetEnable(false);
						TimeManager.Pause = false;
						this.AnimeRestart();
						this._tutorial = SceneBattle.Tutorial.NONE;
						return;
					}
					this._tutorial = SceneBattle.Tutorial.INIT;
					return;
				}
			}
			else if (this._tutorial == SceneBattle.Tutorial.NEXT)
			{
				if (this.IsTimeOut())
				{
					this._tutorial = SceneBattle.Tutorial.INIT;
					return;
				}
			}
			else if (this.IsTimeOut())
			{
				CanvasManager.HdlTutorialMaskCtrl.SetEnable(false);
				if (this._tutorialStep >= SceneBattle.TutorialStep.END3)
				{
					this._tutorial = SceneBattle.Tutorial.NONE;
					this._tutorialStep = SceneBattle.TutorialStep.NONE;
					return;
				}
				TutorialUtil.RequestNextSequence(this._resultArgs.battleArgs.tutorialSequence);
			}
			return;
		}
		this._tutorialStep++;
		this._tutorialMask = false;
		this._tutorialCard = (this._tutorialArts = 0);
		this._tutorialAdd = (this._tutorialSkill = false);
		this._tutorialOrderList = new List<CharaDef.OrderCardType>();
		this._tutorialTime = 0f;
		List<string> list = new List<string>();
		list = null;
		if (SceneBattle.tutorialInfo.TryGetValue(this._tutorialStep, out list))
