				this._tutorialPanelTouch.SetActive(true);
				this._tutorialPanelImage.GetComponent<PguiRawImageCtrl>().SetRawImage("Texture2D/Tutorial/Battle/tutorial_battle_0" + ((list.Count > 0) ? list[0] : "1"), true, false, null);
				this._tutorial = SceneBattle.Tutorial.INFO_PANEL;
				return;
			}
			CanvasManager.HdlTutorialMaskCtrl.SetEnable(true);
			CanvasManager.HdlTutorialMaskCtrl.SetBlackMask(true);
			if (this._tutorialStep == SceneBattle.TutorialStep.INFO1_3_1)
			{
				CanvasManager.HdlTutorialMaskCtrl.SetFrame(0, this._guiData.ActionActAE.transform.parent.Find("Base").GetComponent<RectTransform>(), true, 1f, 1f);
				TimeManager.Pause = true;
			}
			else if (this._tutorialStep == SceneBattle.TutorialStep.INFO1_3_2)
			{
				CanvasManager.HdlTutorialMaskCtrl.SetFrame(0, this._guiData.NumYaseiTotal.transform.parent.GetComponent<RectTransform>(), true, 1f, 1f);
				TimeManager.Pause = true;
			}
			else if (this._tutorialStep == SceneBattle.TutorialStep.INFO1_3_3)
			{
				CanvasManager.HdlTutorialMaskCtrl.SetFrame(0, this._guiData.BeatActAE.transform.parent.Find("Base").GetComponent<RectTransform>(), true, 1f, 1f);
				TimeManager.Pause = true;
			}
			else if (this._tutorialStep == SceneBattle.TutorialStep.INFO2_6_1)
			{
