			{
				CanvasManager.HdlTutorialMaskCtrl.SetFrame(0, this._guiData.Chara[2].GetComponent<RectTransform>(), true, 1f, 1f);
			}
			else if (this._tutorialStep == SceneBattle.TutorialStep.INFO4_4_1)
			{
				CanvasManager.HdlTutorialMaskCtrl.SetFrame(0, true, new Rect?(new Rect(30f, 180f, 220f, 360f)), true, this._camera);
			}
			else
			{
				CanvasManager.HdlTutorialMaskCtrl.SetFrame(0, false, null, true, null);
			}
			CanvasManager.HdlTutorialMaskCtrl.SetFrame(1, false, null, true, null);
			CanvasManager.HdlTutorialMaskCtrl.SetStickCursor(false, null, null, null);
			TutorialMaskCtrl.CharaInfoParameter charaInfoParameter = new TutorialMaskCtrl.CharaInfoParameter();
			charaInfoParameter.dispType = TutorialMaskCtrl.CharaDispType.IN;
			charaInfoParameter.postion = new Vector2?(new Vector2(200f, 500f));
			charaInfoParameter.dispInfoChara = true;
			charaInfoParameter.enableTouchNext = this._tutorialStep != SceneBattle.TutorialStep.INFO3_1_4;
			charaInfoParameter.charaImagePath = "Texture2D/Icon_Chara/Chara/icon_chara_" + list[0];
			charaInfoParameter.messageList = list.GetRange(1, list.Count - 1);
			charaInfoParameter.finishCallBack = delegate
			{
				this._tutorialMask = true;
			};
			CanvasManager.HdlTutorialMaskCtrl.SetCharaInfo(charaInfoParameter);
			this._tutorial = SceneBattle.Tutorial.INFO_MASK;
			return;
		}
		else
		{
			if (this._tutorialStep == SceneBattle.TutorialStep.INIT1)
			{
				if (this._playerList.Find((SceneBattle_Friends itm) => itm.number == 1) != null)
				{
					this._tutorialOrderList.Add(CharaDef.OrderCardType.BEAT);
				}
				this._tutorialOrderList.Add(CharaDef.OrderCardType.ACTION);
				this._tutorialOrderList.Add(CharaDef.OrderCardType.TRY);
				this._tutorialOrderList.Add(CharaDef.OrderCardType.BEAT);
				this._tutorial = SceneBattle.Tutorial.NONE;
				return;
			}
			if (this._tutorialStep == SceneBattle.TutorialStep.INIT2)
			{
				if (this._playerList.Find((SceneBattle_Friends itm) => itm.number == 1) != null)
				{
					this._tutorialOrderList.Add(CharaDef.OrderCardType.BEAT);
				}
				this._addAction = SceneBattle.addActionUse / 2;
				this._tutorialOrderList.Add(CharaDef.OrderCardType.BEAT);
				this._tutorialOrderList.Add(CharaDef.OrderCardType.BEAT);
				this._tutorialOrderList.Add(CharaDef.OrderCardType.BEAT);
				this._tutorial = SceneBattle.Tutorial.NONE;
				return;
			}
			if (this._tutorialStep == SceneBattle.TutorialStep.INIT3)
			{
				if (this._playerList.Find((SceneBattle_Friends itm) => itm.number == 1) != null)
				{
					this._tutorialOrderList.Add(CharaDef.OrderCardType.BEAT);
				}
				this._tutorialOrderList.Add(CharaDef.OrderCardType.ACTION);
				this._tutorialOrderList.Add(CharaDef.OrderCardType.BEAT);
				this._tutorialOrderList.Add(CharaDef.OrderCardType.ACTION);
				this._tutorial = SceneBattle.Tutorial.NONE;
				return;
			}
			if (this._tutorialStep == SceneBattle.TutorialStep.INIT4)
			{
				if (this._playerList.Find((SceneBattle_Friends itm) => itm.number == 1) != null)
				{
					this._tutorialOrderList.Add(CharaDef.OrderCardType.BEAT);
				}
				this._tutorialOrderList.Add(CharaDef.OrderCardType.ACTION);
				this._tutorialOrderList.Add(CharaDef.OrderCardType.TRY);
				this._tutorialOrderList.Add(CharaDef.OrderCardType.BEAT);
