				return;
			}
			if (this._tutorialStep == SceneBattle.TutorialStep.END1 || this._tutorialStep == SceneBattle.TutorialStep.END2 || this._tutorialStep == SceneBattle.TutorialStep.END3 || this._tutorialStep >= SceneBattle.TutorialStep.END4)
