			}
			if (this._tutorialStep == SceneBattle.TutorialStep.BATTLE1_3_1 || this._tutorialStep == SceneBattle.TutorialStep.BATTLE2_8_1 || this._tutorialStep == SceneBattle.TutorialStep.BATTLE3_8_1)
			{
