				return;
			}
			if (this._tutorialStep == SceneBattle.TutorialStep.BATTLE1_3_2 || this._tutorialStep == SceneBattle.TutorialStep.BATTLE1_3_3 || this._tutorialStep == SceneBattle.TutorialStep.BATTLE1_3_4)
			{
				this._tutorial = SceneBattle.Tutorial.NONE;
				return;
			}
			if (this._tutorialStep == SceneBattle.TutorialStep.BATTLE2_3_1)
			{
				CanvasManager.HdlTutorialMaskCtrl.SetEnable(false);
				if (this._playerList.Find((SceneBattle_Friends itm) => itm.number == 1) != null)
				{
					this._tutorialOrderList.Add(CharaDef.OrderCardType.BEAT);
				}
				this._tutorialOrderList.Add(CharaDef.OrderCardType.ACTION);
				this._tutorialOrderList.Add(CharaDef.OrderCardType.ACTION);
				this._tutorialOrderList.Add(CharaDef.OrderCardType.ACTION);
				this._tutorial = SceneBattle.Tutorial.NONE;
				return;
			}
			if (this._tutorialStep == SceneBattle.TutorialStep.BATTLE3_5_1)
			{
				CanvasManager.HdlTutorialMaskCtrl.SetEnable(false);
				if (this._playerList.Find((SceneBattle_Friends itm) => itm.number == 1) != null)
				{
					this._tutorialOrderList.Add(CharaDef.OrderCardType.BEAT);
				}
				this._tutorialOrderList.Add(CharaDef.OrderCardType.ACTION);
				this._tutorialOrderList.Add(CharaDef.OrderCardType.BEAT);
				this._tutorialOrderList.Add(CharaDef.OrderCardType.TRY);
				this._tutorial = SceneBattle.Tutorial.NONE;
				return;
			}
			if (this._tutorialStep == SceneBattle.TutorialStep.BATTLE4_3_1)
			{
				CanvasManager.HdlTutorialMaskCtrl.SetEnable(false);
				this._tutorial = SceneBattle.Tutorial.NONE;
				return;
			}
			if (this._tutorialStep == SceneBattle.TutorialStep.ADD2_5_1)
			{
				CanvasManager.HdlTutorialMaskCtrl.SetEnable(true);
				CanvasManager.HdlTutorialMaskCtrl.SetBlackMask(true);
				RectTransform component = this._guiData.ActGageBase.GetComponent<RectTransform>();
				CanvasManager.HdlTutorialMaskCtrl.SetFrame(0, component, true, 1f, 1f);
				CanvasManager.HdlTutorialMaskCtrl.SetFrame(1, false, null, true, null);
				CanvasManager.HdlTutorialMaskCtrl.SetStickCursor(component, 1f);
				CanvasManager.HdlTutorialMaskCtrl.SetStickCursor(true, null, new Vector3?(new Vector3(0f, 0f, 230f)), new Vector2?(new Vector2(40f, -40f)));
				this._tutorialAdd = true;
				this._tutorial = SceneBattle.Tutorial.NONE;
				this._addAction = SceneBattle.addActionUse;
				return;
			}
			if (this._tutorialStep == SceneBattle.TutorialStep.MASTER3_2_1)
			{
				CanvasManager.HdlTutorialMaskCtrl.SetEnable(true);
				CanvasManager.HdlTutorialMaskCtrl.SetBlackMask(true);
				RectTransform component2 = this._guiData.BtnPlayerSkill.GetComponent<RectTransform>();
				CanvasManager.HdlTutorialMaskCtrl.SetFrame(0, component2, true, 1f, 1f);
				CanvasManager.HdlTutorialMaskCtrl.SetFrame(1, false, null, true, null);
				CanvasManager.HdlTutorialMaskCtrl.SetStickCursor(component2, 1f);
				this._tutorialSkill = true;
				this._tutorial = SceneBattle.Tutorial.NONE;
				return;
			}
			if (this._tutorialStep == SceneBattle.TutorialStep.MASTER3_2_2)
			{
				CanvasManager.HdlTutorialMaskCtrl.SetEnable(true);
				CanvasManager.HdlTutorialMaskCtrl.SetBlackMask(true);
				RectTransform component3 = CanvasManager.HdlOpenWindowBasic.choiceR.GetComponent<RectTransform>();
				CanvasManager.HdlTutorialMaskCtrl.SetFrame(0, component3, true, 1f, 1f);
				CanvasManager.HdlTutorialMaskCtrl.SetFrame(1, false, null, true, null);
				CanvasManager.HdlTutorialMaskCtrl.SetStickCursor(component3, 1f);
				this._tutorialSkill = true;
				this._tutorial = SceneBattle.Tutorial.NONE;
				return;
			}
			if (this._tutorialStep == SceneBattle.TutorialStep.MASTER3_2_3)
			{
				CanvasManager.HdlTutorialMaskCtrl.SetEnable(true);
				CanvasManager.HdlTutorialMaskCtrl.SetBlackMask(true);
				this._tutorialCard = 3;
				CanvasManager.HdlTutorialMaskCtrl.SetFrame(0, this._guiData.Chara[this._tutorialCard - 1].GetComponent<RectTransform>(), true, 1f, 1f);
				CanvasManager.HdlTutorialMaskCtrl.SetFrame(1, false, null, true, null);
				CanvasManager.HdlTutorialMaskCtrl.SetStickCursor(false, null, null, null);
				this._tutorialOrderList.Add(CharaDef.OrderCardType.ACTION);
				this._tutorial = SceneBattle.Tutorial.NONE;
				return;
			}
			if (this._tutorialStep == SceneBattle.TutorialStep.MASTER3_2_4)
			{
				CanvasManager.HdlTutorialMaskCtrl.SetEnable(true);
				CanvasManager.HdlTutorialMaskCtrl.SetBlackMask(true);
				RectTransform component4 = this._guiData.BtnInfoSkill.GetComponent<RectTransform>();
				CanvasManager.HdlTutorialMaskCtrl.SetFrame(0, component4, true, 1f, 1f);
				CanvasManager.HdlTutorialMaskCtrl.SetFrame(1, false, null, true, null);
				CanvasManager.HdlTutorialMaskCtrl.SetStickCursor(component4, 1f);
				this._tutorialSkill = true;
				this._tutorial = SceneBattle.Tutorial.NONE;
				return;
			}
			if (this._tutorialStep == SceneBattle.TutorialStep.BEATARTS3_7_1)
			{
				this._tutorialArts = 3;
				SceneBattle_Friends sceneBattle_Friends = this._playerList.Find((SceneBattle_Friends itm) => itm.number == this._tutorialArts);
				if (sceneBattle_Friends != null)
				{
					sceneBattle_Friends.nowKp = sceneBattle_Friends.maxKp;
				}
				CanvasManager.HdlTutorialMaskCtrl.SetEnable(true);
				CanvasManager.HdlTutorialMaskCtrl.SetBlackMask(true);
				CanvasManager.HdlTutorialMaskCtrl.SetFrame(0, this._guiData.TouchArts[this._tutorialArts - 1].GetComponent<RectTransform>(), true, 1f, 1f);
				CanvasManager.HdlTutorialMaskCtrl.SetFrame(1, false, null, true, null);
				this._tutorial = SceneBattle.Tutorial.NONE;
				return;
			}
			SceneBattle.TutorialStep tutorialStep = this._tutorialStep;
			if (tutorialStep <= SceneBattle.TutorialStep.ACTION3_4_3)
			{
				switch (tutorialStep)
				{
				case SceneBattle.TutorialStep.ACTION1_2_1:
					this._tutorialCard = 2;
					break;
				case SceneBattle.TutorialStep.TRY1_2_2:
					this._tutorialCard = 3;
					break;
				case SceneBattle.TutorialStep.BEAT1_2_3:
					this._tutorialCard = 4;
					break;
				default:
					switch (tutorialStep)
					{
					case SceneBattle.TutorialStep.BEAT2_2_1:
						this._tutorialCard = 2;
						break;
					case SceneBattle.TutorialStep.BEAT2_2_2:
						this._tutorialCard = 3;
						break;
					case SceneBattle.TutorialStep.BEAT2_2_3:
						this._tutorialCard = 4;
						break;
					case SceneBattle.TutorialStep.BATTLE2_3_1:
					case SceneBattle.TutorialStep.INFO2_4_1:
					case SceneBattle.TutorialStep.ADD2_5_1:
					case SceneBattle.TutorialStep.INFO2_6_1:
						break;
					case SceneBattle.TutorialStep.ACTION2_7_1:
						this._tutorialCard = 2;
						break;
					case SceneBattle.TutorialStep.ACTION2_7_2:
						this._tutorialCard = 2;
						break;
					case SceneBattle.TutorialStep.ACTION2_7_3:
						this._tutorialCard = 3;
						break;
					case SceneBattle.TutorialStep.ACTION2_7_4:
						this._tutorialCard = 4;
						break;
					default:
						switch (tutorialStep)
						{
						case SceneBattle.TutorialStep.ACTION3_4_1:
							this._tutorialCard = 2;
							break;
						case SceneBattle.TutorialStep.ACTION3_4_2:
							this._tutorialCard = 4;
							break;
						case SceneBattle.TutorialStep.ACTION3_4_3:
							this._tutorialCard = 3;
							break;
						}
						break;
					}
					break;
				}
			}
			else if (tutorialStep != SceneBattle.TutorialStep.ACTION3_7_2)
			{
				if (tutorialStep != SceneBattle.TutorialStep.TRY3_7_3)
				{
					switch (tutorialStep)
					{
					case SceneBattle.TutorialStep.ORDER4_2_1:
						this._tutorialCard = 2;
						break;
					case SceneBattle.TutorialStep.ORDER4_2_2:
						this._tutorialCard = 4;
						break;
					case SceneBattle.TutorialStep.ORDER4_2_3:
						this._tutorialCard = 5;
						break;
					}
				}
				else
				{
					this._tutorialCard = 4;
				}
			}
			else
			{
				this._tutorialCard = 2;
			}
			if (this._tutorialCard <= 0)
			{
				CanvasManager.HdlTutorialMaskCtrl.SetEnable(false);
				this._tutorial = SceneBattle.Tutorial.NEXT;
				this.SetTimer(0.1f);
				return;
			}
			CanvasManager.HdlTutorialMaskCtrl.SetEnable(true);
			CanvasManager.HdlTutorialMaskCtrl.SetBlackMask(true);
			CanvasManager.HdlTutorialMaskCtrl.SetFrame(0, this._guiData.Chara[this._tutorialCard - 1].GetComponent<RectTransform>(), true, 1f, 1f);
			this._tutorial = SceneBattle.Tutorial.NONE;
			if (this._tutorialStep == SceneBattle.TutorialStep.ACTION2_7_1)
			{
				this._tutorialOrderList.Add(CharaDef.OrderCardType.ACTION);
				CanvasManager.HdlTutorialMaskCtrl.SetFrame(1, this._guiData.ActInfo.transform.Find("InfoBase").GetComponent<RectTransform>(), true, 1f, 1f);
				return;
			}
			CanvasManager.HdlTutorialMaskCtrl.SetFrame(1, false, null, true, null);
			return;
		}
	}

	private void ReStart()
	{
		if (this._subStep == SceneBattle.SUBSTEP.Init)
		{
			this._subStep = SceneBattle.SUBSTEP.Term;
			return;
		}
		if (!this.IsCameraMove())
		{
			if (this._battleRestartArgs.battleEndStatus == DataManagerQuest.BattleEndStatus.CLEAR)
			{
				this._step = SceneBattle.STEP.GameClear;
				return;
			}
			if (this._battleRestartArgs.battleEndStatus == DataManagerQuest.BattleEndStatus.DEAD)
			{
				this._step = SceneBattle.STEP.GameLose;
				return;
			}
			if (this._battleRestartArgs.battleEndStatus == DataManagerQuest.BattleEndStatus.RETIRE)
			{
				this._step = SceneBattle.STEP.Retire;
				return;
			}
			this._step = SceneBattle.STEP.CommandSelect;
			TimeManager.TimeScale = (this._superSpeed ? 10f : ((this._timeScale > 0) ? 2f : 1f));
		}
	}

	private void GameStart()
	{
		if (SceneBattle.pvpBattle && this._resultArgs.battleArgs.pvpTraining > 0)
		{
			this._plyPlasm = 0;
			this._vssPlasm = 0;
			foreach (SceneBattle_Friends sceneBattle_Friends in this._playerList)
			{
				this._plyPlasm += this.culWildPoint(sceneBattle_Friends);
			}
			foreach (SceneBattle_Friends sceneBattle_Friends2 in this._versusList)
			{
				this._vssPlasm += this.culWildPoint(sceneBattle_Friends2);
			}
			SceneBattle.pvpTraining = ((this._vssPlasm > this._plyPlasm) ? (-1) : 1);
		}
		bool flag = true;
		if (this._subStep == SceneBattle.SUBSTEP.Init)
		{
			if (SceneBattle.trainingBattle)
			{
				this._subStep = SceneBattle.SUBSTEP.Term;
			}
			else if (SceneBattle.pvpTraining != 0)
			{
				this._subStep = SceneBattle.SUBSTEP.Term;
				this.SetTimer(3.4f);
			}
			else if (SceneBattle.pvpBattle || SceneBattle.friendsBattle)
			{
				this._subStep = SceneBattle.SUBSTEP.Term;
				this._guiData.BattleStartAE.gameObject.SetActive(true);
				this._guiData.BattleStartAE.GetComponent<PguiReplaceAECtrl>().Replace(SceneBattle.pvpBattle ? "PVP" : (SceneBattle.friendWild ? "EventYasei" : "FRIENDS"));
				this._guiData.BattleStartAE.playTime = 0f;
				this._guiData.BattleStartAE.playOutTime = this._guiData.BattleStartAE.duration;
				SoundManager.Play((SceneBattle.pvpBattle || SceneBattle.friendWild) ? "prd_se_pvp_battlestart" : "prd_se_battle_start", false, false);
				this.SetTimer(3.9f);
			}
			else
			{
				this._subStep = SceneBattle.SUBSTEP.Prepare;
				this._guiData.BattleStartAE.gameObject.SetActive(true);
				this._guiData.BattleStartAE.GetComponent<PguiReplaceAECtrl>().Replace("BATTLE");
				this._guiData.BattleStartAE.playTime = 0f;
				this._guiData.BattleStartAE.playOutTime = this._guiData.BattleStartAE.duration;
				this.SetTimer(4f);
				SoundManager.Play("prd_se_battle_start", false, false);
			}
			foreach (SceneBattle_Friends sceneBattle_Friends3 in this._playerList)
			{
				sceneBattle_Friends3.chara.DispAccessory(0, true, false);
				sceneBattle_Friends3.chara.DispAccessory(1, true, false);
			}
			foreach (SceneBattle_Friends sceneBattle_Friends4 in this._versusList)
			{
				sceneBattle_Friends4.chara.DispAccessory(0, true, false);
				sceneBattle_Friends4.chara.DispAccessory(1, true, false);
			}
			flag = false;
			this.ResetSkillCount();
		}
		else if (this._subStep == SceneBattle.SUBSTEP.Prepare)
		{
			flag = false;
			if (this.IsTimeOut())
			{
				SoundManager.Play("prd_se_battle_start_b", false, false);
				this._subStep = SceneBattle.SUBSTEP.Confirm;
			}
		}
		else if (this._subStep == SceneBattle.SUBSTEP.Confirm)
		{
			flag = false;
			if (!this._guiData.BattleStartAE.gameObject.activeSelf)
			{
				this._subStep = SceneBattle.SUBSTEP.Term;
				if (this._rare >= 0)
				{
					this._guiData.RareInAE.gameObject.SetActive(true);
					this._guiData.RareInAE.playTime = 0f;
					SoundManager.Play("prd_se_warning_rare_enemy", false, false);
					this.SetTimer(2f);
				}
				else if (this._boss >= 0)
				{
					this._guiData.BossInAE.gameObject.SetActive(true);
					this._guiData.BossInAE.playTime = 0f;
					SoundManager.Play("prd_se_warning", false, false);
