			}
			if ((chr.newHp += num3) > chr.maxHp)
			{
				chr.newHp = chr.maxHp;
			}
			chr.nowHp = chr.newHp;
			this.SetHeal(chr, num3, true);
			chr.goodStat.Add(new SceneBattle_InfoBuff(CharaDef.ActionBuffType.TURN_HEAL, 0L, (CharaDef.AttributeMask)0, (CharaDef.HealthMask)0, (CharaDef.EnemyMask)0, 0, -1, false, 0, ""));
		}
		if (this.GetBuffParam(CharaDef.ActionBuffType.TURN_MP, chr, (CharaDef.AttributeMask)0, (CharaDef.HealthMask)0, (CharaDef.EnemyMask)0, out num, out num2) && (num2 < 0 || !this.IsNoMP(chr, true)))
		{
