			{
				return false;
			}
			if (!this.ChkWaveEnemy(charaBuffParamAbility.waveEnemyMask, charaBuffParamAbility.invertWaveEnemyMask, chr.type, charaBuffParamAbility.enemyNum, charaBuffParamAbility.conditionEnemyNum, charaBuffParamAbility.mysideNum, charaBuffParamAbility.conditionMysideNum, false))
			{
				return false;
			}
			int num2 = chr.newHp * 100;
			int num3 = chr.maxHp * charaBuffParamAbility.conditionHpRate;
			if (charaBuffParamAbility.condition == CharaDef.ConditionType.UPPER)
			{
				if (num2 < num3)
				{
					return false;
				}
			}
			else if (charaBuffParamAbility.condition == CharaDef.ConditionType.LOWER)
			{
				if (num2 > num3)
				{
					return false;
				}
			}
			else if (num2 != num3)
			{
				return false;
			}
			if (charaBuffParamAbility.isCountSpecified)
			{
				foreach (SceneBattle_Buff sceneBattle_Buff in chr.buff)
				{
					if (charaBuffParamAbility.buffType == sceneBattle_Buff.buffType)
					{
						return false;
					}
				}
				return true;
			}
			chr.abilityBuff[key] = 1;
		}
		return true;
	}

	private List<SceneBattle_Tag> ExecAbility(bool now = true)
	{
		List<SceneBattle_Tag> list = new List<SceneBattle_Tag>();
		List<SceneBattle_Chara> list2 = new List<SceneBattle_Chara>(this._playerList);
		list2.AddRange(this._emyWaveList);
		list2.AddRange(this._versusList);
		HashSet<int> hashSet = new HashSet<int>();
		if (SceneBattle.actionMax > SceneBattle.addActionMax)
		{
			SceneBattle.addActionMax = SceneBattle.actionMax;
		}
		foreach (SceneBattle_Chara sceneBattle_Chara in list2)
		{
			foreach (int num in sceneBattle_Chara.abilityBuffKey)
			{
				CharaBuffParamAbility cbpa = this._abilityBuffList[num];
				int num2 = 0;
				bool flag = false;
				if (cbpa.buffType == CharaDef.ActionBuffType.RESURRECT)
				{
					if ((num2 = cbpa.increment) < 1)
					{
						num2 = 1;
					}
				}
				else if (cbpa.buffType != CharaDef.ActionBuffType.HEAL && cbpa.buffType != CharaDef.ActionBuffType.MP && cbpa.buffType != CharaDef.ActionBuffType.RECOVER && cbpa.buffType != CharaDef.ActionBuffType.ADD_OKAWARI && cbpa.buffType != CharaDef.ActionBuffType.UPPER_OKAWARI)
				{
					if (SceneBattle.recoverList.Find((SceneBattle_Recover itm) => itm.Type.Contains(cbpa.buffType) && itm.Prm > 0) != null)
					{
						flag = true;
					}
					else if (cbpa.turn > 0)
					{
						flag = true;
					}
					else if (cbpa.giveupReuseNum > 0)
					{
						flag = true;
					}
					else
					{
						if (cbpa.buffType != CharaDef.ActionBuffType.REFLECT || cbpa.increment <= 0)
						{
							continue;
						}
						flag = true;
					}
				}
				if (this.ValidAbility(sceneBattle_Chara, num))
				{
					SceneBattle_Buff sceneBattle_Buff = new SceneBattle_Buff();
					sceneBattle_Buff.SetBuff(cbpa, sceneBattle_Chara);
					foreach (SceneBattle_Tag sceneBattle_Tag in this.GetTagList(sceneBattle_Chara, null, null, cbpa.targetType, cbpa.attributeMask, cbpa.invertAttributeMask, cbpa.healthMask, cbpa.invertHealthMask, cbpa.targetMask, cbpa.invertTargetMask, cbpa.breakElement, num2, null, cbpa.healthMaskType))
					{
						if (!flag || this.CheckBuff(cbpa.buffType, 100, sceneBattle_Tag.tag))
						{
							SceneBattle_Tag sceneBattle_Tag2 = new SceneBattle_Tag(sceneBattle_Tag.tag);
							sceneBattle_Tag2.buf = sceneBattle_Buff.clone();
							if (sceneBattle_Tag2.buf.buffType == CharaDef.ActionBuffType.ICE)
							{
								if (sceneBattle_Tag2.tag.type == CharaDef.Type.BOSS)
								{
									sceneBattle_Tag2.buf.count = this._battleParam.iceCancelBoss;
								}
								else if (sceneBattle_Tag2.tag.type == CharaDef.Type.PARTS)
								{
									sceneBattle_Tag2.buf.count = this._battleParam.iceCancelBoss;
								}
								else if (sceneBattle_Tag2.tag.type == CharaDef.Type.ENEMY)
								{
									sceneBattle_Tag2.buf.count = this._battleParam.iceCancelEnemy;
								}
								else
								{
									sceneBattle_Tag2.buf.count = this._battleParam.iceCancelFriends;
								}
								if (sceneBattle_Tag2.buf.count < 1)
								{
									sceneBattle_Tag2.buf.count = 1;
								}
							}
							else if (sceneBattle_Tag2.buf.buffType == CharaDef.ActionBuffType.REFLECT && sceneBattle_Tag2.buf.increment > 0)
							{
								sceneBattle_Tag2.buf.count = Mathf.Clamp(sceneBattle_Tag2.buf.increment, 1, 9);
							}
							else if (sceneBattle_Tag2.buf.buffType == CharaDef.ActionBuffType.ADD_OKAWARI)
							{
								if (sceneBattle_Tag2.buf.chrTyp == CharaDef.Type.FRIENDS)
								{
									this._addAction += sceneBattle_Tag2.buf.increment * 100;
								}
								else
								{
									this._addActionVersus += sceneBattle_Tag2.buf.increment * 100;
								}
							}
							else if (sceneBattle_Tag2.buf.buffType == CharaDef.ActionBuffType.UPPER_OKAWARI)
							{
								if (sceneBattle_Tag2.buf.chrTyp == CharaDef.Type.FRIENDS)
								{
									SceneBattle.addActionMax += sceneBattle_Tag2.buf.increment * 100;
								}
								else
								{
									SceneBattle.addActionVersusMax += sceneBattle_Tag2.buf.increment * 100;
								}
							}
							sceneBattle_Tag2.flg = 1;
							sceneBattle_Tag2.infKey = num;
							list.Add(sceneBattle_Tag2);
						}
					}
				}
			}
		}
		foreach (SceneBattle_Tag sceneBattle_Tag3 in list)
		{
			if (sceneBattle_Tag3.buf.giveupNum > 0)
			{
				sceneBattle_Tag3.tag.newBuff.Add(sceneBattle_Tag3.buf);
			}
			else
			{
				this.SetAbility(sceneBattle_Tag3);
			}
			if (now)
			{
				if (sceneBattle_Tag3.buf.giveupNum > 0)
				{
					sceneBattle_Tag3.tag.buff.Add(sceneBattle_Tag3.buf);
					hashSet.Add(sceneBattle_Tag3.infKey);
				}
				else if (this.ExecAbility(null, sceneBattle_Tag3))
				{
					hashSet.Add(sceneBattle_Tag3.infKey);
				}
			}
		}
		foreach (int num3 in hashSet)
		{
			CharaBuffParamAbility charaBuffParamAbility = this._abilityBuffList[num3];
			this._popupDataList.Add(new SceneBattle_PopUpData
			{
				typ = DataManagerQuest.WaveTextInfoData.DispType.SKILL,
				msg = charaBuffParamAbility.infoMessage,
				tim = charaBuffParamAbility.infoTime
			});
		}
		return list;
	}

	private void SetAbility(SceneBattle_Tag t)
	{
		SceneBattle_Chara tag = t.tag;
		SceneBattle_Buff buf = t.buf;
		buf.giveupNum = 0;
		if (this.NoPartsBuff(buf.buffType, tag))
		{
			t.noExe = 1;
			return;
		}
		if (this.CheckInvalidBuff(buf, tag))
		{
			t.noExe = 2;
			return;
		}
		if (buf.buffType == CharaDef.ActionBuffType.RESURRECT)
		{
			if ((t.hp = (int)((double)((float)tag.maxHp) * buf.coefficient * buf.rate)) > tag.maxHp)
			{
				t.hp = tag.maxHp;
			}
			else if (t.hp <= tag.escapeHp)
			{
				t.hp = tag.escapeHp + 1;
			}
			tag.newHp = t.hp;
			tag.newBuff = new List<SceneBattle_Buff>();
			tag.newRecover = new List<int>();
			return;
		}
		if (buf.buffType == CharaDef.ActionBuffType.HEAL)
		{
			t.hp = (int)((double)((float)tag.maxHp) * buf.coefficient + 0.009999999776482582);
			float num = 1f;
			int num2 = 0;
			if (t.hp > 0)
			{
				this.GetBuffParam(CharaDef.ActionBuffType.HEAL_AMOUNT, tag, (CharaDef.AttributeMask)0, (CharaDef.HealthMask)0, (CharaDef.EnemyMask)0, out num, out num2);
			}
			t.hp = (int)Mathf.Ceil((float)(t.hp + buf.increment) * num);
			if (t.hp <= 0)
			{
				t.hp = 1;
			}
			t.hp = -t.hp;
			if (tag.newHp > tag.escapeHp && !this.IsUnheal(tag, true) && t.hp < 0 && (tag.newHp -= t.hp) > tag.maxHp)
			{
				tag.newHp = tag.maxHp;
				return;
			}
		}
		else if (buf.buffType == CharaDef.ActionBuffType.MP)
		{
			t.kp = (int)((double)((float)tag.maxKp) * buf.coefficient * 0.009999999776482582 + 0.009999999776482582) + buf.increment;
			float num3 = 1f;
			int num4 = 0;
			if (t.kp > 0)
			{
				this.GetBuffParam(CharaDef.ActionBuffType.MP_AMOUNT, tag, (CharaDef.AttributeMask)0, (CharaDef.HealthMask)0, (CharaDef.EnemyMask)0, out num3, out num4);
			}
			t.kp = (int)Mathf.Ceil((float)t.kp * num3);
			if (buf.increment < 0)
			{
				if (t.kp >= 0)
				{
					t.kp = -1;
				}
			}
			else if (t.kp <= 0)
			{
				t.kp = 1;
			}
			t.kp = -t.kp;
			if (tag.newHp > tag.escapeHp && (t.kp > 0 || !this.IsNoMP(tag, true)))
			{
				tag.newKp = Mathf.Clamp(tag.newKp - t.kp, (tag.newKp < tag.maxKp) ? 0 : tag.maxKp, this.MaxMP(tag, true));
				return;
			}
		}
		else
		{
			if (buf.buffType == CharaDef.ActionBuffType.RECOVER)
			{
				bool flag = (buf.chrTyp == CharaDef.Type.FRIENDS) ^ (tag.type == CharaDef.Type.FRIENDS);
				t.recover = new List<int>();
				List<SceneBattle_Chara> list = new List<SceneBattle_Chara>(this._playerList);
				list.AddRange(this._emyWaveList);
				list.AddRange(this._versusList);
				bool flag2 = false;
				CharaDef.ActionBuffType actionBuffType = CharaDef.ActionBuffType.INVALID;
				foreach (SceneBattle_Chara sceneBattle_Chara in list)
				{
					foreach (int num5 in sceneBattle_Chara.abilityBuffKey)
					{
						CharaBuffParamAbility cbpa = this._abilityBuffList[num5];
						bool flag3 = sceneBattle_Chara.maxHp * cbpa.conditionHpRate / 100 > sceneBattle_Chara.newHp;
						if (cbpa.isCountSpecified && flag3)
						{
							flag2 = cbpa.isCountSpecified;
							actionBuffType = cbpa.buffType;
						}
						else if (cbpa.giveupReuseNum <= 0 && (cbpa.buffType != CharaDef.ActionBuffType.REFLECT || cbpa.increment <= 0) && cbpa.turn <= 0)
						{
							SceneBattle_Recover sceneBattle_Recover = SceneBattle.recoverList.Find((SceneBattle_Recover itm) => itm.Type.Contains(cbpa.buffType) && itm.Prm < 0);
							if (sceneBattle_Recover != null && (sceneBattle_Recover.Mask & buf.abnormalType) != 0L && this.CheckAbility(cbpa.buffType, sceneBattle_Chara, num5, t.tag) > 0 && this.CheckRecover(cbpa, sceneBattle_Recover, flag))
							{
								t.recover.Add(num5);
							}
						}
					}
				}
				if (tag.newHp <= tag.escapeHp)
				{
					return;
				}
				this.SetRecover(t, flag, flag2, actionBuffType);
				using (List<int>.Enumerator enumerator2 = t.recover.GetEnumerator())
				{
					while (enumerator2.MoveNext())
					{
						int num6 = enumerator2.Current;
						if (!tag.newRecover.Contains(num6))
						{
							tag.newRecover.Add(num6);
						}
					}
					return;
				}
			}
			if (SceneBattle.recoverList.Find((SceneBattle_Recover itm) => itm.Type.Contains(buf.buffType) && itm.Prm > 0) != null)
			{
				if (tag.newHp > tag.escapeHp)
				{
					if (t.buf.buffType == CharaDef.ActionBuffType.ICE)
					{
						tag.newBuff.RemoveAll((SceneBattle_Buff itm) => itm.giveupNum <= 0 && itm.buffType == buf.buffType);
					}
					tag.newBuff.Add(buf.clone());
					if (buf.buffType == CharaDef.ActionBuffType.IMPATIENCE)
					{
						int num7 = buf.turn;
						for (int i = 0; i < tag.newBuff.Count; i++)
						{
							if (tag.newBuff[i].buffType == CharaDef.ActionBuffType.IMPATIENCE)
							{
								num7 += tag.newBuff[i].turn;
								break;
							}
						}
						tag.newBuff.RemoveAll((SceneBattle_Buff itm) => itm.giveupNum <= 0 && itm.buffType == buf.buffType);
						tag.newBuff.Add(buf.clone());
						tag.newBuff[tag.newBuff.Count - 1].turn = num7;
						return;
					}
				}
			}
			else if (tag.newHp > tag.escapeHp)
			{
				tag.newBuff.Add(buf.clone());
			}
		}
	}

	private bool ExecAbility(SceneBattle_Chara chr, SceneBattle_Tag tt)
	{
		SceneBattle_Buff buf = tt.buf;
		SceneBattle_Chara tag = tt.tag;
		buf.giveupNum = 0;
		bool flag = false;
		if (tt.noExe > 0)
		{
			if (tt.noExe > 1)
			{
				GameObject esc2 = tt.tag.hpGage.transform.Find("AEImage_EnemyReflect").gameObject;
				esc2.SetActive(true);
				esc2.GetComponent<PguiAECtrl>().PlayAnimation(PguiAECtrl.AmimeType.START, delegate
				{
					esc2.SetActive(false);
				});
			}
		}
		else if (buf.buffType == CharaDef.ActionBuffType.RESURRECT)
		{
			tag.nowHp = tt.hp;
			tag.buff = new List<SceneBattle_Buff>();
			tag.recover = new List<int>();
			tag.goodStat.Add(new SceneBattle_InfoBuff(buf.buffType, 0L, (CharaDef.AttributeMask)0, (CharaDef.HealthMask)0, (CharaDef.EnemyMask)0, 1, buf.turn, false, 0, ""));
			if (buf.chrTyp == CharaDef.Type.FRIENDS && !this._statusErrorList.Contains(buf.buffType))
			{
				this._statusErrorList.Add(buf.buffType);
			}
			flag = true;
			SceneBattle_Friends sceneBattle_Friends = tag as SceneBattle_Friends;
			SceneBattle_Enemy sceneBattle_Enemy = tag as SceneBattle_Enemy;
			if ((sceneBattle_Friends != null && sceneBattle_Friends.inBack >= 0) || (sceneBattle_Enemy != null && !sceneBattle_Enemy.death))
			{
				EffectData effectData = EffectManager.InstantiateEffect("Ef_info_revival", this._effect, tag.chara.GetLayer(), 1f);
				effectData.effectObject.transform.localPosition = tag.chara.transform.localPosition;
				effectData.PlayEffect(false);
				this._effectDataList.Add(effectData);
			}
		}
		else if (buf.buffType == CharaDef.ActionBuffType.HEAL)
		{
			if (tt.hp < 0 && tag.nowHp > tag.escapeHp)
			{
				int num = (this.IsUnheal(tag, false) ? 0 : tt.hp);
				if ((tag.nowHp -= num) > tag.maxHp)
				{
					tag.nowHp = tag.maxHp;
				}
				this.SetHeal(tag, -num, tt.flg > 0);
				tag.goodStat.Add(new SceneBattle_InfoBuff(CharaDef.ActionBuffType.HEAL, 0L, (CharaDef.AttributeMask)0, (CharaDef.HealthMask)0, (CharaDef.EnemyMask)0, 0, buf.turn, false, 0, ""));
				if (buf.chrTyp == CharaDef.Type.FRIENDS && !this._statusErrorList.Contains(buf.buffType))
				{
					this._statusErrorList.Add(buf.buffType);
				}
				flag = true;
			}
		}
		else if (buf.buffType == CharaDef.ActionBuffType.MP)
		{
			if (tag.nowHp > tag.escapeHp)
			{
				if (tt.kp > 0 || !this.IsNoMP(tag, false))
				{
					tag.nowKp = Mathf.Clamp(tag.nowKp - tt.kp, (tag.nowKp < tag.maxKp) ? 0 : tag.maxKp, this.MaxMP(tag, false));
				}
				if (tt.kp < 0)
				{
					tag.goodStat.Add(new SceneBattle_InfoBuff(CharaDef.ActionBuffType.MP, 0L, (CharaDef.AttributeMask)0, (CharaDef.HealthMask)0, (CharaDef.EnemyMask)0, 0, buf.turn, false, 0, ""));
				}
				else
				{
					tag.badStat.Add(new SceneBattle_InfoBuff(CharaDef.ActionBuffType.MP, 0L, (CharaDef.AttributeMask)0, (CharaDef.HealthMask)0, (CharaDef.EnemyMask)0, 0, buf.turn, false, 0, ""));
				}
				if (buf.chrTyp == CharaDef.Type.FRIENDS && !this._statusErrorList.Contains(buf.buffType))
				{
					this._statusErrorList.Add(buf.buffType);
				}
				flag = true;
			}
		}
		else if (buf.buffType == CharaDef.ActionBuffType.RECOVER)
		{
			if (tag.nowHp > tag.escapeHp)
			{
				int num2 = (((buf.chrTyp == CharaDef.Type.FRIENDS) ^ (tag.type == CharaDef.Type.FRIENDS)) ? 1 : 0);
				long num3 = 0L;
				int num4 = 0;
				bool flag2 = false;
				CharaDef.ActionBuffType actionBuffType = CharaDef.ActionBuffType.INVALID;
				new List<SceneBattle_Chara>(this._playerList);
				foreach (int num5 in tag.abilityBuffKey)
				{
					CharaBuffParamAbility charaBuffParamAbility = this._abilityBuffList[num5];
					bool flag3 = tag.maxHp * charaBuffParamAbility.conditionHpRate / 100 > tag.newHp;
					if (charaBuffParamAbility.isCountSpecified && flag3)
					{
						flag2 = charaBuffParamAbility.isCountSpecified;
						actionBuffType = charaBuffParamAbility.buffType;
					}
				}
				foreach (SceneBattle_Recover sceneBattle_Recover in SceneBattle.recoverList)
				{
					if ((buf.abnormalType & sceneBattle_Recover.Mask) != 0L && this.ExecRecover(tag, sceneBattle_Recover, num2, flag2, actionBuffType, ref num4))
					{
						num3 |= sceneBattle_Recover.Mask;
					}
				}
				foreach (int num6 in tt.recover)
				{
					if (!tag.recover.Contains(num6))
					{
						tag.recover.Add(num6);
						CharaBuffParamAbility cbpa = this._abilityBuffList[num6];
						SceneBattle_Recover sceneBattle_Recover2 = SceneBattle.recoverList.Find((SceneBattle_Recover itm) => itm.Type.Contains(cbpa.buffType) && itm.Prm < 0);
						if (sceneBattle_Recover2 != null)
						{
							num3 |= sceneBattle_Recover2.Mask;
							if (cbpa.buffType == CharaDef.ActionBuffType.HATE)
							{
								num4 += cbpa.increment;
							}
						}
					}
				}
				if (num3 != 0L)
				{
					tag.goodStat.Add(new SceneBattle_InfoBuff(buf.buffType, num3, (CharaDef.AttributeMask)0, (CharaDef.HealthMask)0, (CharaDef.EnemyMask)0, num2, (num4 > 0) ? 1 : 0, false, 0, ""));
					if (buf.chrTyp == CharaDef.Type.FRIENDS && !this._statusErrorList.Contains(buf.buffType))
					{
						this._statusErrorList.Add(buf.buffType);
					}
					flag = true;
				}
			}
		}
		else if (SceneBattle.recoverList.Find((SceneBattle_Recover itm) => itm.Type.Contains(buf.buffType) && itm.Prm > 0) != null)
		{
			bool flag4 = false;
			if (tag.nowHp > tag.escapeHp)
			{
				if (buf.buffType == CharaDef.ActionBuffType.ICE)
				{
					tag.buff.RemoveAll((SceneBattle_Buff itm) => itm.giveupNum <= 0 && itm.buffType == buf.buffType);
					tag.badStat.Add(new SceneBattle_InfoBuff(buf.buffType, 0L, (CharaDef.AttributeMask)0, (CharaDef.HealthMask)0, (CharaDef.EnemyMask)0, 0, buf.count, false, 0, ""));
				}
				else if (buf.buffType == CharaDef.ActionBuffType.IMPATIENCE)
				{
					int num7 = buf.turn;
					for (int i = 0; i < tag.badStat.Count; i++)
					{
						if (buf.buffType == tag.badStat[i].Type)
						{
							num7 += tag.badStat[i].Turn;
						}
					}
					buf.turn = num7;
					tag.buff.RemoveAll((SceneBattle_Buff itm) => itm.giveupNum <= 0 && itm.buffType == buf.buffType);
					tag.badStat.Add(new SceneBattle_InfoBuff(buf.buffType, 0L, (CharaDef.AttributeMask)0, (CharaDef.HealthMask)0, (CharaDef.EnemyMask)0, 0, num7, false, 0, ""));
				}
				else if (buf.buffType == CharaDef.ActionBuffType.STUN)
				{
					if (this.CheckHugeFoot(tag))
					{
						flag4 = true;
					}
					else
					{
						tag.badStat.Add(new SceneBattle_InfoBuff(buf.buffType, 0L, (CharaDef.AttributeMask)0, (CharaDef.HealthMask)0, (CharaDef.EnemyMask)0, 0, buf.turn, false, 0, ""));
						if (tag != chr && tag.chara != null)
						{
							tag.chara.PlayAnimation(CharaMotionDefine.ActKey.ABNORMAL_ST, false, 1f, 0.3f, 0.15f, false);
						}
					}
				}
				else if (buf.buffType == CharaDef.ActionBuffType.POISON)
				{
					tag.badStat.Add(new SceneBattle_InfoBuff(buf.buffType, 0L, (CharaDef.AttributeMask)0, (CharaDef.HealthMask)0, (CharaDef.EnemyMask)0, 0, buf.turn, false, 0, ""));
					if (!SceneBattle.pvpBattle && !SceneBattle.friendsBattle)
					{
						this.PlayVoice(tag, CharaVoiceCombi.SitType.CHARA_POISON, VOICE_TYPE.PHD01);
					}
				}
				else if (buf.buffType == CharaDef.ActionBuffType.SLEEP)
				{
					if (this.CheckHugeFoot(tag))
					{
						flag4 = true;
					}
