	private void ExecAbility(SceneBattle_Chara chr, List<SceneBattle_Tag> ability)
	{
		HashSet<int> hashSet = new HashSet<int>();
		foreach (SceneBattle_Tag sceneBattle_Tag in ability)
		{
			if (sceneBattle_Tag.buf.giveupNum > 0)
			{
				sceneBattle_Tag.tag.buff.Add(sceneBattle_Tag.buf);
				hashSet.Add(sceneBattle_Tag.infKey);
			}
			else if (this.ExecAbility(chr, sceneBattle_Tag))
			{
				hashSet.Add(sceneBattle_Tag.infKey);
			}
		}
		foreach (int num in hashSet)
		{
			CharaBuffParamAbility charaBuffParamAbility = this._abilityBuffList[num];
			this._popupDataList.Add(new SceneBattle_PopUpData
			{
				typ = DataManagerQuest.WaveTextInfoData.DispType.SKILL,
				msg = charaBuffParamAbility.infoMessage,
				tim = charaBuffParamAbility.infoTime
			});
		}
	}

