	private List<SceneBattle_Tag> ExecTactics(int side)
	{
		List<SceneBattle_Tag> list = new List<SceneBattle_Tag>();
		list = null;
		if (side > 0)
		{
			if (this._tacticsPlayer && this._resultArgs.deck.tacticsType == TacticsParam.Tactics.Type.TURN_NUM && this._resultArgs.deck.tacticsValue <= this._turnCount)
			{
				list = this.ExecTactics(this._resultArgs.deck.tacticsSkill, this._playerList, this._versusList);
				this._tacticsPlayer = false;
			}
		}
		else if (side < 0)
		{
			if (this._tacticsVersus && this._resultArgs.pvpDeck.tacticsType == TacticsParam.Tactics.Type.TURN_NUM && this._resultArgs.pvpDeck.tacticsValue <= this._turnCount)
			{
				list = this.ExecTactics(this._resultArgs.pvpDeck.tacticsSkill, this._versusList, this._playerList);
				this._tacticsVersus = false;
			}
		}
		else
		{
			if (this._tacticsPlayer)
			{
				if (this._resultArgs.deck.tacticsType == TacticsParam.Tactics.Type.GIVEUP_NUM)
				{
					if (this._resultArgs.deck.tacticsValue <= this._giveupPlayer)
					{
						this._tacticsPlayer = false;
					}
				}
				else if (this._resultArgs.deck.tacticsType == TacticsParam.Tactics.Type.HP_PER)
				{
					int num = 0;
					int num2 = 0;
					foreach (SceneBattle_Friends sceneBattle_Friends in this._playerList)
					{
						num2 += sceneBattle_Friends.maxHp;
						if (sceneBattle_Friends.newHp > 0)
						{
							num += sceneBattle_Friends.newHp;
						}
					}
					if (num * 100 / num2 <= this._resultArgs.deck.tacticsValue)
					{
						this._tacticsPlayer = false;
					}
				}
				if (!this._tacticsPlayer)
				{
					if (list == null)
					{
						list = new List<SceneBattle_Tag>();
					}
					list.AddRange(this.ExecTactics(this._resultArgs.deck.tacticsSkill, this._playerList, this._versusList));
				}
			}
			if (this._tacticsVersus)
			{
				if (this._resultArgs.pvpDeck.tacticsType == TacticsParam.Tactics.Type.GIVEUP_NUM)
				{
					if (this._resultArgs.pvpDeck.tacticsValue <= this._giveupVersus)
					{
						this._tacticsVersus = false;
					}
				}
				else if (this._resultArgs.pvpDeck.tacticsType == TacticsParam.Tactics.Type.HP_PER)
				{
					int num3 = 0;
					int num4 = 0;
					foreach (SceneBattle_Friends sceneBattle_Friends2 in this._versusList)
					{
						num4 += sceneBattle_Friends2.maxHp;
						if (sceneBattle_Friends2.newHp > 0)
						{
							num3 += sceneBattle_Friends2.newHp;
						}
					}
					if (num3 * 100 / num4 <= this._resultArgs.pvpDeck.tacticsValue)
					{
						this._tacticsVersus = false;
					}
				}
				if (!this._tacticsVersus)
				{
					if (list == null)
					{
						list = new List<SceneBattle_Tag>();
					}
					list.AddRange(this.ExecTactics(this._resultArgs.pvpDeck.tacticsSkill, this._versusList, this._playerList));
				}
			}
		}
		return list;
	}

