	private void StatDisp4(SceneBattle_Chara chr)
	{
		chr.statTim += TimeManager.DeltaTime;
		int childCount = chr.statIcon.childCount;
		if (childCount < 1)
		{
			return;
		}
		int num = (chr.stat.Count + childCount - 1) / childCount;
		int num2 = (int)chr.statTim / 3;
		int num3 = ((num > 0) ? (num2 % num * childCount) : 0);
		if (num3 == chr.statIdx)
		{
			return;
		}
		chr.statIdx = num3;
		for (int i = 0; i < childCount; i++)
		{
			Transform transform = chr.statIcon.Find("Stat" + i.ToString());
			if (chr.statIdx + i < chr.stat.Count)
			{
				SceneBattle_InfoBuff inf = chr.stat[num3 + i];
				transform.gameObject.SetActive(true);
				int num4 = SceneBattle.GetBuffIcon(inf.Type, inf.Attribute, inf.Health);
				bool flag = false;
				int num5 = ((inf.Type == CharaDef.ActionBuffType.REFLECT) ? (-1) : inf.Updw);
				int num6 = ((inf.Type == CharaDef.ActionBuffType.REFLECT) ? inf.Updw : ((inf.Type == CharaDef.ActionBuffType.ICE) ? inf.Turn : 0));
				if (inf.Type == CharaDef.ActionBuffType.RESIST)
				{
					SceneBattle_Recover sceneBattle_Recover = SceneBattle.recoverList.Find((SceneBattle_Recover itm) => itm.Mask == inf.Mask && itm.Prm > 0);
					if (inf.Updw == 3 || inf.Updw == -3)
					{
						num4 = 179;
					}
					else if (inf.Updw == 2 || inf.Updw == -2)
					{
						num4 = 178;
					}
					else if (sceneBattle_Recover != null)
					{
						num4 = sceneBattle_Recover.Icn;
						flag = true;
					}
					if (inf.Updw < 0)
					{
						num5 = 0;
					}
					else if (inf.Updw > 0)
					{
						num5 = 1;
					}
				}
				if (inf.Type == CharaDef.ActionBuffType.SCHEDULED)
				{
					num6 = inf.Turn;
				}
				if (inf.Giveup)
				{
					num4 = SceneBattle.giveupIcon;
					flag = false;
					num5 = -1;
					num6 = 0;
				}
				this.SetStatIcon(transform, num4, num5, flag, num6, inf.Giveup);
			}
			else
			{
				transform.gameObject.SetActive(false);
			}
		}
	}

	private void CheckGuts()
