	private void decreaseFocus(SceneBattle_Chara target)
	{
		if (target == null)
		{
			return;
		}
		SceneBattle_Buff sceneBattle_Buff = target.buff.Find((SceneBattle_Buff itm) => itm.giveupNum <= 0 && itm.buffType == CharaDef.ActionBuffType.FOCUS);
		if (sceneBattle_Buff != null)
		{
			sceneBattle_Buff.count--;
			if (sceneBattle_Buff.count <= 0)
			{
				target.buff.Remove(sceneBattle_Buff);
			}
		}
		sceneBattle_Buff = target.newBuff.Find((SceneBattle_Buff itm) => itm.giveupNum <= 0 && itm.buffType == CharaDef.ActionBuffType.FOCUS);
		if (sceneBattle_Buff != null)
		{
			sceneBattle_Buff.count--;
