			}
		}
	}

	private void proceedSchedule(SceneBattle_Chara target, bool isEnd)
	{
		if (target == null)
		{
			return;
		}
		target.buff.FindAll((SceneBattle_Buff itm) => itm.buffType == CharaDef.ActionBuffType.SCHEDULED).ForEach(delegate(SceneBattle_Buff bf)
		{
			if ((isEnd && bf.scheduledBuffParam.timingType == CharaDef.ActionTimingType.END) || (!isEnd && bf.scheduledBuffParam.timingType != CharaDef.ActionTimingType.END))
			{
				bf.scheduledTurn--;
				if (bf.scheduledTurn <= 0)
				{
					this.execScheduled(target, bf);
					target.buff.Remove(bf);
				}
			}
		});
		target.newBuff.FindAll((SceneBattle_Buff itm) => itm.buffType == CharaDef.ActionBuffType.SCHEDULED).ForEach(delegate(SceneBattle_Buff bf)
		{
			if ((isEnd && bf.scheduledBuffParam.timingType == CharaDef.ActionTimingType.END) || (!isEnd && bf.scheduledBuffParam.timingType != CharaDef.ActionTimingType.END))
			{
				bf.scheduledTurn--;
				if (bf.scheduledTurn <= 0)
				{
					target.newBuff.Remove(bf);
				}
			}
		});
	}

	private void execScheduled(SceneBattle_Chara target, SceneBattle_Buff scheduledBuff)
	{
		if (scheduledBuff.scheduledTurn <= 0)
		{
			SceneBattle_Action sceneBattle_Action = new SceneBattle_Action
			{
				chara = target,
				pos = Vector3.zero,
				tagPos = Vector3.zero,
				act = new List<SceneBattle_Act>()
			};
			if (this._step == SceneBattle.STEP.PlayerTurn)
			{
				this._plySchedulesList.Add(sceneBattle_Action);
			}
			else
			{
				this._enemySchedulesList.Add(sceneBattle_Action);
			}
			sceneBattle_Action.eff = new List<SceneBattle_Eff>();
			sceneBattle_Action.total = new List<SceneBattle_Tag>();
			List<SceneBattle_Tag> list = new List<SceneBattle_Tag>();
			int num = 0;
			CharaBuffParam scheduledBuffParam = scheduledBuff.scheduledBuffParam;
			if (scheduledBuffParam.buffType == CharaDef.ActionBuffType.RESURRECT && (num = scheduledBuffParam.increment) < 1)
			{
				num = 1;
			}
			List<SceneBattle_Tag> tagList = this.GetTagList(target, null, list, CharaDef.ActionTargetType.SELF, scheduledBuffParam.attributeMask, scheduledBuffParam.invertAttributeMask, scheduledBuffParam.healthMask, scheduledBuffParam.invertHealthMask, scheduledBuffParam.targetMask, scheduledBuffParam.invertTargetMask, scheduledBuffParam.breakElement, num, null, scheduledBuffParam.healthMaskType);
			if (tagList != null && tagList.Count > 0)
			{
				list.AddRange(tagList);
				if (sceneBattle_Action.act == null)
				{
					sceneBattle_Action.act = new List<SceneBattle_Act>();
				}
				SceneBattle_Act sceneBattle_Act = new SceneBattle_Act();
				sceneBattle_Act.buf = scheduledBuffParam;
				sceneBattle_Act.tag = tagList;
				sceneBattle_Act.tim = 99999f;
				sceneBattle_Act.idx = 0;
				sceneBattle_Action.act.Add(sceneBattle_Act);
				foreach (SceneBattle_Tag sceneBattle_Tag in sceneBattle_Act.tag)
				{
					sceneBattle_Tag.flg = 0;
					this.SetBuff(target, sceneBattle_Act.buf, sceneBattle_Tag, 1f);
				}
			}
			sceneBattle_Action.actTim = 0f;
			sceneBattle_Action.lokTim = 0f;
			sceneBattle_Action.dedTim = 99999f;
			sceneBattle_Action.dedChr = new List<SceneBattle_Chara>();
			sceneBattle_Action.retTim = 0.1f;
			sceneBattle_Action.step = SceneBattle.CMDSTEP.None;
			sceneBattle_Action.dmgkp = false;
			sceneBattle_Action.perDamage = null;
		}
	}

	private List<KeyValuePair<SceneBattle_Tag, SceneBattle_Buff>> ExecActionGiveup(SceneBattle_Action act)
	{
		HashSet<SceneBattle_Chara> hashSet = new HashSet<SceneBattle_Chara>();
		HashSet<SceneBattle_Chara> hashSet2 = new HashSet<SceneBattle_Chara>();
		foreach (SceneBattle_Act sceneBattle_Act in act.act)
		{
			if (sceneBattle_Act.dmg != null)
			{
				foreach (SceneBattle_Tag sceneBattle_Tag in sceneBattle_Act.tag)
				{
					if (sceneBattle_Tag.flg > 0)
					{
						if (sceneBattle_Tag.tag.type == CharaDef.Type.FRIENDS)
						{
							hashSet.Add(sceneBattle_Tag.tag);
						}
						else if (sceneBattle_Tag.tag.chara != null)
						{
							hashSet2.Add(sceneBattle_Tag.tag);
						}
					}
				}
			}
		}
		if (act.refFlg > 0)
		{
			if (act.chara.type == CharaDef.Type.FRIENDS)
			{
				hashSet.Add(act.chara);
			}
			else if (act.chara.chara != null)
			{
				hashSet2.Add(act.chara);
			}
		}
		if (act.perDamage != null)
		{
			foreach (SceneBattle_Chara sceneBattle_Chara in act.perDamage.Keys)
			{
				if (act.perDamage[sceneBattle_Chara] < 0)
				{
					if (sceneBattle_Chara.type == CharaDef.Type.FRIENDS)
					{
						hashSet.Add(sceneBattle_Chara);
					}
					else if (sceneBattle_Chara.chara != null)
					{
						hashSet2.Add(sceneBattle_Chara);
					}
				}
			}
		}
		return this.ExecGiveup(hashSet.Count, hashSet2.Count);
	}

	private List<KeyValuePair<SceneBattle_Tag, SceneBattle_Buff>> ExecGiveup(int ply, int emy)
	{
		List<SceneBattle_Chara> list = new List<SceneBattle_Chara>(this._playerList);
		list.AddRange(this._emyWaveList);
		list.AddRange(this._versusList);
		List<KeyValuePair<SceneBattle_Tag, SceneBattle_Buff>> list2 = new List<KeyValuePair<SceneBattle_Tag, SceneBattle_Buff>>();
		foreach (SceneBattle_Chara sceneBattle_Chara in list)
		{
			foreach (SceneBattle_Buff sceneBattle_Buff in sceneBattle_Chara.newBuff)
			{
				if (sceneBattle_Buff.giveupNum > 0)
				{
					int num = ((sceneBattle_Chara.type == CharaDef.Type.FRIENDS) ? ply : emy);
					while (num-- > 0 && sceneBattle_Buff.giveupCnt < sceneBattle_Buff.giveupNum)
					{
						sceneBattle_Buff.giveupCnt++;
						list2.Add(new KeyValuePair<SceneBattle_Tag, SceneBattle_Buff>(new SceneBattle_Tag(sceneBattle_Chara)
						{
							buf = sceneBattle_Buff.clone(),
							flg = 1,
							infKey = -1
						}, sceneBattle_Buff));
					}
				}
			}
		}
		foreach (KeyValuePair<SceneBattle_Tag, SceneBattle_Buff> keyValuePair in list2)
		{
			this.SetBuff(keyValuePair.Key, keyValuePair.Value);
		}
		return list2;
	}

	private void ExecGiveup(List<KeyValuePair<SceneBattle_Tag, SceneBattle_Buff>> exc)
	{
		foreach (KeyValuePair<SceneBattle_Tag, SceneBattle_Buff> keyValuePair in exc)
		{
			this.ExecBuff(null, keyValuePair.Key, keyValuePair.Value, false);
		}
	}

	private void CheckCommand(List<SceneBattle_Friends> friends, List<SceneBattle_FriendsCommand> command, List<SceneBattle_Action> wait, List<SceneBattle_FriendsCommand> rmv, float skldmg, int sklwat)
	{
		bool flag = friends[0].type == CharaDef.Type.FRIENDS;
		SceneBattle_Enemy sceneBattle_Enemy = ((SceneBattle.trainingBattle && this._boss >= 0) ? this._emyWaveList[this._boss] : null);
		int num = ((sceneBattle_Enemy == null) ? 0 : sceneBattle_Enemy.maxHp);
		int num2 = ((sceneBattle_Enemy == null) ? 0 : sceneBattle_Enemy.atkPwr);
		int num3 = ((sceneBattle_Enemy == null) ? 0 : sceneBattle_Enemy.defPwr);
		int num4 = this._trainingRevive;
		int num5 = this._trainingMission;
		this._scheduleActionDupList = new List<SceneBattle_Action>();
		List<SceneBattle_Chara> list = new List<SceneBattle_Chara>();
		bool flag2 = false;
		using (List<SceneBattle_Friends>.Enumerator enumerator = friends.GetEnumerator())
		{
			while (enumerator.MoveNext())
			{
				SceneBattle_Friends frd2 = enumerator.Current;
				if (command.FindAll((SceneBattle_FriendsCommand itm) => itm.chara.number == frd2.number && itm.card != null).Count > 1)
				{
					flag2 = true;
				}
				if (frd2.newHp <= frd2.escapeHp || this.IsStun(frd2, false) || this.IsSleep(frd2, false) || this.IsIce(frd2, false) || this.IsImpatience(frd2, false))
				{
					if (this.IsIce(frd2, false) && command.Find((SceneBattle_FriendsCommand itm) => itm.chara.number == frd2.number && itm.card != null) == null)
					{
						list.Add(frd2);
					}
				}
				else if (command.Find((SceneBattle_FriendsCommand itm) => itm.chara.number == frd2.number && itm.card != null) == null)
				{
					wait.Add(new SceneBattle_Action
					{
						chara = frd2,
						pos = Vector3.zero,
						tagPos = Vector3.zero
					});
				}
			}
		}
		for (int i = 0; i < command.Count; i++)
		{
