	private bool GetBuffParam(CharaDef.ActionBuffType typ, SceneBattle_Chara chr, CharaDef.AttributeMask spAtr, CharaDef.HealthMask spHel, CharaDef.EnemyMask spEmy, out float prmf, out int prmi)
	{
