		bool flag4 = false;
		CharaDef.ActionBuffType typ2 = typ;
		if (typ2 != CharaDef.ActionBuffType.TURN_MP && typ2 - CharaDef.ActionBuffType.TURN_HEAL > 1)
		{
			switch (typ2)
			{
			case CharaDef.ActionBuffType.SP_ADD_DAMAGE:
			case CharaDef.ActionBuffType.SP_HIT_RATE:
			case CharaDef.ActionBuffType.SP_RCV_DAMAGE:
