			case CharaDef.ActionBuffType.REFLECT:
			case CharaDef.ActionBuffType.ANTI_REFLECT:
			case CharaDef.ActionBuffType.PER_DAMAGE:
			case CharaDef.ActionBuffType.TICKLING:
				break;
			case CharaDef.ActionBuffType.COVER_LOWER:
			case CharaDef.ActionBuffType.COVER_RANDOM:
				flag4 = true;
				goto IL_008B;
			default:
				goto IL_008B;
			}
		}
		flag2 = true;
		IL_008B:
		bool flag5 = false;
		bool flag6 = false;
		if (typ != CharaDef.ActionBuffType.BUFF_INVALID && typ != CharaDef.ActionBuffType.DEBUFF_INVALID)
		{
			float num = 0f;
			int num2 = 0;
			flag5 = this.IsBufInv(chr, true);
