		}
		SceneBattle_Recover sceneBattle_Recover = SceneBattle.recoverList.Find((SceneBattle_Recover itm) => itm.Type.Contains(typ) && itm.Prm < 0);
		prmf = (flag2 ? 0f : 1f);
		prmi = 0;
		foreach (SceneBattle_Buff sceneBattle_Buff in chr.newBuff)
		{
			if (sceneBattle_Buff.buffType == typ && sceneBattle_Buff.giveupNum <= 0 && (sceneBattle_Buff.buffType != CharaDef.ActionBuffType.REFLECT || sceneBattle_Buff.increment <= 0) && (!flag3 || (sceneBattle_Buff.spAttributeMask & spAtr) != (CharaDef.AttributeMask)0 || (sceneBattle_Buff.spAttributeMask == (CharaDef.AttributeMask)0 && ((sceneBattle_Buff.spHealthMask & spHel) != (CharaDef.HealthMask)0 || (sceneBattle_Buff.spHealthMask == (CharaDef.HealthMask)0 && (sceneBattle_Buff.spEnemyMask & spEmy) != (CharaDef.EnemyMask)0)))))
			{
				if (sceneBattle_Recover != null)
				{
					if (sceneBattle_Recover.Prm == -1)
					{
						if (sceneBattle_Buff.coefficient > 1.0)
						{
							if (flag5)
							{
								continue;
							}
						}
						else if (sceneBattle_Buff.coefficient < 1.0 && flag6)
						{
							continue;
						}
					}
					else if (sceneBattle_Recover.Prm == -2)
					{
						if (sceneBattle_Buff.coefficient < 1.0)
						{
							if (flag5)
							{
								continue;
							}
						}
						else if (sceneBattle_Buff.coefficient > 1.0 && flag6)
