							continue;
						}
					}
					else if (sceneBattle_Recover.Prm == -4)
					{
						if (sceneBattle_Buff.increment > 0)
						{
							if (flag5)
							{
								continue;
							}
						}
						else if (sceneBattle_Buff.increment < 0 && flag6)
						{
							continue;
						}
					}
				}
				if (flag2)
				{
					prmf += (float)(sceneBattle_Buff.coefficient * sceneBattle_Buff.rate);
				}
				else if (flag4)
				{
					prmf *= (float)(sceneBattle_Buff.coefficient * (2.0 - sceneBattle_Buff.rate));
				}
				else
				{
					prmf *= (float)(sceneBattle_Buff.coefficient * sceneBattle_Buff.rate);
				}
				int num3 = (int)((double)((float)sceneBattle_Buff.increment) * sceneBattle_Buff.rate + (double)((sceneBattle_Buff.increment < 0) ? (-0.01f) : 0.01f));
				if (sceneBattle_Buff.increment < 0)
				{
					if (num3 >= 0)
					{
						num3 = -1;
					}
				}
				else if (sceneBattle_Buff.increment > 0 && num3 <= 0)
				{
					num3 = 1;
				}
				prmi += num3;
				flag = true;
			}
		}
		List<SceneBattle_Chara> list = new List<SceneBattle_Chara>(this._playerList);
		list.AddRange(this._emyWaveList);
		list.AddRange(this._versusList);
		foreach (SceneBattle_Chara sceneBattle_Chara in list)
