				CharaBuffParamAbility charaBuffParamAbility = this._abilityBuffList[num4];
				if (charaBuffParamAbility.giveupReuseNum <= 0 && (charaBuffParamAbility.buffType != CharaDef.ActionBuffType.REFLECT || charaBuffParamAbility.increment <= 0) && charaBuffParamAbility.turn <= 0)
				{
					int num5 = this.CheckAbility(typ, sceneBattle_Chara, num4, chr);
					if (flag3 && (charaBuffParamAbility.spAttributeMask & spAtr) == (CharaDef.AttributeMask)0)
					{
