	private bool GetResistParam(long msk, SceneBattle_Chara chr, out int prmi, bool isSkill = false, CharaDef.ActionBuffType buffType = CharaDef.ActionBuffType.INVALID)
	{
		bool flag = false;
		prmi = 0;
		foreach (SceneBattle_Buff sceneBattle_Buff in chr.newBuff)
		{
			if (sceneBattle_Buff.giveupNum <= 0 && sceneBattle_Buff.buffType == CharaDef.ActionBuffType.RESIST && (sceneBattle_Buff.abnormalType & msk) != 0L)
			{
				prmi += (int)((double)((float)sceneBattle_Buff.increment) * sceneBattle_Buff.rate + (double)((sceneBattle_Buff.increment < 0) ? (-0.01f) : 0.01f));
				flag = true;
			}
		}
		List<SceneBattle_Chara> list = new List<SceneBattle_Chara>(this._playerList);
		list.AddRange(this._emyWaveList);
		list.AddRange(this._versusList);
		foreach (SceneBattle_Chara sceneBattle_Chara in list)
		{
			foreach (int num in sceneBattle_Chara.abilityBuffKey)
			{
				CharaBuffParamAbility charaBuffParamAbility = this._abilityBuffList[num];
				if (charaBuffParamAbility.isInvalidResistance && isSkill && buffType == charaBuffParamAbility.buffType)
				{
					prmi = 0;
				}
				else if (charaBuffParamAbility.giveupReuseNum <= 0 && (charaBuffParamAbility.buffType != CharaDef.ActionBuffType.REFLECT || charaBuffParamAbility.increment <= 0) && charaBuffParamAbility.turn <= 0)
				{
					int num2 = this.CheckAbility(CharaDef.ActionBuffType.RESIST, sceneBattle_Chara, num, chr);
					if ((charaBuffParamAbility.abTyp & msk) != 0L)
					{
						while (num2-- > 0)
						{
							prmi += charaBuffParamAbility.increment;
							flag = true;
						}
					}
				}
			}
		}
		return flag;
	}

