		return "";
	}

	private string GetHealthName(CharaDef.HealthMask msk)
	{
		string text = "すべての";
		CharaDef.ActionBuffType actionBuffType = CharaDef.ActionBuffType.INVALID;
		if ((msk & CharaDef.HealthMask.HEALTH) != (CharaDef.HealthMask)0)
		{
			text = "げんき";
		}
		else if ((msk & CharaDef.HealthMask.POISON) != (CharaDef.HealthMask)0)
		{
			actionBuffType = CharaDef.ActionBuffType.POISON;
		}
		else if ((msk & CharaDef.HealthMask.STUN) != (CharaDef.HealthMask)0)
		{
			actionBuffType = CharaDef.ActionBuffType.STUN;
		}
		else if ((msk & CharaDef.HealthMask.SLEEP) != (CharaDef.HealthMask)0)
		{
			actionBuffType = CharaDef.ActionBuffType.SLEEP;
		}
		else if ((msk & CharaDef.HealthMask.SEAL) != (CharaDef.HealthMask)0)
		{
			actionBuffType = CharaDef.ActionBuffType.SEAL;
		}
		else if ((msk & CharaDef.HealthMask.ICE) != (CharaDef.HealthMask)0)
		{
			actionBuffType = CharaDef.ActionBuffType.ICE;
		}
		else if ((msk & CharaDef.HealthMask.BLEED) != (CharaDef.HealthMask)0)
		{
			actionBuffType = CharaDef.ActionBuffType.BLEED;
		}
		else if ((msk & CharaDef.HealthMask.UNHEAL) != (CharaDef.HealthMask)0)
		{
			actionBuffType = CharaDef.ActionBuffType.UNHEAL;
		}
		else if ((msk & CharaDef.HealthMask.MP_NOCOUNT) != (CharaDef.HealthMask)0)
		{
			actionBuffType = CharaDef.ActionBuffType.MP_NOCOUNT;
		}
		else if ((msk & CharaDef.HealthMask.BUFF_INVALID) != (CharaDef.HealthMask)0)
		{
			actionBuffType = CharaDef.ActionBuffType.BUFF_INVALID;
		}
		else if ((msk & CharaDef.HealthMask.PARALYSIS) != (CharaDef.HealthMask)0)
		{
			actionBuffType = CharaDef.ActionBuffType.PARALYSIS;
		}
		else if ((msk & CharaDef.HealthMask.SILENCE) != (CharaDef.HealthMask)0)
		{
			actionBuffType = CharaDef.ActionBuffType.SILENCE;
		}
		else if ((msk & CharaDef.HealthMask.INAUDIBLE) != (CharaDef.HealthMask)0)
		{
			actionBuffType = CharaDef.ActionBuffType.INAUDIBLE;
		}
		else if ((msk & CharaDef.HealthMask.BURNED) != (CharaDef.HealthMask)0)
		{
			actionBuffType = CharaDef.ActionBuffType.BURNED;
		}
		else if ((msk & CharaDef.HealthMask.FOCUS) != (CharaDef.HealthMask)0)
		{
			actionBuffType = CharaDef.ActionBuffType.FOCUS;
		}
		else if ((msk & CharaDef.HealthMask.IMPATIENCE) != (CharaDef.HealthMask)0)
		{
			actionBuffType = CharaDef.ActionBuffType.IMPATIENCE;
		}
		if (actionBuffType != CharaDef.ActionBuffType.INVALID)
		{
			text = this.GetBuffName(actionBuffType);
		}
		return text;
	}

