	private int IsBuffUpDown(SceneBattle_Buff bf, bool isSchedule = false)
	{
		int num = 0;
		CharaDef.ActionBuffType type = (isSchedule ? bf.scheduledBuffType : bf.buffType);
		if (type == CharaDef.ActionBuffType.RESIST || type == CharaDef.ActionBuffType.MP)
		{
			num = ((bf.increment > 0) ? 1 : 0);
		}
		else
		{
			SceneBattle_Recover sceneBattle_Recover = SceneBattle.recoverList.Find((SceneBattle_Recover itm) => itm.Type.Contains(type));
			if (sceneBattle_Recover == null || sceneBattle_Recover.Prm >= 0)
			{
				num = -1;
			}
			else if (sceneBattle_Recover.Prm == -1)
			{
				if (bf.coefficient > 1.0)
				{
					num = 1;
				}
			}
			else if (sceneBattle_Recover.Prm == -2)
			{
				if (bf.coefficient < 1.0)
				{
					num = 1;
				}
			}
			else if (sceneBattle_Recover.Prm == -3)
			{
				num = ((bf.increment > 0) ? 1 : 0);
			}
			else if (sceneBattle_Recover.Prm == -4)
			{
				num = ((bf.increment > 0) ? 1 : 0);
			}
			else if (sceneBattle_Recover.Prm == -5)
			{
				num = ((bf.increment > 0) ? 1 : 0);
			}
			else if (sceneBattle_Recover.Prm == -6)
			{
				num = 1;
			}
		}
		return num;
	}

	private SceneBattle_Chara GetAbnormalChara(CharaDef.ActionBuffType typ, SceneBattle_Chara chr, bool nb = false)
	{
		SceneBattle_Buff sceneBattle_Buff = (nb ? chr.newBuff.Find((SceneBattle_Buff itm) => itm.giveupNum <= 0 && itm.buffType == typ) : chr.buff.Find((SceneBattle_Buff itm) => itm.giveupNum <= 0 && itm.buffType == typ));
		if (sceneBattle_Buff == null)
		{
			return null;
		}
		if (sceneBattle_Buff.chrTyp == CharaDef.Type.FRIENDS)
		{
			return this._playerList[sceneBattle_Buff.chrIdx];
		}
		if (sceneBattle_Buff.chrTyp == CharaDef.Type.INVALID)
		{
			return this._versusList[sceneBattle_Buff.chrIdx];
		}
		return this._enemyList[sceneBattle_Buff.chrIdx];
	}

	private CharaDef.HealthMask GetHealthMask(SceneBattle_Chara chr, bool nb = false)
	{
		CharaDef.HealthMask healthMask = (CharaDef.HealthMask)0;
		List<SceneBattle_Buff> list = (nb ? chr.newBuff : chr.buff);
		if (list != null)
		{
			foreach (SceneBattle_Buff sceneBattle_Buff in list)
			{
				if (sceneBattle_Buff.buffType == CharaDef.ActionBuffType.STUN)
				{
					healthMask |= CharaDef.HealthMask.STUN;
				}
				else if (sceneBattle_Buff.buffType == CharaDef.ActionBuffType.POISON)
				{
					healthMask |= CharaDef.HealthMask.POISON;
				}
