								sceneBattle_Missile.tag = new Vector3(vector.x, sceneBattle_Eff.height, vector.z);
								sceneBattle_Missile.eff = EffectManager.InstantiateEffect(sceneBattle_Eff.nam, this._effect, sceneBattle_Eff.light ? ((act.chara.type == CharaDef.Type.FRIENDS) ? SceneBattle.playerLayer : SceneBattle.enemyLayer) : SceneBattle.effectLayer, 1f);
								sceneBattle_Missile.eff.effectObject.transform.localPosition = (sceneBattle_Missile.pos = sceneBattle_Eff.pos + act.chara.chara.GetNodePos(sceneBattle_Eff.node.ToString()));
								sceneBattle_Missile.eff.effectObject.transform.LookAt(sceneBattle_Missile.tag);
								sceneBattle_Missile.eff.effectObject.transform.localEulerAngles += sceneBattle_Eff.rot;
								sceneBattle_Missile.eff.effectObject.transform.localScale = sceneBattle_Eff.scl;
								sceneBattle_Missile.eff.PlayEffect(false);
								sceneBattle_Missile.len = sceneBattle_Eff.fly;
								sceneBattle_Missile.tim = 0f;
								sceneBattle_Missile.chr = act.chara;
								this._missileList.Add(sceneBattle_Missile);
								if (act.camMssl == null && act.actParam != null && act.actParam.actionParam.cameraType == CharaDef.ActionCameraType.BULLET_FOCUS)
								{
									act.camMssl = sceneBattle_Missile;
								}
							}
							else
							{
								bool flag = false;
								if (sceneBattle_Eff.hittag == null)
								{
									flag = true;
								}
								else
								{
									SceneBattle_Tag sceneBattle_Tag = sceneBattle_Eff.hittag.Find((SceneBattle_Tag itm) => itm.tag == tt);
									if (sceneBattle_Tag != null && (sceneBattle_Tag.hp > 0 || sceneBattle_Tag.flg > 0))
									{
										flag = true;
									}
								}
								if (flag)
								{
									int num = (sceneBattle_Eff.light ? ((act.chara.type == CharaDef.Type.FRIENDS) ? SceneBattle.playerLayer : SceneBattle.enemyLayer) : SceneBattle.effectLayer);
									EffectData effectData2 = EffectManager.InstantiateEffect(sceneBattle_Eff.nam, this._effect, num, 1f);
									effectData2.effectObject.transform.localPosition = vector + sceneBattle_Eff.pos;
									effectData2.effectObject.transform.localEulerAngles = sceneBattle_Eff.rot;
									effectData2.effectObject.transform.localScale = sceneBattle_Eff.scl;
									effectData2.SetPublisher(act.chara.chara.gameObject.name);
									effectData2.PlayEffect(false);
									this.SetCamouflageEffect(effectData2);
									this._effectDataList.Add(effectData2);
								}
							}
						}
					}
				}
				sceneBattle_Eff.tim = -1f;
			}
		}
	}

	private void PlayerChain()
	{
		SceneBattle_FriendsCommand sceneBattle_FriendsCommand = this._plyCmdList[this._plyCmdCtr];
		if (this._stepCtr == 0)
		{
			this._stepCtr++;
			this._chainCount = 0;
			foreach (SceneBattle_FriendsCommand sceneBattle_FriendsCommand2 in sceneBattle_FriendsCommand.chainLst)
			{
				List<FieldCameraScaler> charaCameraList = this._charaCameraList;
				int chainCount = this._chainCount;
				this._chainCount = chainCount + 1;
				FieldCameraScaler fieldCameraScaler = charaCameraList[chainCount];
				fieldCameraScaler.transform.position = (sceneBattle_FriendsCommand2.chara as SceneBattle_Friends).chainCameraPos;
				fieldCameraScaler.transform.eulerAngles = (sceneBattle_FriendsCommand2.chara as SceneBattle_Friends).chainCameraRot;
				fieldCameraScaler.fieldCamera.enabled = true;
				fieldCameraScaler.fieldCamera.cullingMask = (1 << SceneBattle.playerLayer) | (1 << SceneBattle.playerLayer + 1) | (1 << SceneBattle.playerShadowLayer) | (1 << SceneBattle.stageLayer) | (1 << SceneBattle.playerBloomLayer);
				fieldCameraScaler.GetComponent<MultipleGaussianBloom>().enabled = sceneBattle_FriendsCommand2.chara.chara.charaEffect != null;
				fieldCameraScaler.gameObject.SetActive(true);
				sceneBattle_FriendsCommand2.chara.chara.PlayAnimation(CharaMotionDefine.ActKey.ACCENT, false, 1f, 0.3f, 0.15f, false);
				this.PlayVoice(sceneBattle_FriendsCommand2.chara, CharaVoiceCombi.SitType.INVALID, (this._chainCount > 1) ? VOICE_TYPE.CHA02 : VOICE_TYPE.CHA01);
			}
			this._waitIconList = new List<KeyValuePair<Texture2D, List<bool>>>();
			this._waitDisp = 0f;
			if (sceneBattle_FriendsCommand.joinLst != null)
			{
				foreach (SceneBattle_FriendsCommand sceneBattle_FriendsCommand3 in sceneBattle_FriendsCommand.joinLst)
				{
					this._waitIconList.Add(new KeyValuePair<Texture2D, List<bool>>((sceneBattle_FriendsCommand3.chara as SceneBattle_Friends).icon, new List<bool> { sceneBattle_FriendsCommand3.paralysis, sceneBattle_FriendsCommand3.silence }));
				}
			}
			if (this._waitIconList.Count > 0)
			{
				SoundManager.Play("prd_se_standby_skill_info", false, false);
			}
			if (this._maxChain < this._chainCount)
			{
				this._maxChain = this._chainCount;
			}
			if (this._chainCount >= 2)
			{
				this._chainSumCount += this._chainCount;
			}
			this._chainExec++;
			SceneBattle_CardInfo card = sceneBattle_FriendsCommand.card;
			int num = 1;
			string text = "ダメージ";
			string text2 = "<size=32>3.3</size>倍";
			if (card != null)
			{
				if (card.card.type == CharaDef.OrderCardType.BEAT || card.card.type == CharaDef.OrderCardType.SPECIAL)
				{
					if (this._maxChainBeat < this._chainCount)
					{
						this._maxChainBeat = this._chainCount;
					}
					num = 3;
					text = "ダメージ";
					int num2 = (int)this.chainDmg(this._chainCount);
					text2 = "<size=32>1." + (num2 / 10).ToString();
					if ((num2 %= 10) > 0)
					{
						text2 += num2.ToString();
					}
					text2 += "</size>倍";
				}
				else if (card.card.type == CharaDef.OrderCardType.ACTION)
				{
					if (this._maxChainAction < this._chainCount)
					{
						this._maxChainAction = this._chainCount;
					}
					num = 1;
					text = "獲得ＭＰ";
					text2 = "<size=32>+" + this.chainKp(this._chainCount).ToString() + "</size>";
				}
				else if (card.card.type == CharaDef.OrderCardType.TRY)
				{
					if (this._maxChainTry < this._chainCount)
					{
						this._maxChainTry = this._chainCount;
					}
					num = 2;
					text = "プラズムチャージ";
					text2 = "<size=32>+" + (this.chainWild(this._chainCount) / 10).ToString() + "</size>";
				}
			}
			for (int i = 0; i < this._chainCount; i++)
			{
				this._charaCameraList[i].rect = new Rect((float)i / (float)this._chainCount, -0.1f, 1f / (float)this._chainCount, 1.1f);
			}
			for (int j = this._chainCount; j < this._charaCameraList.Count; j++)
			{
				this._charaCameraList[j].gameObject.SetActive(false);
			}
			this._camera.fieldCamera.cullingMask &= ~(1 << SceneBattle.playerLayer) & ~(1 << SceneBattle.playerShadowLayer) & ~(1 << SceneBattle.playerBloomLayer);
			this._guiData.ChainFrontAE.gameObject.SetActive(true);
			this._guiData.ChainFrontAE.GetComponent<PguiReplaceAECtrl>().Replace("CHAIN_" + this._chainCount.ToString("D2"));
			this._guiData.ChainFrontAE.PlayAnimation((sceneBattle_FriendsCommand.arts > 0) ? PguiAECtrl.AmimeType.START_SUB : PguiAECtrl.AmimeType.START, null);
			this._guiData.ChainFrontAE.transform.Find("ChorusOption/Base/Img_Num").GetComponent<PguiReplaceSpriteCtrl>().Replace(this._chainCount);
			this._guiData.ChainFrontAE.transform.Find("ChorusOption/Base/Img_Flag").GetComponent<PguiReplaceSpriteCtrl>().Replace(num);
			this._guiData.ChainFrontAE.transform.Find("ChorusOption/Base/Txt/Txt_Option").GetComponent<PguiTextCtrl>().text = text;
			this._guiData.ChainFrontAE.transform.Find("ChorusOption/Base/Txt/Num_Option").GetComponent<PguiTextCtrl>().text = text2;
			this._guiData.ChainBackAE.transform.parent.gameObject.SetActive(true);
			this._guiData.ChainBackAE.GetComponent<PguiReplaceAECtrl>().Replace("CHAIN_" + this._chainCount.ToString("D2"));
			this._guiData.ChainBackAE.PlayAnimation(PguiAECtrl.AmimeType.START, null);
			if (this._chainCount < 5)
			{
				SoundManager.Play("prd_se_chain_start", false, false);
			}
			else
			{
				SoundManager.Play("prd_se_five_chain_start", false, false);
			}
			using (List<AEImage>.Enumerator enumerator2 = this._guiData.StaySkill.GetEnumerator())
			{
				while (enumerator2.MoveNext())
				{
					AEImage aeimage = enumerator2.Current;
					aeimage.gameObject.SetActive(false);
				}
				return;
			}
		}
		if (!this._guiData.ChainBackAE.transform.parent.gameObject.activeSelf || this._guiData.ChainBackAE.GetAnimeType() != PguiAECtrl.AmimeType.START || !this._guiData.ChainBackAE.IsPlaying())
		{
			int num3 = this.chainAct(this._chainCount);
			num3 = (int)((float)num3 * this._playerSkillAdd + 0.01f);
			if (this._noCaptain)
			{
				num3 = 0;
			}
			if ((this._addAction += num3) > SceneBattle.addActionMax)
			{
				this._addAction = SceneBattle.addActionMax;
			}
			this._chainCount = 0;
			this._subStep = ((sceneBattle_FriendsCommand.arts > 0) ? SceneBattle.SUBSTEP.Arts : SceneBattle.SUBSTEP.Attack);
			float num4 = 0.328125f;
			float num5 = 0.8888889f;
			foreach (FieldCameraScaler fieldCameraScaler2 in this._charaCameraList)
			{
				fieldCameraScaler2.rect = new Rect(0f, 0f, num4, num5);
				fieldCameraScaler2.gameObject.SetActive(false);
			}
			this._camera.fieldCamera.cullingMask |= (1 << SceneBattle.playerLayer) | (1 << SceneBattle.playerShadowLayer) | (1 << SceneBattle.playerBloomLayer);
			return;
		}
		this.DispWaitSkill(this._guiData.StaySkill);
	}

	private void PlayerArts()
	{
		SceneBattle_FriendsCommand sceneBattle_FriendsCommand = this._plyCmdList[this._plyCmdCtr];
		if (this._stepCtr == 0)
		{
			int num = sceneBattle_FriendsCommand.chara.maxKp;
			if (sceneBattle_FriendsCommand.tickle > 0)
			{
				num = num * this._battleParam.enemySideTickling.mpDecreaseRate / 100;
			}
			if (sceneBattle_FriendsCommand.chara.arts.authParam.EnhanceFlag)
			{
				num = this.MaxMP(sceneBattle_FriendsCommand.chara, false);
			}
			if ((sceneBattle_FriendsCommand.chara.nowKp -= num) < 0)
			{
				sceneBattle_FriendsCommand.chara.nowKp = 0;
			}
			this._chainCount++;
			if (string.IsNullOrEmpty(sceneBattle_FriendsCommand.actParam.authParam.authName) || this._superSpeed)
			{
				this._subStep = SceneBattle.SUBSTEP.Attack;
				if (sceneBattle_FriendsCommand.chain > 0)
				{
					this.DispChainCount();
				}
			}
			else
			{
				this._stepCtr = ((sceneBattle_FriendsCommand.tickle == 0) ? 1 : 11);
			}
			this._artsCount++;
		}
		if (this._stepCtr == 1 || this._stepCtr == 21)
		{
			this._stepCtr = 2;
			if (sceneBattle_FriendsCommand.chain > 0)
			{
				this.DispChainCount();
			}
			this._authPlayer.gameObject.SetActive(true);
			this._authPlayer.transform.localEulerAngles = Vector3.zero;
			List<CharaModelHandle.InitializeParam> list = new List<CharaModelHandle.InitializeParam> { sceneBattle_FriendsCommand.chara.chara.initializeParam };
			if (SceneBattle.pvpBattle || SceneBattle.trainingBattle || sceneBattle_FriendsCommand.chara.number - 1 != this._resultArgs.deck.deckHelperIndex)
			{
				foreach (CharaPackData charaPackData in DataManager.DmChara.GetUserCharaMap().Values)
				{
					if (charaPackData.id != sceneBattle_FriendsCommand.chara.charaId)
					{
						list.Add(CharaModelHandle.InitializeParam.CreaateByCharaId(charaPackData.id, charaPackData.equipClothImageId, charaPackData.equipLongSkirt, false));
					}
				}
			}
			this._authPlayer.Initialize(sceneBattle_FriendsCommand.actParam.authParam.authName, list, this._stage, null, null, sceneBattle_FriendsCommand.synergy, this._timeScale > 0, false);
			this._authLoading = TimeManager.SystemNow;
			return;
		}
		if (this._stepCtr == 2)
		{
			if (this._authPlayer.IsFinishInitialize())
			{
				this._stepCtr = 3;
				this._authPlayer.PlayAuth(false);
				this._guiData.KemonoArtsAE.gameObject.SetActive(true);
				this._guiData.KemonoArtsAE.GetComponent<PguiReplaceAECtrl>().Replace(sceneBattle_FriendsCommand.synergy ? "MAX" : "NORMAL");
				this._guiData.KemonoArtsAE.PlayAnimation(PguiAECtrl.AmimeType.START, null);
				this._guiData.KemonoArtsAE.transform.Find("Txt_CharaName").GetComponent<PguiTextCtrl>().text = sceneBattle_FriendsCommand.chara.charaName;
				this._guiData.KemonoArtsAE.transform.Find("SkillName/Txt_SkillName").GetComponent<PguiTextCtrl>().text = sceneBattle_FriendsCommand.chara.arts.actionName;
				this._guiData.KemonoFadeAE.gameObject.SetActive(true);
				this._guiData.KemonoFadeAE.PlayAnimation(PguiAECtrl.AmimeType.START, null);
				this._camera.gameObject.SetActive(false);
				CanvasManager.HdlLoadAndTipsCtrl.SetDispLoading(false);
				return;
			}
			if ((TimeManager.SystemNow - this._authLoading).TotalSeconds > 1.0)
			{
				CanvasManager.HdlLoadAndTipsCtrl.SetDispLoading(true);
				return;
			}
		}
		else if (this._stepCtr == 3)
		{
			if (this._authPlayer.IsFinished())
			{
				this._authPlayer.DestroyProcessing();
				this._authPlayer.gameObject.SetActive(false);
				this._subStep = SceneBattle.SUBSTEP.Attack;
				this._camera.gameObject.SetActive(true);
				return;
			}
		}
		else if (this._stepCtr == 11)
		{
			SceneBattle.CMDSTEP cmdstep = ((this._plyCmdCtr > 0) ? this._plyCmdList[this._plyCmdCtr - 1].step : SceneBattle.CMDSTEP.None);
			if (cmdstep == SceneBattle.CMDSTEP.None || cmdstep == SceneBattle.CMDSTEP.End)
			{
				this._stepCtr = 12;
				this._reqCamera = SceneBattle.CameraType.Dead;
				this._cameraBattleDeadLok = sceneBattle_FriendsCommand.chara.chara.GetHaraPos();
				this._cameraBattleDeadPos = this._cameraBattleDeadLok + new Vector3(-0.75f, -0.5f, 5f);
				this._cameraBattleDeadFov = SceneBattle.battleFieldOfView;
				this._guiData.TickleStartAE.gameObject.SetActive(true);
				this._guiData.TickleStartAE.PlayAnimation(PguiAECtrl.AmimeType.START, null);
				SoundManager.Play("prd_se_tickle_start", false, false);
				return;
			}
		}
		else if (this._stepCtr == 12)
		{
			if (!this._guiData.TickleStartAE.IsPlaying())
			{
				this._stepCtr = 13;
				this._reqCamera = SceneBattle.CameraType.Dead;
				this._cameraBattleDeadPos.z = this._cameraBattleDeadPos.z - 1.5f;
				this._guiData.TickleStartAE.gameObject.SetActive(false);
				sceneBattle_FriendsCommand.chara.chara.PlayAnimation((this._timeScale > 0) ? CharaMotionDefine.ActKey.LAUGH_SHORT : CharaMotionDefine.ActKey.LAUGH, false, 1f, 0.3f, 0.15f, false);
				sceneBattle_FriendsCommand.effTickle = EffectManager.InstantiateEffect("Ef_buff_tickling", this._effect, sceneBattle_FriendsCommand.chara.chara.GetLayer(), 1f);
				sceneBattle_FriendsCommand.effTickle.effectObject.transform.localPosition = sceneBattle_FriendsCommand.chara.chara.GetHaraPos() + new Vector3(0f, 0f, 0.5f);
				sceneBattle_FriendsCommand.effTickle.PlayEffect(false);
				this.PlayVoice(sceneBattle_FriendsCommand.chara, CharaVoiceCombi.SitType.INVALID, VOICE_TYPE.JAM01);
				sceneBattle_FriendsCommand.seTickle = SoundManager.Play("prd_se_tickle_doing", true, false);
				return;
			}
		}
		else if (this._stepCtr == 13 || this._stepCtr == 14)
		{
			if (!sceneBattle_FriendsCommand.chara.chara.IsCurrentAnimation(CharaMotionDefine.ActKey.LAUGH) && !sceneBattle_FriendsCommand.chara.chara.IsCurrentAnimation(CharaMotionDefine.ActKey.LAUGH_SHORT))
			{
				this._stepCtr = 15;
				EffectManager.DestroyEffect(sceneBattle_FriendsCommand.effTickle);
				sceneBattle_FriendsCommand.effTickle = null;
				sceneBattle_FriendsCommand.seTickle.Stop();
				this._guiData.TickleResultAE.gameObject.SetActive(true);
				this._guiData.TickleResultAE.GetComponent<PguiReplaceAECtrl>().Replace((sceneBattle_FriendsCommand.tickle > 0) ? "myself_success" : "myself_mistake");
				this._guiData.TickleResultAE.PlayAnimation(PguiAECtrl.AmimeType.START, null);
				float num2 = 0f;
				if (sceneBattle_FriendsCommand.tickle > 0)
				{
					this.PlayVoice(sceneBattle_FriendsCommand.chara, CharaVoiceCombi.SitType.INVALID, VOICE_TYPE.JMF01);
					num2 = SoundManager.GetVoiceLength(sceneBattle_FriendsCommand.chara.chara.loadVoiceCueSheetName, VOICE_TYPE.JMF01);
				}
				if (num2 < 2f)
				{
					num2 = 2f;
				}
				this.SetTimer(num2);
				SoundManager.Play((sceneBattle_FriendsCommand.tickle > 0) ? "prd_se_tickle_fail" : "prd_se_tickle_success", false, false);
				return;
			}
			if (this._stepCtr == 13)
			{
				if (sceneBattle_FriendsCommand.chara.chara.GetMotionTime(false) < 0.5f)
				{
					this._cameraLokTarget = (this._cameraBattleDeadLok = sceneBattle_FriendsCommand.chara.chara.GetHaraPos());
					this._cameraPosTarget = (this._cameraBattleDeadPos = this._cameraBattleDeadLok + new Vector3(-0.75f, -0.5f, 3.5f));
					sceneBattle_FriendsCommand.effTickle.effectObject.transform.localPosition = sceneBattle_FriendsCommand.chara.chara.GetHaraPos() + new Vector3(0f, 0f, 0.5f);
					return;
				}
				if (sceneBattle_FriendsCommand.chara.chara.GetMotionTime(false) >= (sceneBattle_FriendsCommand.chara.chara.IsCurrentAnimation(CharaMotionDefine.ActKey.LAUGH_SHORT) ? 3f : 5f))
				{
					if (sceneBattle_FriendsCommand.tickle > 0)
					{
						this.PlayVoice(sceneBattle_FriendsCommand.chara, CharaVoiceCombi.SitType.INVALID, VOICE_TYPE.JAM02);
					}
					this._stepCtr = 14;
					return;
				}
			}
		}
		else if (this._stepCtr == 15 && !this._guiData.TickleResultAE.IsPlaying() && this.IsTimeOut())
		{
			this._guiData.TickleResultAE.gameObject.SetActive(false);
			if (sceneBattle_FriendsCommand.tickle > 0)
			{
				this._subStep = SceneBattle.SUBSTEP.Prepare;
				this._plyCmdCtr++;
				this.UpdateActionCard(sceneBattle_FriendsCommand);
				return;
			}
			this._stepCtr = 21;
		}
	}

	private void PlayerAttack()
	{
		SceneBattle_FriendsCommand sceneBattle_FriendsCommand = this._plyCmdList[this._plyCmdCtr];
		if (this._stepCtr == 0)
		{
			this._stepCtr++;
			if (sceneBattle_FriendsCommand.arts <= 0)
			{
				this._chainCount++;
				if (sceneBattle_FriendsCommand.chain > 0)
				{
					this.DispChainCount();
				}
				if (sceneBattle_FriendsCommand.card != null)
				{
					if (sceneBattle_FriendsCommand.card.card.type == CharaDef.OrderCardType.BEAT)
					{
						this._guiData.BeatActAE.transform.parent.gameObject.SetActive(true);
						this._guiData.BeatActAE.transform.parent.Find("Base/Txt_SkillName").GetComponent<PguiTextCtrl>().text = sceneBattle_FriendsCommand.chara.specialAttack.actionName;
						this._guiData.BeatActAE.PlayAnimation(PguiAECtrl.AmimeType.START, null);
					}
					else if (sceneBattle_FriendsCommand.card.card.type == CharaDef.OrderCardType.ACTION || sceneBattle_FriendsCommand.card.card.type == CharaDef.OrderCardType.SPECIAL)
					{
						int num = this.MaxMP(sceneBattle_FriendsCommand.chara, false);
						sceneBattle_FriendsCommand.dspKp = (float)sceneBattle_FriendsCommand.chara.nowKp / (float)sceneBattle_FriendsCommand.chara.maxKp;
						PguiAECtrl pguiAECtrl = ((sceneBattle_FriendsCommand.card.card.type == CharaDef.OrderCardType.ACTION) ? this._guiData.ActionActAE : this._guiData.SpecialActAE);
						pguiAECtrl.transform.parent.gameObject.SetActive(true);
						Transform transform = pguiAECtrl.transform.parent.Find("Base/KpgageAll");
						transform.Find("Kpgage_Gage").GetComponent<PguiImageCtrl>().m_Image.fillAmount = Mathf.Clamp01((sceneBattle_FriendsCommand.dspKp > 1f) ? (sceneBattle_FriendsCommand.dspKp - 1f) : sceneBattle_FriendsCommand.dspKp);
						transform.Find("Kpgage_Add").gameObject.SetActive(false);
						AEImage component = transform.Find("AEImage_NotHeal").GetComponent<AEImage>();
						component.autoPlay = true;
						component.playLoop = true;
						component.playOutTime = component.duration;
						component.playTime = 0f;
						component.gameObject.SetActive(this.IsNoMP(sceneBattle_FriendsCommand.chara, false));
						pguiAECtrl.PlayAnimation(PguiAECtrl.AmimeType.START, null);
						pguiAECtrl.transform.parent.Find("Base/AEImage_Plus").GetComponent<PguiAECtrl>().PauseAnimation(PguiAECtrl.AmimeType.START, null);
						pguiAECtrl.transform.parent.Find("Base/AEImage_MAX").GetComponent<PguiAECtrl>().PauseAnimation(PguiAECtrl.AmimeType.START, null);
						int num2 = 0;
						if (!component.gameObject.activeSelf)
						{
							foreach (SceneBattle_Tag sceneBattle_Tag in sceneBattle_FriendsCommand.kp)
							{
								if (sceneBattle_Tag.tag == sceneBattle_FriendsCommand.chara)
								{
									num2 += sceneBattle_Tag.kp;
								}
							}
						}
						pguiAECtrl.transform.parent.Find("Base/AEImage_Plus/Num_KPPlus").GetComponent<PguiTextCtrl>().text = "+" + num2.ToString();
						bool flag = sceneBattle_FriendsCommand.chara.arts != null;
						pguiAECtrl.transform.parent.Find("Base/KpgageAll").gameObject.SetActive(flag);
						pguiAECtrl.transform.parent.Find("Base/AEImage_Plus").gameObject.SetActive(flag);
						pguiAECtrl.transform.parent.Find("Base/AEImage_MAX").gameObject.SetActive(flag);
						pguiAECtrl.transform.parent.Find("Base/KpgageAll_MPdouble").gameObject.SetActive(flag && sceneBattle_FriendsCommand.chara.maxKp < num);
						pguiAECtrl.transform.parent.Find("Base/KpgageAll_MPdouble/Kpgage_Gage_MPdouble").gameObject.SetActive(sceneBattle_FriendsCommand.chara.nowKp > sceneBattle_FriendsCommand.chara.maxKp);
						pguiAECtrl.transform.parent.Find("Base/AEImage_MAX_MPdouble").gameObject.SetActive(false);
					}
					if (sceneBattle_FriendsCommand.card.card.type == CharaDef.OrderCardType.TRY || sceneBattle_FriendsCommand.card.card.type == CharaDef.OrderCardType.SPECIAL)
					{
						this._guiData.TryActAE.transform.parent.gameObject.SetActive(true);
						this._guiData.TryActPlasmAE.gameObject.SetActive(true);
						this._guiData.TryActAE.PlayAnimation(PguiAECtrl.AmimeType.START, null);
						this._guiData.TryActPlasmAE.PauseAnimation(PguiAECtrl.AmimeType.START, null);
					}
				}
			}
			if (sceneBattle_FriendsCommand.wildChain > 0)
			{
				this._wildPower += sceneBattle_FriendsCommand.wildChain;
				this._wildPowerBF = int.Parse(this._guiData.NumYaseiTotal.text);
				sceneBattle_FriendsCommand.wildChain = 0;
			}
			if (sceneBattle_FriendsCommand.chainLst != null && sceneBattle_FriendsCommand.chainLst.Count > 1)
			{
				sceneBattle_FriendsCommand.chainLst[1].chara.chara.PlayAnimation(CharaMotionDefine.ActKey.ACCENT, false, 1f, 0.3f, 0.15f, false);
			}
			sceneBattle_FriendsCommand.step = SceneBattle.CMDSTEP.Init;
			if (sceneBattle_FriendsCommand.chara.bleed && sceneBattle_FriendsCommand.card != null)
			{
				this._bleedChrList.Add(sceneBattle_FriendsCommand.chara);
			}
			if (sceneBattle_FriendsCommand.chara.burned && sceneBattle_FriendsCommand.card != null)
			{
