		else
		{
			if (this._tutorialStep == SceneBattle.TutorialStep.BATTLE1_3_1 || this._tutorialStep == SceneBattle.TutorialStep.BATTLE1_3_2 || this._tutorialStep == SceneBattle.TutorialStep.BATTLE1_3_3)
			{
