				bool flag3 = sceneBattle_FriendsCommand.card != null && sceneBattle_FriendsCommand.card.card != null && sceneBattle_FriendsCommand.card.card.type == CharaDef.OrderCardType.ACTION;
				Transform transform2 = (flag3 ? this._guiData.ActionActAE.transform.parent.Find("Base/KpgageAll") : this._guiData.SpecialActAE.transform.parent.Find("Base/KpgageAll"));
