					image.fillAmount = Mathf.Clamp01((sceneBattle_FriendsCommand.dspKp > 1f) ? (sceneBattle_FriendsCommand.dspKp - 1f) : sceneBattle_FriendsCommand.dspKp);
					if (flag3)
