						this._guiData.SpecialActAE.transform.parent.Find("Base/KpgageAll_MPdouble").gameObject.SetActive(sceneBattle_FriendsCommand.chara.arts != null && sceneBattle_FriendsCommand.chara.maxKp < num3);
						this._guiData.SpecialActAE.transform.parent.Find("Base/KpgageAll_MPdouble/Kpgage_Gage_MPdouble").gameObject.SetActive(sceneBattle_FriendsCommand.dspKp > 1f);
