				sceneBattle_FriendsCommand.kp.Clear();
				if (!sceneBattle_FriendsCommand.dmgkp && !SceneBattle.pvpBattle && !SceneBattle.friendsBattle)
				{
					sceneBattle_FriendsCommand.dmgkp = true;
					List<SceneBattle_Chara> list = new List<SceneBattle_Chara>();
					foreach (SceneBattle_Act sceneBattle_Act2 in sceneBattle_FriendsCommand.act)
					{
						if (sceneBattle_Act2.dmg != null)
						{
							if (sceneBattle_Act2.tim >= 0f)
							{
								sceneBattle_FriendsCommand.dmgkp = false;
							}
							foreach (SceneBattle_Tag sceneBattle_Tag3 in sceneBattle_Act2.tag)
							{
								if (sceneBattle_Tag3.hp > 0 && !list.Contains(sceneBattle_Tag3.tag))
								{
									list.Add(sceneBattle_Tag3.tag);
								}
							}
						}
					}
					if (sceneBattle_FriendsCommand.dmgkp)
					{
						foreach (SceneBattle_Chara sceneBattle_Chara in list)
						{
							SceneBattle_Enemy sceneBattle_Enemy = (SceneBattle_Enemy)sceneBattle_Chara;
							if (!(sceneBattle_Enemy.chara == null) || sceneBattle_Enemy.nowHp <= sceneBattle_Enemy.escapeHp)
							{
								SceneBattle_Enemy sceneBattle_Enemy2 = ((sceneBattle_Enemy.chara == null) ? sceneBattle_Enemy.body : sceneBattle_Enemy);
								if (!this.IsNoMP(sceneBattle_Enemy2, false))
								{
									sceneBattle_Enemy2.nowKp = Mathf.Clamp(sceneBattle_Enemy2.nowKp + sceneBattle_Enemy.increaseKpByDamage, 0, this.MaxMP(sceneBattle_Enemy2, false));
								}
							}
						}
