				}
			}
			bool flag4 = sceneBattle_FriendsCommand.step >= SceneBattle.CMDSTEP.Retreat;
			bool flag5 = false;
			if (!this._guiData.HugeFadeAE.gameObject.activeSelf)
			{
				if (this._emyWaveList.Find((SceneBattle_Enemy itm) => itm.huge > 1 && itm.nowHp <= itm.escapeHp && itm.chara.IsModelActive()) == null)
				{
					if (sceneBattle_FriendsCommand.step == SceneBattle.CMDSTEP.End)
					{
						flag5 = true;
					}
					else if ((flag4 || sceneBattle_FriendsCommand.reflect.Count <= 0) && this._plyCmdCtr + 1 < this._plyCmdList.Count && this._plyCmdList[this._plyCmdCtr + 1].chain > 0 && sceneBattle_FriendsCommand.actTim >= sceneBattle_FriendsCommand.actParam.motionParam.nextActionTime)
					{
						flag5 = true;
					}
				}
			}
			if (flag5)
			{
				this.CheckGuts();
				this.CheckIce(sceneBattle_FriendsCommand.chara, false);
				this.CheckSleep();
				this.ExecGiveup(sceneBattle_FriendsCommand.givBuf);
				flag4 = true;
				this._subStep = SceneBattle.SUBSTEP.Prepare;
				this._plyCmdCtr++;
				this.UpdateActionCard(sceneBattle_FriendsCommand);
