				else if (this._guiData.BeatActAE.GetAnimeType() == PguiAECtrl.AmimeType.START && !this._guiData.BeatActAE.IsPlaying())
				{
					this._guiData.BeatActAE.PlayAnimation(PguiAECtrl.AmimeType.LOOP, null);
				}
			}
			if (this._guiData.ActionActAE.transform.parent.gameObject.activeSelf)
			{
				if (flag4)
				{
					if (this._guiData.ActionActAE.GetAnimeType() != PguiAECtrl.AmimeType.END)
					{
						this._guiData.ActionActAE.PlayAnimation(PguiAECtrl.AmimeType.END, null);
					}
				}
				else if (this._guiData.ActionActAE.GetAnimeType() == PguiAECtrl.AmimeType.START && !this._guiData.ActionActAE.IsPlaying())
				{
					this._guiData.ActionActAE.PlayAnimation(PguiAECtrl.AmimeType.LOOP, null);
					this._guiData.ActionActAE.transform.parent.Find("Base/AEImage_Plus").GetComponent<PguiAECtrl>().ResumeAnimation();
				}
			}
			if (this._guiData.TryActAE.transform.parent.gameObject.activeSelf)
			{
