						this._guiData.TryActAE.PlayAnimation(PguiAECtrl.AmimeType.END, null);
					}
				}
				else if (this._guiData.TryActAE.GetAnimeType() == PguiAECtrl.AmimeType.START && !this._guiData.TryActAE.IsPlaying())
				{
					this._guiData.TryActAE.PlayAnimation(PguiAECtrl.AmimeType.LOOP, null);
				}
				if (this._guiData.TryActPlasmAE.m_AEImage.playSpeed < 0.5f && this._guiData.TryActAE.m_AEImage.playTime >= this._guiData.TryActMove)
				{
