	private void UpdateActionCard(SceneBattle_FriendsCommand playerCommand)
	{
		if (playerCommand.card != null)
		{
			playerCommand.card.action.transform.SetParent(this._guiData.OrderCard, false);
			playerCommand.card.actArts.transform.SetParent(this._guiData.OrderCard, false);
		}
		if (playerCommand.rmvCmd != null)
		{
			foreach (SceneBattle_FriendsCommand sceneBattle_FriendsCommand in playerCommand.rmvCmd.Keys)
			{
				if (sceneBattle_FriendsCommand.card != null)
				{
					sceneBattle_FriendsCommand.card.action.transform.SetParent(this._guiData.OrderCard, false);
					sceneBattle_FriendsCommand.card.actArts.transform.SetParent(this._guiData.OrderCard, false);
				}
				if (sceneBattle_FriendsCommand.mark >= 0)
				{
					this._actionChainList[sceneBattle_FriendsCommand.mark].SetParent(this._guiData.OrderCard, false);
					sceneBattle_FriendsCommand.mark = -1;
				}
				SceneBattle_FriendsCommand sceneBattle_FriendsCommand2 = playerCommand.rmvCmd[sceneBattle_FriendsCommand];
				if (sceneBattle_FriendsCommand2 != null && sceneBattle_FriendsCommand2.chain <= 0 && sceneBattle_FriendsCommand2.mark >= 0)
				{
					this._actionChainList[sceneBattle_FriendsCommand2.mark].SetParent(this._guiData.OrderCard, false);
					sceneBattle_FriendsCommand2.mark = -1;
				}
			}
		}
		int i = this._plyCmdCtr;
		while (i < this._plyCmdList.Count)
		{
			playerCommand = this._plyCmdList[i];
			if (playerCommand.card != null)
			{
				if (playerCommand.mark >= 0)
				{
					this._actionChainList[playerCommand.mark].SetParent(this._guiData.OrderCard, false);
					playerCommand.mark = -1;
					break;
				}
				break;
			}
			else
			{
				i++;
			}
		}
		this._actionCardTime = 0f;
	}

	private void DispChainCount()
	{
		this._guiData.ChainCountAE.gameObject.SetActive(true);
		this._guiData.ChainCountAE.GetComponent<PguiReplaceAECtrl>().Replace(this._chainCount.ToString("D2"));
		this._guiData.ChainCountAE.PlayAnimation(PguiAECtrl.AmimeType.START, null);
		SoundManager.Play("prd_se_chain_" + this._chainCount.ToString(), false, false);
	}

	private void DispWaitSkill(List<AEImage> lst)
	{
		if ((this._waitDisp -= TimeManager.DeltaTime) <= 0f)
		{
			if (this._waitIconList.Count > 0)
			{
				foreach (AEImage aeimage in lst)
				{
					if (!aeimage.gameObject.activeSelf)
					{
						aeimage.gameObject.SetActive(true);
						aeimage.playTime = 0f;
						aeimage.transform.Find("Icon_Chara").GetComponent<PguiRawImageCtrl>().SetTexture(this._waitIconList[0].Key, true);
						aeimage.GetComponent<Grayscale>().enabled = this._waitIconList[0].Value[0];
						PguiReplaceAECtrl component = aeimage.transform.Find("AEImage_StaySkill_Front").GetComponent<PguiReplaceAECtrl>();
						component.Replace(this._waitIconList[0].Value[1] ? "SraySkill_Silence" : "StaySkill");
						component.GetComponent<PguiAECtrl>().PlayAnimation(PguiAECtrl.AmimeType.START, null);
						PguiAECtrl component2 = aeimage.transform.Find("AEImage_Info_Paralysis").GetComponent<PguiAECtrl>();
						component2.gameObject.SetActive(this._waitIconList[0].Value[0]);
						if (component2.gameObject.activeSelf)
						{
							component2.PlayAnimation(PguiAECtrl.AmimeType.START, null);
							SoundManager.Play("prd_se_electric_shock", false, false);
						}
						this._waitIconList.RemoveAt(0);
						break;
					}
				}
			}
			this._waitDisp = 0.066f;
		}
	}

	private void DispScheduledSkill(List<AEImage> lst)
	{
		if ((this._waitDisp -= TimeManager.DeltaTime) <= 0f)
		{
			if (this._scheduleActionDupList.Count > 0)
			{
				foreach (AEImage aeimage in lst)
				{
					if (!aeimage.gameObject.activeSelf)
					{
						aeimage.gameObject.SetActive(true);
						aeimage.playTime = 0f;
						this._scheduleActionDupList.RemoveAt(0);
						break;
					}
				}
			}
			this._waitDisp = 0.066f;
		}
	}

	private void CheckEnemyCommand()
	{
		this._emyCmdList = new List<SceneBattle_EnemyCommand>();
		this._enemySchedulesList = new List<SceneBattle_Action>();
		this._scheduleActionDupList = new List<SceneBattle_Action>();
		bool flag = false;
		List<SceneBattle_Enemy> list = this._emyWaveList.FindAll((SceneBattle_Enemy itm) => itm.chara != null && itm.normalAttack.Count > 0 && itm.newHp > itm.escapeHp);
		if (list.Find((SceneBattle_Enemy itm) => itm.huge > 1) != null)
		{
			list.RemoveAll((SceneBattle_Enemy itm) => itm.huge == 1);
		}
		foreach (SceneBattle_Enemy sceneBattle_Enemy in this._emyWaveList)
		{
			this.proceedSchedule(sceneBattle_Enemy, false);
		}
		list.FindAll((SceneBattle_Enemy itm) => this.IsStun(itm, false) || this.IsSleep(itm, false)).ForEach(delegate(SceneBattle_Enemy noActionEnemy)
		{
			this.decreaseFocus(noActionEnemy);
		});
		list.RemoveAll((SceneBattle_Enemy itm) => this.IsStun(itm, false) || this.IsSleep(itm, false));
		using (List<SceneBattle_Enemy>.Enumerator enumerator = list.GetEnumerator())
		{
			while (enumerator.MoveNext())
			{
				SceneBattle_Enemy emy = enumerator.Current;
				List<SceneBattle_Enemy> list2 = this._emyWaveList.FindAll((SceneBattle_Enemy itm) => itm.chara == null && itm.body == emy);
				List<EnemyAttackData.Param> list3 = new List<EnemyAttackData.Param>();
				foreach (EnemyAttackData.Param param in emy.normalAttack)
				{
					bool flag2 = true;
					if (param.death.Count > 0)
					{
						foreach (int num in param.death)
						{
							if (num > 0 && num <= list2.Count)
							{
								SceneBattle_Enemy sceneBattle_Enemy2 = list2[num - 1];
								if (sceneBattle_Enemy2.nowHp > sceneBattle_Enemy2.escapeHp)
								{
									flag2 = false;
									break;
								}
							}
						}
					}
					if (param.alive.Count > 0)
					{
						foreach (int num2 in param.alive)
						{
							if (num2 > 0 && num2 <= list2.Count)
							{
								SceneBattle_Enemy sceneBattle_Enemy3 = list2[num2 - 1];
								if (sceneBattle_Enemy3.nowHp <= sceneBattle_Enemy3.escapeHp)
								{
									flag2 = false;
									break;
								}
							}
						}
					}
					if (flag2)
					{
						list3.Add(param);
					}
				}
				int num3 = 0;
				bool flag3 = true;
				for (int i = 0; i < emy.actionNum; i++)
				{
					flag = true;
					foreach (SceneBattle_Friends sceneBattle_Friends in this._playerList)
					{
						if (sceneBattle_Friends.newHp > sceneBattle_Friends.escapeHp)
						{
							flag = false;
						}
					}
					SceneBattle_EnemyCommand sceneBattle_EnemyCommand = new SceneBattle_EnemyCommand();
					sceneBattle_EnemyCommand.chara = emy;
					sceneBattle_EnemyCommand.chain = 0;
					sceneBattle_EnemyCommand.card = null;
					sceneBattle_EnemyCommand.arts = ((emy.maxKp <= 0 || emy.arts == null || emy.nowKp - num3 * emy.maxKp < emy.maxKp || this.IsSeal(emy, false) || this.IsIce(emy, false) || this.IsBurned(emy, false)) ? 0 : 1);
					int num4 = 0;
					if (sceneBattle_EnemyCommand.arts > 0)
					{
						sceneBattle_EnemyCommand.actParam = emy.arts;
						sceneBattle_EnemyCommand.voice = VOICE_TYPE.SKL01;
						if (sceneBattle_EnemyCommand.actParam.authParam.EnhanceFlag)
						{
							num4 = emy.nowKp - emy.maxKp;
						}
					}
					else
					{
						sceneBattle_EnemyCommand.actParam = list3[emy.actCount % list3.Count].param;
						if (emy.actionPattern == CharaDef.EnemyActionPattern.LOTTERY)
						{
							int num5 = 0;
							for (int j = 0; j < list3.Count; j++)
							{
								num5 += list3[j].point;
							}
							num5 = Random.Range(0, num5);
							for (int k = 0; k < list3.Count; k++)
							{
								if ((num5 -= list3[k].point) < 0)
								{
									sceneBattle_EnemyCommand.actParam = list3[k].param;
									break;
								}
							}
						}
						sceneBattle_EnemyCommand.voice = VOICE_TYPE.ATK01;
					}
					sceneBattle_EnemyCommand.paralysis = this.IsParalysis(emy, false) && Random.Range(0, 100) < ((emy.type == CharaDef.Type.BOSS) ? this._battleParam.paralysisBoss : this._battleParam.paralysisEnemy);
					sceneBattle_EnemyCommand.silence = this.IsSilence(emy, false);
					this.SetEnemyTarget();
					if (!sceneBattle_EnemyCommand.paralysis)
					{
						flag3 = false;
						this.SetAct(sceneBattle_EnemyCommand, this._playerSkillDef, 0, 0f, 0, flag, 0, num4);
						if (sceneBattle_EnemyCommand.act.Count > 0)
						{
							if (sceneBattle_EnemyCommand.arts > 0)
							{
								num3++;
								if (!flag && (emy.newKp -= emy.maxKp) < 0)
								{
									emy.newKp = 0;
								}
							}
							if (!flag && !this.IsNoMP(sceneBattle_EnemyCommand.chara, true))
							{
								sceneBattle_EnemyCommand.chara.newKp = Mathf.Clamp(sceneBattle_EnemyCommand.chara.newKp + sceneBattle_EnemyCommand.chara.increaseKpByAttack, 0, this.MaxMP(sceneBattle_EnemyCommand.chara, true));
							}
							sceneBattle_EnemyCommand.step = SceneBattle.CMDSTEP.None;
							sceneBattle_EnemyCommand.camMssl = null;
							this._emyCmdList.Add(sceneBattle_EnemyCommand);
							emy.actCount++;
						}
						if (sceneBattle_EnemyCommand.refFlg > 0)
						{
							break;
						}
					}
				}
				if (flag3)
				{
					this.decreaseFocus(emy);
				}
			}
		}
		foreach (SceneBattle_Enemy sceneBattle_Enemy4 in this._emyWaveList)
		{
			this.proceedSchedule(sceneBattle_Enemy4, true);
		}
	}

	private void EnemyTurn()
	{
		if (this._continueStep == 0)
		{
			if (this._subStep == SceneBattle.SUBSTEP.Init)
			{
				if (this._stepCtr == 0)
				{
					this._stepCtr++;
					this.OffBuff();
					this.ResetStatus();
					this._reqCamera = SceneBattle.CameraType.Battle;
					foreach (SceneBattle_Enemy sceneBattle_Enemy in this._emyWaveList)
					{
