	}

	private void WaveClear()
	{
		if (this._subStep == SceneBattle.SUBSTEP.Init)
		{
			this._subStep = SceneBattle.SUBSTEP.Term;
			this._reqCamera = SceneBattle.CameraType.WaveClear;
			if (this._currentWave < this._numberWave)
			{
				this.PlayVoice(this._playerList[this._lastDamageFriends], CharaVoiceCombi.SitType.WAVE_CLEAR, VOICE_TYPE.WCL01);
				return;
			}
		}
		else if (!this.IsCameraMove())
		{
			this._step = ((this._currentWave < this._numberWave) ? SceneBattle.STEP.WaveStart : SceneBattle.STEP.GameClear);
			this.InitWave(999);
			if (this._tutorialStep != SceneBattle.TutorialStep.NONE)
			{
				this._tutorial = SceneBattle.Tutorial.INIT;
			}
		}
	}

	private void JudgePvpTraining()
	{
		if (SceneBattle.pvpTraining == 0)
		{
			return;
		}
		this._step = ((this._pvpTrainingScorePlayer >= this._pvpTrainingScoreVersus) ? SceneBattle.STEP.GameClear : SceneBattle.STEP.GameLose);
		this._guiData.TacticsEndScoreAE.transform.Find("OwnNum").GetComponent<PguiTextCtrl>().text = this._pvpTrainingScorePlayer.ToString();
		this._guiData.TacticsEndScoreAE.gameObject.SetActive(true);
		this._guiData.TacticsEndScoreAE.playOutTime = this._guiData.TacticsEndScoreAE.duration;
		this._guiData.TacticsEndScoreAE.playTime = (this._guiData.TacticsEndScoreAE.playInTime = 0f);
		this._guiData.TacticsEndScoreAE.playLoop = false;
		this._guiData.TacticsEndScoreAE.autoPlay = true;
		this._guiData.TacticsEndScoreAE.transform.Find("OwnNum").GetComponent<PguiTextCtrl>().text = this._pvpTrainingScorePlayer.ToString();
		this._guiData.TacticsEndScoreAE.transform.Find("EnemyNum").GetComponent<PguiTextCtrl>().text = this._pvpTrainingScoreVersus.ToString();
		SoundManager.Play("prd_se_training_judge", false, false);
	}

