						this._resultArgs.bgm = "prd_bgm0994";
					}
					else if (this._resultArgs.bgm == "prd_bgm0995")
					{
						this._resultArgs.bgm = "prd_bgm0996";
					}
					else if (this._resultArgs.bgm == "prd_bgm0997")
					{
						this._resultArgs.bgm = "prd_bgm0998";
					}
					else
					{
						this._resultArgs.bgm = "prd_bgm0020";
					}
					this._guiData.ResultAE.gameObject.SetActive(true);
					this._guiData.ResultAE.GetComponent<PguiReplaceAECtrl>().Replace("WIN");
					this._guiData.ResultAE.playOutTime = this._guiData.ResultAE.duration;
					this._guiData.ResultAE.playTime = 0f;
				}
				int num2 = this._resultArgs.quest.wavePackDataList.Count - 1;
				string text = "";
				if (num2 > -1)
				{
					text = this._resultArgs.quest.wavePackDataList[num2].victoryBgmName;
				}
				if (SoundManager.IsExsistCueSheetAssetData(text))
				{
					this._resultArgs.bgm = text;
				}
				SoundManager.PlayBGM(this._resultArgs.bgm);
				this._subStep = SceneBattle.SUBSTEP.Confirm;
				this._reqCamera = SceneBattle.CameraType.GameClear;
				this.ResetStatus();
				foreach (SceneBattle_Enemy sceneBattle_Enemy in this._emyWaveList)
				{
					if (sceneBattle_Enemy.chara != null)
					{
						sceneBattle_Enemy.chara.SetModelActive(false);
					}
				}
				this.SetTimer(3f);
				this._resultArgs.battleMissionStatus = new List<bool>();
				foreach (BattleMissionOneStatic battleMissionOneStatic in this._resultArgs.quest.battleMissionPack.staticData.mission)
				{
					if (battleMissionOneStatic.type == BattleMissionType.CLEAR_DEAD_NUM)
					{
						int num3 = 0;
						foreach (SceneBattle_Friends sceneBattle_Friends5 in this._playerList)
						{
							if (sceneBattle_Friends5.nowHp <= sceneBattle_Friends5.escapeHp)
							{
								num3++;
							}
						}
						this._resultArgs.battleMissionStatus.Add(num3 <= battleMissionOneStatic.value0);
					}
					else if (battleMissionOneStatic.type == BattleMissionType.TURN_NUM)
					{
						this._resultArgs.battleMissionStatus.Add(this._turnCount <= battleMissionOneStatic.value0);
					}
					else if (battleMissionOneStatic.type == BattleMissionType.CHAIN_NUM)
					{
						this._resultArgs.battleMissionStatus.Add(this._maxChain >= battleMissionOneStatic.value0);
					}
					else if (battleMissionOneStatic.type == BattleMissionType.CHAIN_BEAT_NUM)
					{
						this._resultArgs.battleMissionStatus.Add(this._maxChainBeat >= battleMissionOneStatic.value0);
					}
					else if (battleMissionOneStatic.type == BattleMissionType.CHAIN_ACTION_NUM)
					{
						this._resultArgs.battleMissionStatus.Add(this._maxChainAction >= battleMissionOneStatic.value0);
					}
					else if (battleMissionOneStatic.type == BattleMissionType.CHAIN_TRY_NUM)
					{
						this._resultArgs.battleMissionStatus.Add(this._maxChainTry >= battleMissionOneStatic.value0);
					}
					else if (battleMissionOneStatic.type == BattleMissionType.CHARA_LIMITED)
					{
						bool flag = false;
						using (List<SceneBattle_Friends>.Enumerator enumerator = this._playerList.GetEnumerator())
						{
							while (enumerator.MoveNext())
							{
								if (enumerator.Current.charaId == battleMissionOneStatic.value0)
								{
									flag = true;
									break;
								}
							}
						}
						this._resultArgs.battleMissionStatus.Add(flag);
					}
					else if (battleMissionOneStatic.type == BattleMissionType.HP_RATIO)
					{
						int num4 = 0;
						int num5 = 0;
						foreach (SceneBattle_Friends sceneBattle_Friends6 in this._playerList)
						{
							if (sceneBattle_Friends6.nowHp > sceneBattle_Friends6.escapeHp)
							{
								num4 += sceneBattle_Friends6.nowHp;
							}
							num5 += sceneBattle_Friends6.maxHp;
						}
						this._resultArgs.battleMissionStatus.Add(num4 * 100 / num5 >= battleMissionOneStatic.value0);
					}
					else if (battleMissionOneStatic.type == BattleMissionType.STATUS_ERROR)
					{
						this._resultArgs.battleMissionStatus.Add(this._statusErrorList.Contains((CharaDef.ActionBuffType)battleMissionOneStatic.value0));
					}
					else if (battleMissionOneStatic.type == BattleMissionType.OKAWARI)
					{
						this._resultArgs.battleMissionStatus.Add(this._okawari >= battleMissionOneStatic.value0);
					}
					else if (battleMissionOneStatic.type == BattleMissionType.ARTS)
					{
						this._resultArgs.battleMissionStatus.Add(this._artsCount >= battleMissionOneStatic.value0);
					}
					else
					{
						this._resultArgs.battleMissionStatus.Add(false);
					}
				}
				this._resultArgs.resultVoiceFirst = "";
				this._resultArgs.resultVoiceFirstSheet = "";
				this._resultArgs.resultVoiceFirstLength = 0f;
				this._resultArgs.resultVoiceSecond = "";
				this._resultArgs.resultVoiceSecondSheet = "";
				this._resultArgs.resultVoiceSecondTime = TimeManager.SystemNow;
				SceneBattle_Friends sceneBattle_Friends7 = this._playerList[this._lastDamageFriends];
				List<CharaVoiceCombi> list = DataManager.DmChara.GetCharaVoiceCombiList(CharaVoiceCombi.SitType.BATTLE_CLEAR, sceneBattle_Friends7.charaId).FindAll((CharaVoiceCombi itm) => this._playerList.Find((SceneBattle_Friends itm2) => itm2.charaId == itm.secondCharaId) != null);
				if (list.Count > 0)
				{
					CharaVoiceCombi charaVoiceCombi = list[Random.Range(0, list.Count)];
					this._resultArgs.resultVoiceFirst = charaVoiceCombi.firstVoiceName;
					SceneBattle_Friends sceneBattle_Friends8 = this._playerList.Find((SceneBattle_Friends itm) => itm.charaId == charaVoiceCombi.secondCharaId);
					if (sceneBattle_Friends8 != null)
					{
						this._resultArgs.resultVoiceSecond = charaVoiceCombi.secondVoiceName;
						if (string.IsNullOrEmpty(this._resultArgs.resultVoiceSecond))
						{
							this._resultArgs.resultVoiceSecond = SoundManager.CreateVoiceNameByType(sceneBattle_Friends8.chara.loadVoiceCueSheetName, VOICE_TYPE.WIN01);
						}
						if (!string.IsNullOrEmpty(this._resultArgs.resultVoiceSecond))
						{
							SoundManager.LoadCueSheet(this._resultArgs.resultVoiceSecondSheet = sceneBattle_Friends8.chara.loadVoiceCueSheetName);
						}
					}
				}
				if (string.IsNullOrEmpty(this._resultArgs.resultVoiceFirst))
				{
					this._resultArgs.resultVoiceFirst = SoundManager.CreateVoiceNameByType(sceneBattle_Friends7.chara.loadVoiceCueSheetName, VOICE_TYPE.WIN01);
				}
				if (!string.IsNullOrEmpty(this._resultArgs.resultVoiceFirst))
				{
					SoundManager.LoadCueSheet(this._resultArgs.resultVoiceFirstSheet = sceneBattle_Friends7.chara.loadVoiceCueSheetName);
					this._resultArgs.resultVoiceFirstLength = SoundManager.GetVoiceLength(this._resultArgs.resultVoiceFirstSheet, this._resultArgs.resultVoiceFirst);
					if (SceneBattle.pvpBattle || SceneBattle.friendWild)
					{
						SoundManager.PlayVoice(this._resultArgs.resultVoiceFirstSheet, this._resultArgs.resultVoiceFirst);
						this._resultArgs.resultVoiceFirst = "";
						this._resultArgs.resultVoiceSecondTime = TimeManager.SystemNow.AddSeconds((double)this._resultArgs.resultVoiceFirstLength);
					}
				}
				if (SceneBattle.pvpBattle && !this._resultArgs.debug)
				{
					this._resultArgs.battleArgs.isSeasonReplacement = DataManager.DmPvp.RequestActionPvPEnd(true, this._turnCount, this._resultArgs.battleArgs.pvpSeasonId, this._resultArgs.battleArgs.hash_id, this._resultArgs.battleArgs.difficulty, this._okawari, this._maxChain, this._chainExec, this._chainSumCount, this._maxDmg, this._kemoStatus, this._artsCount, this._playerSkillTotalCount, this._plyTickleSuccessCount);
					return;
				}
			}
		}
		else if (this._subStep == SceneBattle.SUBSTEP.Confirm)
		{
			if (this._stepCtr == 0)
			{
				if (this.IsTimeOut() && !this.IsPlayingPvpAuth())
				{
					if (this._tutorialStep != SceneBattle.TutorialStep.NONE)
					{
						this._tutorial = SceneBattle.Tutorial.INIT;
					}
					else
					{
						this._stepCtr++;
						this._result = new GameObject("");
						SceneManager.Add3DObjectByBaseField(this._result.transform);
						if (SceneBattle.pvpBattle || SceneBattle.friendWild)
						{
							this._resultFriends = new GameObject("LuckyResult", new Type[] { typeof(CharaModelHandle) }).GetComponent<CharaModelHandle>();
							this._resultFriends.Initialize(1004, true, false, 1, false, false, false, null);
							this._resultFriends.SetModelActive(true);
							this._resultFriends.SetAlpha(1f);
							this._resultFriends.shadowSize = 0.3f;
							this._resultFriends.PlayAnimation(CharaMotionDefine.ActKey.JOY, true, 1f, 0f, 0f, false);
							this._resultFriends.transform.position = new Vector3(this._cameraLokNow.x, -1.5f, this._cameraLokNow.z);
							this._resultFriends.transform.LookAt(this._cameraPosNow);
							this._resultFriends.transform.eulerAngles = new Vector3(0f, this._resultFriends.transform.eulerAngles.y, 0f);
							this._resultFriends.transform.Translate(new Vector3(2f, 0f, 0f));
							this._resultFriends.PlayAnimation(CharaMotionDefine.ActKey.POSITIVE, false, 1f, 0f, 0f, false);
						}
						else
						{
							this._resultFriends = this._playerList[this._lastDamageFriends].chara;
						}
						this._resultFriends.transform.SetParent(this._result.transform, false);
						GameObject gameObject = new GameObject("CamPos");
						gameObject.transform.SetParent(this._resultFriends.transform, false);
						gameObject.transform.localPosition = new Vector3(0f, 0f, 4f);
						GameObject gameObject2 = new GameObject("LokPos");
						gameObject2.transform.SetParent(this._resultFriends.transform, false);
						gameObject2.transform.localPosition = new Vector3(-1.4f, 0f, 0f);
						int num6 = LayerMask.NameToLayer("AuthMain");
						this._resultFriends.SetLayer(num6);
						Light component = Object.Instantiate<GameObject>(this._stage.lightByPlayer.gameObject).GetComponent<Light>();
						component.transform.SetParent(this._result.transform, false);
						component.cullingMask = (1 << num6) | (1 << SceneBattle.playerBloomLayer);
						this._resultCamera = new GameObject("Result Camera", new Type[] { typeof(Camera) }).AddComponent<FieldCameraScaler>();
						this._resultCamera.transform.SetParent(this._result.transform, false);
						this._resultCamera.fieldCamera.clearFlags = CameraClearFlags.Depth;
						this._resultCamera.fieldCamera.backgroundColor = Color.clear;
						this._resultCamera.fieldCamera.depth = (float)((SceneManager.CameraDepth[SceneManager.CanvasType.BACK] + SceneManager.CameraDepth[SceneManager.CanvasType.FRONT]) / 2);
						this._resultCamera.fieldCamera.allowHDR = false;
						this._resultCamera.gameObject.layer = num6;
						this._resultCamera.fieldCamera.cullingMask = (1 << num6) | (1 << SceneBattle.playerBloomLayer);
						this._resultCamera.gameObject.AddComponent<MultipleGaussianBloom>().gaussianFilter = MultipleGaussianBloom.FilterTaps._5Taps;
						this._resultCamera.gameObject.GetComponent<MultipleGaussianBloom>().enabled = this._resultFriends.charaEffect != null;
						this.SetTimer(0.5f);
					}
				}
			}
			else if (this.IsTimeOut())
			{
				this._subStep = SceneBattle.SUBSTEP.Term;
			}
			if (this._result != null)
			{
				float num7 = Mathf.Clamp01((1f - this._timer * 2f) * 1.1f);
				float num8 = num7 - 0.65f;
				if (num8 > 0f)
				{
					this._camera.GetComponent<Blur>().enabled = true;
					this._camera.GetComponent<Blur>().amount = Mathf.Clamp01(num8 * 3f);
				}
				if (SceneBattle.pvpBattle || SceneBattle.friendWild)
				{
					Vector3 position = this._resultFriends.transform.position;
					position.y = Mathf.Lerp(-1.5f, 0.5f, num7);
					this._resultFriends.transform.position = position;
				}
				Vector3 position2 = this._resultFriends.transform.Find("CamPos").position;
				Vector3 position3 = this._resultFriends.transform.Find("LokPos").position;
				Vector3 haraPos = this._resultFriends.GetHaraPos();
				if (this._resultFriends.modelName.IndexOf("_0241_") > 0 || this._resultFriends.modelName.IndexOf("_0322_") > 0)
				{
					haraPos.y = this._resultFriends.transform.position.y + 1.05f;
				}
				position2.y = (position3.y = haraPos.y);
				this._resultCamera.transform.position = Vector3.Lerp(this._cameraPosNow, position2, num7);
				this._resultCamera.transform.LookAt(Vector3.Lerp(this._cameraLokNow, position3, num7));
				this._resultCamera.fieldOfView = Mathf.Lerp(this._cameraFovNow, SceneBattle.cameraFieldOfView, num7);
				this._camera.transform.position = this._resultCamera.transform.position;
				this._camera.transform.rotation = this._resultCamera.transform.rotation;
				this._camera.fieldOfView = this._resultCamera.fieldOfView;
				this._camera.fieldCamera.cullingMask &= ~(1 << SceneBattle.playerBloomLayer) & ~(1 << SceneBattle.enemyBloomLayer);
				if (this._subStep != SceneBattle.SUBSTEP.Confirm)
				{
					this._camera.rect = new Rect(-1f, -1f, -1f, -1f);
					this._camera.GetComponent<MultipleGaussianBloom>().enabled = false;
					SceneBattle.resultRT = new RenderTexture(1654, 764, 24, RenderTextureFormat.ARGB32);
					SceneBattle.resultRT.wrapMode = TextureWrapMode.Clamp;
					SceneBattle.resultRT.useMipMap = false;
					SceneBattle.resultRT.autoGenerateMips = false;
					SceneBattle.resultRT.filterMode = FilterMode.Bilinear;
					SceneBattle.resultRT.hideFlags = HideFlags.HideAndDontSave;
					SceneBattle.resultRT.antiAliasing = 2;
					SceneBattle.resultRT.Create();
					this._camera.fieldCamera.targetTexture = SceneBattle.resultRT;
					CanvasManager.SetBgTex(SceneBattle.resultRT);
					return;
				}
			}
		}
		else
		{
			this._requestNextScene = SceneManager.SceneName.SceneBattleResult;
		}
	}

	private void GameLose()
	{
		if (SceneBattle.trainingBattle)
		{
			this.GameClear(DataManagerQuest.BattleEndStatus.DEAD);
			return;
		}
		if (this._subStep == SceneBattle.SUBSTEP.Init)
		{
			if (this._stepCtr == 0)
			{
				this._stepCtr++;
				this._resultArgs.battleEndStatus = DataManagerQuest.BattleEndStatus.DEAD;
				this.SaveRestart();
				this._guiData.ChainCountAE.gameObject.SetActive(false);
				this._guiData.BeatActAE.transform.parent.gameObject.SetActive(false);
				this._guiData.ActionActAE.transform.parent.gameObject.SetActive(false);
				this._guiData.TryActAE.transform.parent.gameObject.SetActive(false);
				this._guiData.SpecialActAE.transform.parent.gameObject.SetActive(false);
				this._guiData.TryActPlasmAE.gameObject.SetActive(false);
				this._guiData.PvpChainCountAE.gameObject.SetActive(false);
				this._guiData.PvpBeatActAE.transform.parent.gameObject.SetActive(false);
				this._guiData.PvpActionActAE.transform.parent.gameObject.SetActive(false);
				this._guiData.PvpSpecialActAE.transform.parent.gameObject.SetActive(false);
				this._guiData.PvpTryActAE.transform.parent.gameObject.SetActive(false);
				this._guiData.RareInAE.gameObject.SetActive(false);
				this._guiData.BossInAE.gameObject.SetActive(false);
				this._guiData.BattleStartAE.gameObject.SetActive(false);
				this._guiData.ChainFrontAE.gameObject.SetActive(false);
				this._guiData.ChainBackAE.transform.parent.gameObject.SetActive(false);
				this._guiData.TickleStartAE.gameObject.SetActive(false);
				this._guiData.TickleResultAE.gameObject.SetActive(false);
				foreach (FieldCameraScaler fieldCameraScaler in this._charaCameraList)
				{
					fieldCameraScaler.gameObject.SetActive(false);
				}
				foreach (SceneBattle_FriendsCommand sceneBattle_FriendsCommand in this._plyCmdList)
				{
					if (sceneBattle_FriendsCommand.card != null && sceneBattle_FriendsCommand.card.cid >= 0)
					{
						this._disCardList.Add(sceneBattle_FriendsCommand.card);
					}
					if (sceneBattle_FriendsCommand.rmvCmd != null)
					{
						foreach (SceneBattle_FriendsCommand sceneBattle_FriendsCommand2 in sceneBattle_FriendsCommand.rmvCmd.Keys)
						{
							if (sceneBattle_FriendsCommand2.card != null && sceneBattle_FriendsCommand2.card.cid >= 0)
							{
								this._disCardList.Add(sceneBattle_FriendsCommand2.card);
							}
						}
					}
					if (sceneBattle_FriendsCommand.effTickle != null)
					{
						EffectManager.DestroyEffect(sceneBattle_FriendsCommand.effTickle);
						sceneBattle_FriendsCommand.effTickle = null;
						sceneBattle_FriendsCommand.seTickle.Stop();
					}
				}
				this._plyCmdList = new List<SceneBattle_FriendsCommand>();
				foreach (SceneBattle_FriendsCommand sceneBattle_FriendsCommand3 in this._plyRmvList)
				{
					if (sceneBattle_FriendsCommand3.card != null && sceneBattle_FriendsCommand3.card.cid >= 0)
					{
						this._disCardList.Add(sceneBattle_FriendsCommand3.card);
					}
				}
				this._plyRmvList = new List<SceneBattle_FriendsCommand>();
				foreach (SceneBattle_Friends sceneBattle_Friends in this._playerList)
				{
					if (sceneBattle_Friends.card != null && sceneBattle_Friends.card.cid >= 0)
					{
						this._disCardList.Add(sceneBattle_Friends.card);
					}
					sceneBattle_Friends.card = null;
				}
				foreach (SceneBattle_FriendsCommand sceneBattle_FriendsCommand4 in this._vssCmdList)
				{
					if (sceneBattle_FriendsCommand4.effTickle != null)
					{
						EffectManager.DestroyEffect(sceneBattle_FriendsCommand4.effTickle);
						sceneBattle_FriendsCommand4.effTickle = null;
						sceneBattle_FriendsCommand4.seTickle.Stop();
					}
				}
				this._vssCmdList = new List<SceneBattle_FriendsCommand>();
				this._vssRmvList = new List<SceneBattle_FriendsCommand>();
				this._combiVoiceList = new List<SceneBattle_CombiVoice>();
				foreach (SceneBattle_Friends sceneBattle_Friends2 in this._playerList)
				{
					SoundManager.Stop(sceneBattle_Friends2.chara.loadVoiceCueSheetName);
				}
				foreach (SceneBattle_Friends sceneBattle_Friends3 in this._versusList)
				{
					SoundManager.Stop(sceneBattle_Friends3.chara.loadVoiceCueSheetName);
				}
				TimeManager.TimeScale = 1f;
			}
			if (!this._guiData.TacticsEndScoreAE.gameObject.activeSelf || this._guiData.TacticsEndScoreAE.end)
			{
				if (SceneBattle.pvpBattle || SceneBattle.friendWild)
				{
					this.SetupPvpResultAuth(false);
					if (SceneBattle.pvpBattle)
					{
						this._subStep = SceneBattle.SUBSTEP.Confirm;
						if (!this._resultArgs.debug)
						{
							DataManager.DmPvp.RequestActionPvPEnd(false, this._turnCount, this._resultArgs.battleArgs.pvpSeasonId, this._resultArgs.battleArgs.hash_id, this._resultArgs.battleArgs.difficulty, this._okawari, this._maxChain, this._chainExec, this._chainSumCount, this._maxDmg, this._kemoStatus, this._artsCount, 0, this._plyTickleSuccessCount);
						}
					}
					else
					{
						this._subStep = SceneBattle.SUBSTEP.Term;
					}
					this.SetTimer(2f);
					SoundManager.StopBGM(2000);
				}
				else
				{
					this._camera.fieldCamera.cullingMask |= (1 << SceneBattle.playerLayer) | (1 << SceneBattle.playerShadowLayer) | (1 << SceneBattle.playerBloomLayer);
					foreach (SceneBattle_Friends sceneBattle_Friends4 in this._playerList)
					{
						if (sceneBattle_Friends4.nowHp > sceneBattle_Friends4.escapeHp)
						{
							sceneBattle_Friends4.chara.PlayAnimation(CharaMotionDefine.ActKey.SORROW, false, 1f, 0.3f, 0.15f, false);
						}
						sceneBattle_Friends4.chara.SetAlpha(1f);
					}
					this._subStep = SceneBattle.SUBSTEP.Term;
					this.SetTimer(0.25f);
					SoundManager.Play("prd_se_quest_fail", false, false);
					SoundManager.StopBGM(250);
					this._popupDataList = new List<SceneBattle_PopUpData>();
					this._popupTime = 0f;
					foreach (DataManagerQuest.WaveTextInfoData waveTextInfoData in this._waveTextInfoList)
					{
						if (waveTextInfoData.InfoDispType == DataManagerQuest.WaveTextInfoData.DispType.LOSE)
						{
							this._popupDataList.Add(new SceneBattle_PopUpData
							{
								typ = waveTextInfoData.InfoDispType,
								msg = waveTextInfoData.InfoText,
								tim = waveTextInfoData.DispTime
							});
						}
					}
				}
				this._reqCamera = SceneBattle.CameraType.GameLose;
				return;
			}
		}
		else if (this._subStep == SceneBattle.SUBSTEP.Confirm)
		{
			if (!DataManager.IsServerRequesting())
			{
				this.SetPvpCoin();
				this._subStep = SceneBattle.SUBSTEP.Term;
				PlayerPrefs.DeleteKey(SceneBattle.battleRestartKey);
				return;
			}
		}
		else if (this.IsTimeOut() && !this._continuePanel.activeSelf && !this._backDeckAll.activeSelf)
		{
			if (this._popupDataList.Find((SceneBattle_PopUpData itm) => itm.typ == DataManagerQuest.WaveTextInfoData.DispType.LOSE) == null && this._popupType != DataManagerQuest.WaveTextInfoData.DispType.LOSE)
			{
				this._requestNextScene = SceneManager.SceneName.SceneQuest;
			}
		}
	}

	private void Retire()
	{
		if (SceneBattle.trainingBattle)
		{
			this.GameClear(DataManagerQuest.BattleEndStatus.RETIRE);
			return;
		}
		if (this._subStep == SceneBattle.SUBSTEP.Init)
		{
			this._resultArgs.battleEndStatus = DataManagerQuest.BattleEndStatus.RETIRE;
			this.SaveRestart();
			this._guiData.ChainCountAE.gameObject.SetActive(false);
			this._guiData.BeatActAE.transform.parent.gameObject.SetActive(false);
			this._guiData.ActionActAE.transform.parent.gameObject.SetActive(false);
			this._guiData.TryActAE.transform.parent.gameObject.SetActive(false);
			this._guiData.TryActPlasmAE.gameObject.SetActive(false);
			this._guiData.PvpChainCountAE.gameObject.SetActive(false);
			this._guiData.PvpBeatActAE.transform.parent.gameObject.SetActive(false);
			this._guiData.PvpActionActAE.transform.parent.gameObject.SetActive(false);
			this._guiData.PvpSpecialActAE.transform.parent.gameObject.SetActive(false);
			this._guiData.PvpTryActAE.transform.parent.gameObject.SetActive(false);
			this._guiData.RareInAE.gameObject.SetActive(false);
			this._guiData.BossInAE.gameObject.SetActive(false);
			this._guiData.BattleStartAE.gameObject.SetActive(false);
			this._guiData.ChainFrontAE.gameObject.SetActive(false);
			this._guiData.ChainBackAE.transform.parent.gameObject.SetActive(false);
			this._guiData.TickleStartAE.gameObject.SetActive(false);
			this._guiData.TickleResultAE.gameObject.SetActive(false);
			foreach (FieldCameraScaler fieldCameraScaler in this._charaCameraList)
			{
				fieldCameraScaler.gameObject.SetActive(false);
			}
			foreach (SceneBattle_FriendsCommand sceneBattle_FriendsCommand in this._plyCmdList)
			{
				if (sceneBattle_FriendsCommand.card != null && sceneBattle_FriendsCommand.card.cid >= 0)
				{
					this._disCardList.Add(sceneBattle_FriendsCommand.card);
				}
				if (sceneBattle_FriendsCommand.rmvCmd != null)
				{
					foreach (SceneBattle_FriendsCommand sceneBattle_FriendsCommand2 in sceneBattle_FriendsCommand.rmvCmd.Keys)
					{
						if (sceneBattle_FriendsCommand2.card != null && sceneBattle_FriendsCommand2.card.cid >= 0)
						{
							this._disCardList.Add(sceneBattle_FriendsCommand2.card);
						}
					}
				}
				if (sceneBattle_FriendsCommand.effTickle != null)
				{
					EffectManager.DestroyEffect(sceneBattle_FriendsCommand.effTickle);
					sceneBattle_FriendsCommand.effTickle = null;
					sceneBattle_FriendsCommand.seTickle.Stop();
				}
			}
			this._plyCmdList = new List<SceneBattle_FriendsCommand>();
			foreach (SceneBattle_FriendsCommand sceneBattle_FriendsCommand3 in this._plyRmvList)
			{
				if (sceneBattle_FriendsCommand3.card != null && sceneBattle_FriendsCommand3.card.cid >= 0)
				{
					this._disCardList.Add(sceneBattle_FriendsCommand3.card);
				}
			}
			this._plyRmvList = new List<SceneBattle_FriendsCommand>();
			foreach (SceneBattle_Friends sceneBattle_Friends in this._playerList)
			{
				if (sceneBattle_Friends.card != null && sceneBattle_Friends.card.cid >= 0)
				{
					this._disCardList.Add(sceneBattle_Friends.card);
				}
				sceneBattle_Friends.card = null;
			}
			foreach (SceneBattle_FriendsCommand sceneBattle_FriendsCommand4 in this._vssCmdList)
			{
				if (sceneBattle_FriendsCommand4.effTickle != null)
				{
					EffectManager.DestroyEffect(sceneBattle_FriendsCommand4.effTickle);
					sceneBattle_FriendsCommand4.effTickle = null;
					sceneBattle_FriendsCommand4.seTickle.Stop();
				}
			}
			this._vssCmdList = new List<SceneBattle_FriendsCommand>();
			this._vssRmvList = new List<SceneBattle_FriendsCommand>();
			this._combiVoiceList = new List<SceneBattle_CombiVoice>();
			foreach (SceneBattle_Friends sceneBattle_Friends2 in this._playerList)
			{
				SoundManager.Stop(sceneBattle_Friends2.chara.loadVoiceCueSheetName);
			}
			foreach (SceneBattle_Friends sceneBattle_Friends3 in this._versusList)
			{
				SoundManager.Stop(sceneBattle_Friends3.chara.loadVoiceCueSheetName);
			}
			if (SceneBattle.pvpBattle || SceneBattle.friendWild)
			{
				this.SetupPvpResultAuth(false);
				if (SceneBattle.pvpBattle)
				{
					this._subStep = SceneBattle.SUBSTEP.Confirm;
					if (!this._resultArgs.debug)
					{
						DataManager.DmPvp.RequestActionPvPEnd(false, this._turnCount, this._resultArgs.battleArgs.pvpSeasonId, this._resultArgs.battleArgs.hash_id, this._resultArgs.battleArgs.difficulty, this._okawari, this._maxChain, this._chainExec, this._chainSumCount, this._maxDmg, this._kemoStatus, this._artsCount, 0, 0);
					}
				}
				else
				{
					this._subStep = SceneBattle.SUBSTEP.Term;
				}
				this.SetTimer(2f);
				TimeManager.TimeScale = 1f;
				SoundManager.StopBGM(2000);
			}
			else
			{
				this._camera.fieldCamera.cullingMask |= (1 << SceneBattle.playerLayer) | (1 << SceneBattle.playerShadowLayer) | (1 << SceneBattle.playerBloomLayer);
				foreach (SceneBattle_Friends sceneBattle_Friends4 in this._playerList)
				{
					if (sceneBattle_Friends4.nowHp > sceneBattle_Friends4.escapeHp)
					{
						sceneBattle_Friends4.pos.z = SceneBattle.playerBasePos;
						sceneBattle_Friends4.offZ = 0f;
						sceneBattle_Friends4.chara.transform.localPosition = (sceneBattle_Friends4.hpPos = sceneBattle_Friends4.pos);
						sceneBattle_Friends4.chara.transform.localEulerAngles = Vector3.zero;
						sceneBattle_Friends4.chara.PlayAnimation(CharaMotionDefine.ActKey.SORROW, false, 1f, 0.3f, 0.15f, false);
					}
					sceneBattle_Friends4.chara.SetAlpha(1f);
				}
				foreach (SceneBattle_Enemy sceneBattle_Enemy in this._emyWaveList)
				{
					if (sceneBattle_Enemy.nowHp > sceneBattle_Enemy.escapeHp)
					{
						sceneBattle_Enemy.hpPos = sceneBattle_Enemy.pos;
						SceneBattle_Enemy sceneBattle_Enemy2 = sceneBattle_Enemy;
						sceneBattle_Enemy2.hpPos.x = sceneBattle_Enemy2.hpPos.x + sceneBattle_Enemy.hugeX;
						if (sceneBattle_Enemy.chara != null)
						{
							sceneBattle_Enemy.chara.transform.localPosition = sceneBattle_Enemy.pos - new Vector3(0f, 0f, sceneBattle_Enemy.offZ);
							sceneBattle_Enemy.chara.transform.localEulerAngles = new Vector3(0f, 180f, 0f);
							sceneBattle_Enemy.chara.PlayAnimation(CharaMotionDefine.ActKey.IDLING, true, 1f, 0.3f, 0.15f, false);
						}
					}
				}
				this._subStep = SceneBattle.SUBSTEP.Term;
				this.SetTimer(0.25f);
				SoundManager.Play("prd_se_quest_fail", false, false);
				SoundManager.StopBGM(250);
				this._popupDataList = new List<SceneBattle_PopUpData>();
				this._popupTime = 0f;
			}
			this._reqCamera = SceneBattle.CameraType.GameLose;
			return;
		}
		if (this._subStep == SceneBattle.SUBSTEP.Confirm)
		{
			if (!DataManager.IsServerRequesting())
			{
				this.SetPvpCoin();
				this._subStep = SceneBattle.SUBSTEP.Term;
				PlayerPrefs.DeleteKey(SceneBattle.battleRestartKey);
				return;
			}
		}
		else if (this.IsTimeOut() && !this._menuPanel.activeSelf && !this._backDeckAll.activeSelf)
		{
			this._requestNextScene = SceneManager.SceneName.SceneQuest;
		}
	}

	private void SetPvpCoin()
	{
		DataManagerPvp.PvPEndResult lastPvPEndResult = DataManager.DmPvp.GetLastPvPEndResult();
		Transform transform = this._guiData.PvpCoinGet.transform.Find("Num");
		transform.GetComponent<PguiTextCtrl>().text = "×" + lastPvPEndResult.getPvpCoin.ToString();
		transform.GetComponent<PguiGradientCtrl>().SetGameObjectById(((this._resultArgs.battleArgs.pvpTraining > 0) ? (lastPvPEndResult.bonusAddCoin > 0) : (lastPvPEndResult.campaignAddCoin > 0)) ? "CAMPAIGN" : "NORMAL");
		PvpPackData pvpPackData = DataManager.DmPvp.GetPvpPackDataBySeasonID(this._resultArgs.battleArgs.pvpSeasonId);
		if (pvpPackData == null)
		{
			pvpPackData = PvpPackData.MakeDummy(1);
		}
		ItemStaticBase itemStaticBase = DataManager.DmItem.GetItemStaticBase(pvpPackData.staticData.rewardItemId);
		GameObject gameObject = transform.Find("Icon_PvP").gameObject;
		gameObject.SetActive(itemStaticBase != null);
		if (itemStaticBase != null)
		{
			gameObject.GetComponent<PguiRawImageCtrl>().SetRawImage(itemStaticBase.GetIconName(), true, false, null);
		}
		this._guiData.PvpCoinGet.transform.Find("PvPMode_x3").gameObject.SetActive(this._resultArgs.battleArgs.pvp3x);
		this._guiData.PvpCoinGet.gameObject.SetActive(true);
		this._guiData.PvpCoinGet.ExPlayAnimation(SimpleAnimation.ExPguiStatus.START, null);
	}

	private void SetupPvpResultAuth(bool win)
	{
		this.PlayPvpAuth(win ? 1 : 2);
		this._camera.fieldCamera.cullingMask |= (1 << SceneBattle.enemyLayer) | (1 << SceneBattle.enemyShadowLayer) | (1 << SceneBattle.enemyBloomLayer);
		this._camera.fieldCamera.cullingMask |= (1 << SceneBattle.playerLayer) | (1 << SceneBattle.playerShadowLayer) | (1 << SceneBattle.playerBloomLayer);
		this._stage.StageAuthHideManager.gameObject.SetActive(false);
		Transform transform = this._stage.stageModelObj.transform.Find("AuthHideGroup");
		if (transform != null)
		{
			transform.gameObject.SetActive(false);
		}
		SoundManager.Play(win ? "prd_se_pvp_victory" : "prd_se_pvp_defeat", false, false);
		this._pvpAuthChr = new Dictionary<int, CharaModelHandle>();
		int i = -1;
		List<int> list = new List<int>();
		foreach (SceneBattle_Friends sceneBattle_Friends in this._playerList)
		{
			if (!SceneBattle.friendWild || sceneBattle_Friends.number - 1 != this._resultArgs.deck.deckHelperIndex)
			{
				this._pvpAuthChr.Add(i += 2, sceneBattle_Friends.chara);
				list.Add(sceneBattle_Friends.charaId);
			}
		}
		if (SceneBattle.friendWild)
		{
			SceneBattle_Friends sceneBattle_Friends2 = this._playerList.Find((SceneBattle_Friends itm) => itm.number - 1 == this._resultArgs.deck.deckHelperIndex);
			if (sceneBattle_Friends2 != null)
			{
				if (DataManager.DmChara.CheckSameChara(sceneBattle_Friends2.charaId, list))
				{
					sceneBattle_Friends2.chara.SetAlpha(0f);
				}
				else
				{
					this._pvpAuthChr.Add(i += 2, sceneBattle_Friends2.chara);
					list.Add(sceneBattle_Friends2.charaId);
				}
			}
		}
		i = 0;
		foreach (SceneBattle_Friends sceneBattle_Friends3 in this._versusList)
		{
			if (DataManager.DmChara.CheckSameChara(sceneBattle_Friends3.charaId, list))
			{
				sceneBattle_Friends3.chara.SetAlpha(0f);
			}
			else
			{
				this._pvpAuthChr.Add(i += 2, sceneBattle_Friends3.chara);
			}
		}
		foreach (int num in this._pvpAuthChr.Keys)
		{
			CharaMotionDefine.ActKey actKey = CharaMotionDefine.ActKey.PVP_RESULT_STAND;
			if (num == 6 || num == 7)
			{
				actKey = CharaMotionDefine.ActKey.PVP_RESULT_LIE;
			}
			else if (num == 8)
			{
				actKey = CharaMotionDefine.ActKey.PVP_RESULT_SIT;
			}
			else if (num > 8)
			{
				actKey = CharaMotionDefine.ActKey.PVP_RESULT_RUN;
			}
			this._pvpAuthChr[num].PlayAnimation(actKey, true, 1f, 0f, 0f, false);
			this._pvpAuthChr[num].SetAlpha(1f);
		}
		i = 1;
		while (i <= 10 && this._pvpAuthLcy.Count < 4)
		{
			if (!this._pvpAuthChr.ContainsKey(i))
			{
				CharaModelHandle component = new GameObject("Lucky" + i.ToString(), new Type[] { typeof(CharaModelHandle) }).GetComponent<CharaModelHandle>();
				component.transform.SetParent(this._field.transform, false);
				component.Initialize(1004, true, false, 0, false, false, false, null);
				component.SetLayer(SceneBattle.playerLayer);
				component.SetModelActive(true);
				component.SetAlpha(1f);
				component.shadowSize = 0.3f;
				CharaMotionDefine.ActKey actKey2 = CharaMotionDefine.ActKey.POSITIVE;
				if (i == 3 || i == 7)
				{
					actKey2 = CharaMotionDefine.ActKey.DENIAL;
				}
				else if (i == 4 || i == 8)
				{
					actKey2 = CharaMotionDefine.ActKey.JOY;
				}
				else if (i == 5 || i == 9)
				{
					actKey2 = CharaMotionDefine.ActKey.SURPRISE;
				}
				component.PlayAnimation(actKey2, true, 1f, 0f, 0f, false);
				this._pvpAuthLcy.Add(i, component);
			}
			i++;
		}
		this._guiData.ResultAE.gameObject.SetActive(true);
		this._guiData.ResultAE.GetComponent<PguiReplaceAECtrl>().Replace("LOSE");
		this._guiData.ResultAE.playOutTime = this._guiData.ResultAE.duration;
		this._guiData.ResultAE.playTime = 0f;
		this._effectPvpList[0].effectObject.SetActive(true);
		for (i = 1; i < this._effectPvpList.Count; i++)
		{
			CharaModelHandle charaModelHandle = null;
			Transform transform2 = null;
			if (this._pvpAuthChr.TryGetValue(i, out charaModelHandle))
			{
				transform2 = charaModelHandle.GetNodeTransform("j_wrist_r");
			}
			if (transform2 != null)
			{
				this._effectPvpList[i].effectObject.SetActive(true);
				this._effectPvpList[i].effectObject.transform.SetParent(transform2, false);
				this._effectPvpList[i].effectObject.transform.localPosition = new Vector3(-0.085f, 0.01f, 0.04f);
				this._effectPvpList[i].effectObject.transform.localEulerAngles = new Vector3(75f, 0f, 0f);
			}
		}
	}

	private void SetupTrainingResultAuth()
	{
		this.PlayPvpAuth(1);
		this._camera.fieldCamera.cullingMask &= ~(1 << SceneBattle.enemyLayer) & ~(1 << SceneBattle.enemyShadowLayer) & ~(1 << SceneBattle.enemyBloomLayer);
		this._camera.fieldCamera.cullingMask |= (1 << SceneBattle.playerLayer) | (1 << SceneBattle.playerShadowLayer) | (1 << SceneBattle.playerBloomLayer);
		foreach (SceneBattle_Friends sceneBattle_Friends in this._playerList)
		{
			sceneBattle_Friends.chara.PlayAnimation(CharaMotionDefine.ActKey.WIN_ST, false, 1f, 0.3f, 0.15f, false);
			sceneBattle_Friends.chara.DispAccessory(3, true, sceneBattle_Friends == this._playerList[this._lastDamageFriends]);
		}
		foreach (CharaModelHandle charaModelHandle in this._pvpAuthLcy.Values)
		{
			charaModelHandle.SetModelActive(true);
		}
		this._pvpAuthLcy[6].PlayAnimation(CharaMotionDefine.ActKey.BIRD_OUT, true, 1f, 0f, 0f, false);
		this._pvpAuthLcy[7].PlayAnimation(CharaMotionDefine.ActKey.BIRD_OUT, true, 1f, 0f, 0f, false);
		this._guiData.ResultAE.gameObject.SetActive(true);
		this._guiData.ResultAE.GetComponent<PguiReplaceAECtrl>().Replace("TRAINING");
		this._guiData.ResultAE.playOutTime = this._guiData.ResultAE.duration;
		this._guiData.ResultAE.playTime = 0f;
		this.SetTrainingVoice(1, 0.3f);
		SoundManager.Play("prd_se_result_victory", false, false);
	}

	private void UpdateEffect()
	{
		foreach (SceneBattle_Friends sceneBattle_Friends in this._playerList)
		{
			this.UpdateEffectOne(sceneBattle_Friends);
		}
		foreach (SceneBattle_Enemy sceneBattle_Enemy in this._emyWaveList)
		{
			if (sceneBattle_Enemy.chara == null)
			{
				this.UpdateEffectParts(sceneBattle_Enemy);
			}
			else
			{
				this.UpdateEffectOne(sceneBattle_Enemy);
			}
		}
		foreach (SceneBattle_Friends sceneBattle_Friends2 in this._versusList)
		{
			this.UpdateEffectOne(sceneBattle_Friends2);
		}
		foreach (SceneBattle_Friends sceneBattle_Friends3 in this._playerList)
		{
			this.UpdateEffectLayer(sceneBattle_Friends3);
		}
		foreach (SceneBattle_Friends sceneBattle_Friends4 in this._versusList)
		{
			this.UpdateEffectLayer(sceneBattle_Friends4);
		}
		List<EffectData> list = new List<EffectData>();
		foreach (EffectData effectData in this._effectDataList)
		{
			if (effectData.IsFinishByAnimation())
			{
				list.Add(effectData);
			}
		}
		foreach (EffectData effectData2 in list)
		{
			this._effectDataList.Remove(effectData2);
			EffectManager.DestroyEffect(effectData2);
		}
		List<SceneBattle_Missile> list2 = new List<SceneBattle_Missile>();
		foreach (SceneBattle_Missile sceneBattle_Missile in this._missileList)
		{
			if ((sceneBattle_Missile.tim += TimeManager.DeltaTime) >= sceneBattle_Missile.len)
			{
				list2.Add(sceneBattle_Missile);
			}
			float num = ((sceneBattle_Missile.len > 0f) ? Mathf.Clamp01(sceneBattle_Missile.tim / sceneBattle_Missile.len) : 1f);
			sceneBattle_Missile.eff.effectObject.transform.localPosition = Vector3.Lerp(sceneBattle_Missile.pos, sceneBattle_Missile.tag, num);
		}
		foreach (SceneBattle_Missile sceneBattle_Missile2 in list2)
		{
			sceneBattle_Missile2.chr = null;
			this._missileList.Remove(sceneBattle_Missile2);
			EffectManager.DestroyEffect(sceneBattle_Missile2.eff);
			sceneBattle_Missile2.eff = null;
		}
		List<SceneBattle_CombiVoice> list3 = new List<SceneBattle_CombiVoice>();
		foreach (SceneBattle_CombiVoice sceneBattle_CombiVoice in this._combiVoiceList)
		{
			if ((sceneBattle_CombiVoice.delay -= TimeManager.DeltaTime) <= 0f)
			{
				SoundManager.PlayVoice(sceneBattle_CombiVoice.sheet, sceneBattle_CombiVoice.voice);
				list3.Add(sceneBattle_CombiVoice);
			}
		}
		foreach (SceneBattle_CombiVoice sceneBattle_CombiVoice2 in list3)
		{
			this._combiVoiceList.Remove(sceneBattle_CombiVoice2);
		}
		bool flag = this._emyWaveList.Find((SceneBattle_Enemy itm) => itm.huge == 1 && itm.nowHp > itm.escapeHp) != null;
		SceneBattle_Enemy sceneBattle_Enemy2;
		if (!flag)
		{
			sceneBattle_Enemy2 = null;
		}
		else
		{
			sceneBattle_Enemy2 = this._emyWaveList.Find((SceneBattle_Enemy itm) => itm.huge == 2 && itm.nowHp < itm.escapeHp);
		}
		SceneBattle_Enemy sceneBattle_Enemy3 = sceneBattle_Enemy2;
		if (this._hugeEffR == null)
		{
			if (sceneBattle_Enemy3 != null)
			{
				this._hugeEffR = EffectManager.InstantiateEffect("Ef_info_cerulean_sandstar", this._effect, SceneBattle.effectLayer, 1f);
				this._hugeEffR.PlayEffect(false);
			}
		}
		else if (sceneBattle_Enemy3 == null)
		{
			EffectManager.DestroyEffect(this._hugeEffR);
			this._hugeEffR = null;
		}
		SceneBattle_Enemy sceneBattle_Enemy4;
		if (!flag)
		{
			sceneBattle_Enemy4 = null;
		}
		else
		{
			sceneBattle_Enemy4 = this._emyWaveList.Find((SceneBattle_Enemy itm) => itm.huge == 3 && itm.nowHp < itm.escapeHp);
		}
		SceneBattle_Enemy sceneBattle_Enemy5 = sceneBattle_Enemy4;
		if (this._hugeEffL == null)
		{
			if (sceneBattle_Enemy5 != null)
			{
				this._hugeEffL = EffectManager.InstantiateEffect("Ef_info_cerulean_sandstar", this._effect, SceneBattle.effectLayer, 1f);
				this._hugeEffL.PlayEffect(false);
			}
		}
		else if (sceneBattle_Enemy5 == null)
		{
			EffectManager.DestroyEffect(this._hugeEffL);
			this._hugeEffL = null;
		}
		if (flag && !this._guiData.HugeFadeAE.gameObject.activeSelf && this._guiData.HugeFadeAE.m_AEImage.playTime < 0.1f)
		{
			if (sceneBattle_Enemy3 != null && sceneBattle_Enemy3.chara.IsModelActive() && (!sceneBattle_Enemy3.chara.IsCurrentAnimation(CharaMotionDefine.ActKey.IDLING) || !sceneBattle_Enemy3.chara.IsLoopAnimation()))
			{
				sceneBattle_Enemy3 = null;
			}
			if (sceneBattle_Enemy5 != null && sceneBattle_Enemy5.chara.IsModelActive() && (!sceneBattle_Enemy5.chara.IsCurrentAnimation(CharaMotionDefine.ActKey.IDLING) || !sceneBattle_Enemy5.chara.IsLoopAnimation()))
			{
				sceneBattle_Enemy5 = null;
			}
			if (sceneBattle_Enemy3 != null && sceneBattle_Enemy5 != null)
			{
				this._guiData.HugeFadeAE.gameObject.SetActive(true);
				this._guiData.HugeFadeAE.ResumeAnimation();
			}
		}
	}

	private void UpdateEffectLayer(SceneBattle_Friends friends)
	{
		List<EffectData> list = this._effectDataList.FindAll((EffectData data) => data.Publisher == friends.chara.gameObject.name);
		if (list == null || list.Count == 0)
		{
			return;
		}
		int partsBodyLayer = friends.chara.GetPartsBodyLayer();
		foreach (EffectData effectData in list)
		{
			if (!(effectData.effectObject == null))
			{
				if (partsBodyLayer == SceneBattle.ignoreLayer && effectData.effectObject.layer != SceneBattle.ignoreLayer)
				{
					effectData.effectObject.SetLayerRecursively(SceneBattle.ignoreLayer);
				}
				else if (partsBodyLayer != SceneBattle.ignoreLayer && effectData.effectObject.layer != effectData.NormalLayer)
				{
					effectData.effectObject.SetLayerRecursively(effectData.NormalLayer);
				}
			}
		}
		if (!friends.chara.IsCurrentAnimation(CharaMotionDefine.ActKey.STAND_BY_LP) && friends.effWait != null)
		{
			this._effectDataList.Remove(friends.effWait);
			friends.chara.DestroyEffect(friends.effWait);
			friends.effWait = null;
			friends.effWaitTime = 0f;
		}
	}

	private void UpdateEffectOne(SceneBattle_Chara chr)
	{
		SceneBattle_Friends sceneBattle_Friends = chr as SceneBattle_Friends;
		SceneBattle_Enemy sceneBattle_Enemy = chr as SceneBattle_Enemy;
		if (this._waveEnemy != (CharaDef.EnemyMask)0)
		{
			int num = this.MaxMP(chr, true);
			if (chr.newKp > num)
			{
				chr.newKp = num;
			}
			num = this.MaxMP(chr, false);
			if (chr.nowKp > num)
			{
				chr.nowKp = num;
			}
		}
		if (this._pvpAuthAnim == null)
		{
			FieldCameraScaler fieldCameraScaler = null;
			Camera camera = null;
			if (chr.type == CharaDef.Type.FRIENDS)
			{
				int num2 = chr.number - 1;
				if (num2 >= 0 && num2 < this._charaCameraList.Count && this._backCharaList[num2].activeSelf && (fieldCameraScaler = this._charaCameraList[num2]).gameObject.activeSelf)
				{
					camera = this._bgCameraList[num2];
				}
			}
			CharaMotionDefine.ActKey actKey = ((chr.cover == null || (chr.coverStep & 1) == 0 || sceneBattle_Enemy != null) ? CharaMotionDefine.ActKey.IDLING : CharaMotionDefine.ActKey.COVER_LP);
			if (!chr.chara.IsCurrentAnimation(CharaMotionDefine.ActKey.WIN_ST) && !chr.chara.IsCurrentAnimation(CharaMotionDefine.ActKey.WIN_LP))
			{
				if (chr.nowHp < chr.escapeHp)
				{
					actKey = CharaMotionDefine.ActKey.DEATH_LP;
