				chr.effPoison = this.SetAbnormalEffectParam("Ef_buff_poison_lp", chr, chr.abnormalRoot);
			}
		}
		else if (chr.effPoison != null)
		{
			chr.chara.DestroyEffect(chr.effPoison);
			chr.effPoison = null;
		}
		if (flag4 && this.IsSleep(chr, false))
		{
			if (chr.effSleep == null)
			{
				chr.effSleep = this.SetAbnormalEffectParam("Ef_buff_sleep", chr, chr.abnormalHead);
			}
		}
		else if (chr.effSleep != null)
		{
			chr.chara.DestroyEffect(chr.effSleep);
			chr.effSleep = null;
		}
		if (flag4 && this.IsIce(chr, false))
		{
			SceneBattle_Buff sceneBattle_Buff = chr.buff.Find((SceneBattle_Buff itm) => itm.giveupNum <= 0 && itm.buffType == CharaDef.ActionBuffType.ICE);
			int num15 = ((sceneBattle_Buff == null) ? 0 : sceneBattle_Buff.count);
			string text;
			if (chr.type == CharaDef.Type.BOSS)
			{
				if (num15 >= 3)
				{
					text = "Ef_buff_ice_large_boss";
				}
				else if (num15 >= 2)
				{
					text = "Ef_buff_ice_middle_boss";
				}
				else
				{
					text = "Ef_buff_ice_small_boss";
				}
			}
			else if (num15 >= 3)
			{
				text = "Ef_buff_ice_large";
			}
			else if (num15 >= 2)
			{
				text = "Ef_buff_ice_middle";
			}
			else
			{
				text = "Ef_buff_ice_small";
			}
			if (chr.effIce != null && chr.effIce.EffectName != text)
			{
				chr.chara.DestroyEffect(chr.effIce);
				chr.effIce = null;
			}
			if (chr.effIce == null)
			{
				chr.effIce = this.SetAbnormalEffectParam(text, chr, chr.abnormalRoot);
			}
		}
		else if (chr.effIce != null)
		{
			chr.chara.DestroyEffect(chr.effIce);
			chr.effIce = null;
		}
		if (sceneBattle_Friends != null && (SceneBattle.pvpBattle || SceneBattle.friendsBattle || SceneBattle.trainingBattle))
		{
			if (sceneBattle_Friends.chara.IsModelActive() && sceneBattle_Friends.nowHp >= sceneBattle_Friends.escapeHp && this._step > SceneBattle.STEP.WaveStart && this._step < SceneBattle.STEP.WaveClear && (this._cameraType != SceneBattle.CameraType.Command || sceneBattle_Friends.type == CharaDef.Type.INVALID))
			{
				if (sceneBattle_Friends.effBarrier == null)
				{
					sceneBattle_Friends.effBarrier = EffectManager.InstantiateEffect(SceneBattle.trainingBattle ? "Ef_info_pvp_barrier_ryukyu_lp" : "Ef_info_pvp_barrier_lp", sceneBattle_Friends.chara.transform, sceneBattle_Friends.chara.GetLayer(), 1f);
					sceneBattle_Friends.effBarrier.effectObject.transform.localPosition = new Vector3(0f, -999f, 0f);
					sceneBattle_Friends.effBarrier.PlayEffect(false);
					if (SceneBattle.trainingBattle)
					{
						sceneBattle_Friends.effBarrier.SetNormalizedTime(Random.Range(0f, 1f));
					}
					sceneBattle_Friends.chara.SetEffect(sceneBattle_Friends.effBarrier);
				}
			}
			else if (sceneBattle_Friends.effBarrier != null)
			{
				sceneBattle_Friends.chara.DestroyEffect(sceneBattle_Friends.effBarrier);
				sceneBattle_Friends.effBarrier = null;
				if (sceneBattle_Friends.chara.IsModelActive() && sceneBattle_Friends.nowHp < sceneBattle_Friends.escapeHp)
				{
					EffectData effectData6 = EffectManager.InstantiateEffect(SceneBattle.trainingBattle ? "Ef_info_pvp_barrier_ryukyu_break" : "Ef_info_pvp_barrier_break", sceneBattle_Friends.chara.transform, sceneBattle_Friends.chara.GetLayer(), 1f);
					effectData6.effectObject.transform.localPosition = new Vector3(0f, -999f, 0f);
					effectData6.PlayEffect(false);
					sceneBattle_Friends.chara.SetEffect(effectData6);
				}
			}
		}
		if (sceneBattle_Friends != null)
		{
			if (chr.chara.IsCurrentAnimation(CharaMotionDefine.ActKey.STAND_BY_LP))
			{
				if (sceneBattle_Friends.effWait == null && !string.IsNullOrEmpty(sceneBattle_Friends.waitAction.charaEffectName) && (sceneBattle_Friends.effWaitTime += TimeManager.DeltaTime) >= sceneBattle_Friends.waitAction.charaEffectStartOffsetTime)
				{
					int num16 = (sceneBattle_Friends.waitAction.setEffectLayerToLoop ? SceneBattle.effectLayer : sceneBattle_Friends.chara.GetLayer());
					sceneBattle_Friends.effWait = EffectManager.InstantiateEffect(sceneBattle_Friends.waitAction.charaEffectName, sceneBattle_Friends.chara.transform, num16, 1f);
					if (sceneBattle_Friends.chara.GetPartsBodyLayer() == SceneBattle.ignoreLayer)
					{
						sceneBattle_Friends.effWait.effectObject.SetLayerRecursively(SceneBattle.ignoreLayer);
					}
					Vector3 charaEffectOffsetPosition = sceneBattle_Friends.waitAction.charaEffectOffsetPosition;
					if (!sceneBattle_Friends.waitAction.noJoint && sceneBattle_Friends.type == CharaDef.Type.INVALID)
					{
						charaEffectOffsetPosition.x = -charaEffectOffsetPosition.x;
						charaEffectOffsetPosition.z = -charaEffectOffsetPosition.z;
					}
					sceneBattle_Friends.effWait.effectObject.transform.localPosition = charaEffectOffsetPosition;
					sceneBattle_Friends.effWait.effectObject.transform.localEulerAngles = sceneBattle_Friends.waitAction.charaEffectOffsetRotation;
					sceneBattle_Friends.effWait.effectObject.transform.localScale = sceneBattle_Friends.waitAction.charaEffectOffsetScale;
					sceneBattle_Friends.effWait.SetPublisher(sceneBattle_Friends.chara.name);
					sceneBattle_Friends.effWait.PlayEffect(false);
					if (!sceneBattle_Friends.waitAction.noJoint)
					{
						sceneBattle_Friends.chara.SetEffect(sceneBattle_Friends.effWait);
					}
					this._effectDataList.Add(sceneBattle_Friends.effWait);
				}
			}
			else
			{
				EffectData effWait = sceneBattle_Friends.effWait;
			}
			using (List<SceneBattle_Friends>.Enumerator enumerator = this._playerList.GetEnumerator())
			{
				while (enumerator.MoveNext())
				{
					SceneBattle_Friends ply = enumerator.Current;
					ply.chara.DispAccessory(0, ply.nowHp > ply.escapeHp && (this.GetHealthMask(ply, false) & CharaDef.HealthMask.HEALTH) > (CharaDef.HealthMask)0, false);
					ply.chara.DispAccessory(2, this._plyCmdList.Find((SceneBattle_FriendsCommand itm) => itm.chara == ply && itm.step == SceneBattle.CMDSTEP.Attack) != null, false);
				}
			}
			using (List<SceneBattle_Friends>.Enumerator enumerator = this._versusList.GetEnumerator())
			{
				while (enumerator.MoveNext())
				{
					SceneBattle_Friends vss = enumerator.Current;
					vss.chara.DispAccessory(0, vss.nowHp > vss.escapeHp && (this.GetHealthMask(vss, false) & CharaDef.HealthMask.HEALTH) > (CharaDef.HealthMask)0, false);
					vss.chara.DispAccessory(2, this._vssCmdList.Find((SceneBattle_FriendsCommand itm) => itm.chara == vss && itm.step == SceneBattle.CMDSTEP.Attack) != null, false);
				}
			}
		}
	}

	private void UpdateEffectParts(SceneBattle_Enemy emy)
	{
		if (emy.nowHp < emy.escapeHp && !emy.death)
		{
			EffectData effectData = EffectManager.InstantiateEffect(emy.deathEffect, this._effect, SceneBattle.effectLayer, emy.deathEffectScale);
			effectData.effectObject.transform.position = emy.parts.position;
			effectData.PlayEffect(false);
			this._effectDataList.Add(effectData);
			emy.death = true;
			if (emy.modelHandle != null)
			{
				emy.modelHandle.SetMatCap(1f);
				emy.modelHandle.FadeOut(0.25f);
			}
		}
		else if (emy.nowHp >= emy.escapeHp && emy.partsType == CharaDef.PartsType.SUBUNIT && emy.death)
		{
			if (emy.modelHandle != null)
			{
				emy.modelHandle.SetMatCap(0f);
				emy.modelHandle.FadeIn(0.25f);
			}
			EffectData effectData2 = EffectManager.InstantiateEffect("Ef_info_monster_appear", this._effect, SceneBattle.effectLayer, 1f);
			effectData2.effectObject.transform.position = emy.parts.position;
			effectData2.PlayEffect(false);
			emy.death = false;
		}
		bool flag = emy.body.chara.IsModelActive() && emy.body.nowHp > emy.body.escapeHp && this._step < SceneBattle.STEP.GameClear;
		if (flag && this.IsStun(emy, false))
		{
			if (emy.effStun == null)
			{
				emy.effStun = this.SetAbnormalEffectParts("Ef_buff_stun_lp", emy, emy.abnormalHead);
			}
			this.SetAbnormalEffectParts(emy.effStun, emy, emy.abnormalHead);
		}
		else if (emy.effStun != null)
		{
			EffectManager.DestroyEffect(emy.effStun);
			emy.effStun = null;
		}
		if (flag && this.IsPoison(emy, false))
		{
			if (emy.effPoison == null)
			{
				emy.effPoison = this.SetAbnormalEffectParts("Ef_buff_poison_lp", emy, emy.abnormalRoot);
			}
			this.SetAbnormalEffectParts(emy.effPoison, emy, emy.abnormalRoot);
		}
		else if (emy.effPoison != null)
		{
			EffectManager.DestroyEffect(emy.effPoison);
			emy.effPoison = null;
		}
		if (flag && this.IsSleep(emy, false))
		{
			if (emy.effSleep == null)
			{
				emy.effSleep = this.SetAbnormalEffectParts("Ef_buff_sleep", emy, emy.abnormalHead);
			}
			this.SetAbnormalEffectParts(emy.effSleep, emy, emy.abnormalHead);
		}
		else if (emy.effSleep != null)
		{
			EffectManager.DestroyEffect(emy.effSleep);
			emy.effSleep = null;
		}
		if (flag && this.IsIce(emy, false))
		{
			SceneBattle_Buff sceneBattle_Buff = emy.buff.Find((SceneBattle_Buff itm) => itm.giveupNum <= 0 && itm.buffType == CharaDef.ActionBuffType.ICE);
			int num = ((sceneBattle_Buff == null) ? 0 : sceneBattle_Buff.count);
			string text = "Ef_buff_ice_small";
			if (num >= 3)
			{
				text = "Ef_buff_ice_large";
			}
			else if (num >= 2)
			{
				text = "Ef_buff_ice_middle";
			}
			if (emy.effIce != null && emy.effIce.EffectName != text)
			{
				EffectManager.DestroyEffect(emy.effIce);
				emy.effIce = null;
			}
			if (emy.effIce == null)
			{
				emy.effIce = this.SetAbnormalEffectParts(text, emy, emy.abnormalRoot);
			}
			this.SetAbnormalEffectParts(emy.effIce, emy, emy.abnormalRoot);
			return;
		}
		if (emy.effIce != null)
		{
			EffectManager.DestroyEffect(emy.effIce);
			emy.effIce = null;
		}
	}

	private EffectData SetAbnormalEffectParam(string en, SceneBattle_Chara chr, Vector3 prm)
	{
		EffectData effectData = EffectManager.InstantiateEffect(en, this._effect, chr.chara.GetLayer(), 1f);
		Vector3 vector = new Vector3(0f, prm.y, prm.z);
		SceneBattle_Enemy sceneBattle_Enemy = chr as SceneBattle_Enemy;
		if (sceneBattle_Enemy != null)
		{
			vector += new Vector3(sceneBattle_Enemy.hugeX, 0f, chr.offZ);
		}
		effectData.effectObject.transform.localPosition = vector;
		effectData.effectObject.transform.localEulerAngles = chr.chara.transform.localEulerAngles;
		foreach (MeshRenderer meshRenderer in effectData.effectObject.GetComponentsInChildren<MeshRenderer>())
		{
			meshRenderer.transform.localScale = meshRenderer.transform.localScale * prm.x;
		}
		foreach (ParticleSystem particleSystem in effectData.effectObject.GetComponentsInChildren<ParticleSystem>())
		{
			particleSystem.transform.localScale = particleSystem.transform.localScale * prm.x;
		}
		effectData.PlayEffect(false);
		chr.chara.SetEffect(effectData);
		return effectData;
	}

	private EffectData SetAbnormalEffectParts(string en, SceneBattle_Enemy emy, Vector3 prm)
	{
		EffectData effectData = EffectManager.InstantiateEffect(en, this._effect, SceneBattle.enemyLayer, 1f);
		effectData.effectObject.transform.localEulerAngles = emy.body.chara.transform.localEulerAngles;
		foreach (MeshRenderer meshRenderer in effectData.effectObject.GetComponentsInChildren<MeshRenderer>())
		{
			meshRenderer.transform.localScale = meshRenderer.transform.localScale * prm.x;
		}
		foreach (ParticleSystem particleSystem in effectData.effectObject.GetComponentsInChildren<ParticleSystem>())
		{
			particleSystem.transform.localScale = particleSystem.transform.localScale * prm.x;
		}
		effectData.PlayEffect(false);
		return effectData;
	}

	private void SetAbnormalEffectParts(EffectData eff, SceneBattle_Enemy emy, Vector3 prm)
	{
		eff.effectObject.transform.position = emy.parts.position + new Vector3(0f, prm.y, prm.z + emy.offZ);
	}

	private void SetCamouflageEffect(EffectData eff)
	{
		foreach (Transform transform in eff.effectObject.GetComponentsInChildren<Transform>(true))
		{
			if (transform.name.EndsWith("_refraction"))
			{
				transform.gameObject.layer = SceneBattle.camouflageLayer;
				Renderer[] components = transform.GetComponents<Renderer>();
				for (int j = 0; j < components.Length; j++)
				{
					foreach (Material material in components[j].materials)
					{
						material.SetFloat("_Camouflage", 0.9f);
						material.SetFloat("_Alpha", 1f);
					}
				}
			}
		}
	}

	private bool Poison(SceneBattle_Chara chr)
	{
		SceneBattle_Chara sceneBattle_Chara = ((chr.chara == null || chr.nowHp > chr.escapeHp) ? this.GetAbnormalChara(CharaDef.ActionBuffType.POISON, chr, false) : null);
		if (sceneBattle_Chara == null)
		{
			return false;
		}
		bool flag = chr.nowHp > chr.escapeHp + 1 && chr.guts > 0;
		float num = this._battleParam.poisonFriends;
		bool flag2 = this._invincibleEnemy;
		if (chr.type == CharaDef.Type.BOSS)
		{
			num = this._battleParam.poisonBoss;
		}
		else if (chr.type == CharaDef.Type.PARTS)
		{
			num = this._battleParam.poisonBoss;
		}
		else if (chr.type == CharaDef.Type.ENEMY)
		{
			num = this._battleParam.poisonEnemy;
		}
		else if (chr.type == CharaDef.Type.FRIENDS)
		{
			flag2 = this._invinciblePlayer;
		}
		int num2 = (int)((float)chr.maxHp * num);
		if (num2 < 1)
		{
			num2 = 1;
		}
		SceneBattle_Enemy sceneBattle_Enemy = chr as SceneBattle_Enemy;
		bool flag3 = false;
		if (sceneBattle_Enemy != null && sceneBattle_Enemy.body != null && sceneBattle_Enemy.nowHp <= sceneBattle_Enemy.escapeHp)
		{
			flag3 = true;
		}
		this.SetDamage(chr, num2, false, (CharaDef.AttributeMask)0, (CharaDef.AttributeMask)0, 0, false, 0, flag3, 1f);
		if (chr.chara == null && chr.nowHp <= chr.escapeHp)
		{
			SceneBattle_Enemy body = (chr as SceneBattle_Enemy).body;
			int num3 = 0;
			if (this.GetAbnormalChara(CharaDef.ActionBuffType.POISON, body, false) != null)
			{
				if ((num3 = (int)((float)body.maxHp * num)) < 1)
				{
					num3 = 1;
				}
				num3 += num2;
			}
			this.SetDamage(body, num2, false, (CharaDef.AttributeMask)0, (CharaDef.AttributeMask)0, num3, false, 0, false, 1f);
			flag = body.nowHp > body.escapeHp + 1 && body.guts > 0;
			if (!flag2 && (body.nowHp -= num2) <= body.escapeHp)
			{
				body.nowHp = body.escapeHp;
				if (flag)
				{
					body.guts--;
					body.nowHp++;
				}
			}
			this.CheckDead(body, true);
			if (body.type != CharaDef.Type.FRIENDS && sceneBattle_Chara.type == CharaDef.Type.FRIENDS)
			{
				this._lastDamageFriends = sceneBattle_Chara.idx;
			}
			body.newHp = body.nowHp;
			return body.nowHp <= body.escapeHp;
		}
		if (!flag2 && (chr.nowHp -= num2) <= chr.escapeHp)
		{
			chr.nowHp = chr.escapeHp;
			if (flag)
			{
				chr.guts--;
				chr.nowHp++;
			}
		}
		this.CheckDead(chr, true);
		if (chr.type != CharaDef.Type.FRIENDS && sceneBattle_Chara.type == CharaDef.Type.FRIENDS)
		{
			this._lastDamageFriends = sceneBattle_Chara.idx;
		}
		chr.newHp = chr.nowHp;
		return chr.chara != null && chr.nowHp <= chr.escapeHp;
	}

	private int Bleed()
	{
		int num = 0;
		while (this._bleedChrList.Count > 0)
		{
			SceneBattle_Chara chr = this._bleedChrList[0];
			SceneBattle_Chara sceneBattle_Chara = ((chr.nowHp > chr.escapeHp) ? this.GetAbnormalChara(CharaDef.ActionBuffType.BLEED, chr, false) : null);
			if (sceneBattle_Chara != null)
			{
				int count = this._bleedChrList.FindAll((SceneBattle_Chara itm) => itm == chr).Count;
				bool flag = chr.nowHp > chr.escapeHp + 1 && chr.guts > 0;
				float num2 = this._battleParam.bleedFriends;
				bool flag2 = this._invincibleEnemy;
				if (chr.type == CharaDef.Type.BOSS)
				{
					num2 = this._battleParam.bleedBoss;
				}
				else if (chr.type == CharaDef.Type.PARTS)
				{
					num2 = this._battleParam.bleedBoss;
				}
				else if (chr.type == CharaDef.Type.ENEMY)
				{
					num2 = this._battleParam.bleedEnemy;
				}
				else if (chr.type == CharaDef.Type.FRIENDS)
				{
					flag2 = this._invinciblePlayer;
				}
				int num3 = (int)((float)chr.maxHp * num2) * count;
				this.SetDamage(chr, num3, false, (CharaDef.AttributeMask)0, (CharaDef.AttributeMask)0, 0, false, 0, false, 1f);
				if (!flag2 && (chr.nowHp -= num3) <= chr.escapeHp)
				{
					chr.nowHp = chr.escapeHp;
					if (flag)
					{
						chr.guts--;
						chr.nowHp++;
					}
					else
					{
						num++;
					}
				}
				this.CheckDead(chr, true);
				if (chr.type != CharaDef.Type.FRIENDS && sceneBattle_Chara.type == CharaDef.Type.FRIENDS)
				{
					this._lastDamageFriends = sceneBattle_Chara.idx;
				}
				chr.newHp = chr.nowHp;
			}
			this._bleedChrList.RemoveAll((SceneBattle_Chara itm) => itm == chr);
		}
		return num;
	}

