			num2 = -1;
			break;
		case CharaDef.ActionBuffType.UNHEAL:
			text3 = "SEAL";
			num2 = -1;
			break;
		case CharaDef.ActionBuffType.REFLECT:
			num3 = inf.Updw;
			num2 = -1;
			break;
		case CharaDef.ActionBuffType.ANTI_REFLECT:
			num2 = -1;
			break;
		case CharaDef.ActionBuffType.MP_NOCOUNT:
			text3 = "SEAL";
			num2 = -1;
			break;
		case CharaDef.ActionBuffType.RCV_ALLDAMAGE:
			text = "全体攻撃による被ダメージ";
			text2 = (isGood ? "軽減" : "増加");
			break;
		case CharaDef.ActionBuffType.HATE_HALF:
			text = "いかく、かくれみ効果半減";
			num2 = -1;
			break;
		case CharaDef.ActionBuffType.BUFF_INVALID:
			num2 = -1;
			break;
		case CharaDef.ActionBuffType.PARALYSIS:
			text3 = "SEAL";
			num2 = -1;
			break;
		case CharaDef.ActionBuffType.SILENCE:
			text3 = "SEAL";
			num2 = -1;
			break;
		case CharaDef.ActionBuffType.HEAL_AMOUNT:
		case CharaDef.ActionBuffType.MP_AMOUNT:
			text2 = (isGood ? "アップ" : "ダウン");
			break;
		case CharaDef.ActionBuffType.INAUDIBLE:
			text3 = "SEAL";
			num2 = -1;
			break;
		case CharaDef.ActionBuffType.BURNED:
			text3 = "SEAL";
			num2 = -1;
			break;
		case CharaDef.ActionBuffType.FOCUS:
			text3 = "SEAL";
			num2 = -1;
			num3 = inf.Turn;
			break;
		case CharaDef.ActionBuffType.IMPATIENCE:
			num2 = -1;
			break;
		}
		if (text3 == "BUFF" && !isGood)
		{
			text3 = "DEBUFF";
		}
		Transform transform = obj.Find("Txt_Status");
		transform.GetComponent<PguiTextCtrl>().text = text + text2;
		transform.GetComponent<PguiGradientCtrl>().SetGameObjectById(text3);
		transform.gameObject.SetActive(inf.Arts == 0);
		text = string.Concat(new string[]
		{
			text,
			"<size=28>",
			Mathf.Abs(inf.Arts).ToString(),
			"%</size>",
			text2
		});
		Transform transform2 = obj.Find("Txt_Status_DmageUp");
		transform2.GetComponent<PguiTextCtrl>().text = text;
		transform2.gameObject.SetActive(inf.Arts != 0 && isGood);
		Transform transform3 = obj.Find("Txt_Status_DmageDown");
		transform3.GetComponent<PguiTextCtrl>().text = text;
		transform3.gameObject.SetActive(inf.Arts != 0 && !isGood);
		this.SetStatIcon(obj.Find("Null_StatusIcon").GetChild(0), num, num2, flag, num3, inf.Giveup);
		obj.GetComponent<SimpleAnimation>().ExPlayAnimation(isGood ? SimpleAnimation.ExPguiStatus.LOOP : SimpleAnimation.ExPguiStatus.LOOP_SUB, null);
	}

	private void HpGageStatOff(SceneBattle_Chara chr)
	{
		if (chr.goodStat.Count > 0 && chr.goodStatTim >= 0f)
		{
			chr.goodStat.RemoveAt(0);
		}
		if (chr.badStat.Count > 0 && chr.badStatTim >= 0f)
		{
			chr.badStat.RemoveAt(0);
		}
		chr.goodStatTim = (chr.badStatTim = -1f);
		chr.hpGage.transform.Find("Null_StatusInfo_Up").gameObject.SetActive(false);
		chr.hpGage.transform.Find("Null_StatusInfo_Down").gameObject.SetActive(false);
		if (chr.type == CharaDef.Type.FRIENDS)
		{
			Transform transform = this._guiData.Chara[chr.number - 1].transform.Find("Card");
			transform.Find("Null_StatusInfo_Up").gameObject.SetActive(false);
			transform.Find("Null_StatusInfo_Down").gameObject.SetActive(false);
		}
	}

	private string GetDmgName(GameObject gage)
	{
		string text = gage.name + "_";
		int num = 1;
		if (this._damageNoDictionary.ContainsKey(text))
		{
			using (IEnumerator enumerator = this._guiData.NumDamage.GetEnumerator())
			{
				while (enumerator.MoveNext())
				{
					if (((Transform)enumerator.Current).name.StartsWith(text))
					{
						if ((num = this._damageNoDictionary[text] + 1) > SceneBattle.damageDispPos.Length)
						{
							num = 1;
							break;
						}
						break;
					}
				}
			}
		}
		this._damageNoDictionary[text] = num;
		return text + num.ToString();
	}

	private void SetDamage(SceneBattle_Chara chr, int dmg, bool arts, CharaDef.AttributeMask atk, CharaDef.AttributeMask tag, int total, bool chain, int per, bool brk, float dup)
	{
		if (SceneBattle.trainingBattle && chr is SceneBattle_Enemy)
		{
			this._trainingScore += (long)dmg;
			this.SetTrainingScore(false);
		}
		else if (SceneBattle.pvpTraining != 0)
		{
			if (chr.type == CharaDef.Type.FRIENDS)
			{
				this._pvpTrainingScoreVersus += (long)dmg;
			}
			else
			{
				this._pvpTrainingScorePlayer += (long)dmg;
			}
		}
		int num = 99999999;
		if (dmg > num)
		{
			dmg = num;
		}
		if (total > num)
		{
			total = num;
		}
		float buffAttr = this.GetBuffAttr(atk, tag);
		string text = ((dmg > 0) ? dmg.ToString() : "MISS");
		string text2 = ((per > 0) ? (chr.hpGage.name + "_" + (SceneBattle.damageDispPos.Length + per).ToString()) : this.GetDmgName(chr.hpGage));
		string text3 = "";
		if (dup >= 3f)
		{
			text3 = "Info_DamageUp_L";
		}
		else if (dup >= 2.25f)
		{
			text3 = "Info_DamageUp_M";
		}
		else if (dup >= 1.5f)
		{
			text3 = "Info_DamageUp_S";
		}
		GameObject gameObject;
		Transform transform3;
		if (arts)
		{
			gameObject = Object.Instantiate<GameObject>(brk ? this._numDamageArtsB : ((buffAttr > 1f) ? this._numDamageArtsP : ((buffAttr < 1f) ? this._numDamageArtsM : this._numDamageArts)));
			gameObject.SetActive(true);
			gameObject.name = text2;
			gameObject.transform.SetParent(this._guiData.NumDamage, false);
			SimpleAnimation componentInChildren = gameObject.GetComponentInChildren<SimpleAnimation>();
			componentInChildren.ExPlayAnimation(SimpleAnimation.ExPguiStatus.START, null);
			Transform transform = componentInChildren.transform.Find("NumAll");
			int num2 = 1;
			for (;;)
			{
				Transform transform2 = transform.Find("num_0" + num2.ToString());
				if (transform2 == null)
				{
					break;
				}
				if (text.Length < num2)
				{
					transform2.gameObject.SetActive(false);
				}
				else
				{
					transform2.GetComponent<PguiTextCtrl>().text = text.Substring(num2 - 1, 1);
				}
				num2++;
			}
			transform3 = componentInChildren.transform.Find("DamageUp_Info");
		}
		else
		{
			gameObject = Object.Instantiate<GameObject>(brk ? this._numDamageBrk : ((per > 0) ? this._numDamagePer : ((buffAttr > 1f) ? this._numDamagePlus : ((buffAttr < 1f) ? this._numDamageMinus : this._numDamageNorm))));
			gameObject.SetActive(true);
			gameObject.name = text2;
			gameObject.transform.SetParent(this._guiData.NumDamage, false);
			SimpleAnimation componentInChildren2 = gameObject.GetComponentInChildren<SimpleAnimation>();
			componentInChildren2.ExPlayAnimation(SimpleAnimation.ExPguiStatus.START, null);
			if (per > 0)
			{
				Text component = componentInChildren2.transform.Find("Num").GetComponent<Text>();
				component.fontSize = ((per > 1) ? 48 : 40);
				component.text = ((total > 0) ? total.ToString() : "MISS");
				component.transform.Find("Num").GetComponent<PguiTextCtrl>().text = "＋わりあい " + text;
			}
			else
			{
				componentInChildren2.transform.Find("Num").GetComponent<PguiTextCtrl>().text = text;
			}
			transform3 = componentInChildren2.transform.Find("DamageUp_Info");
		}
		PguiAECtrl componentInChildren3 = gameObject.GetComponentInChildren<PguiAECtrl>();
		componentInChildren3.gameObject.SetActive(chain);
		if (componentInChildren3.gameObject.activeSelf)
		{
			componentInChildren3.PlayAnimation(PguiAECtrl.AmimeType.START, null);
		}
		foreach (object obj in transform3)
		{
			Transform transform4 = (Transform)obj;
			transform4.gameObject.SetActive(transform4.name == text3 && total <= 0);
		}
		if (per <= 0 && total > 0)
		{
			gameObject = Object.Instantiate<GameObject>(brk ? this._numDamageTotalB : ((buffAttr > 1f) ? this._numDamageTotalP : ((buffAttr < 1f) ? this._numDamageTotalM : this._numDamageTotal)));
			gameObject.SetActive(true);
			gameObject.name = chr.hpGage.name + "_1";
			gameObject.transform.SetParent(this._guiData.NumDamage, false);
			SimpleAnimation componentInChildren4 = gameObject.GetComponentInChildren<SimpleAnimation>();
			componentInChildren4.ExPlayAnimation(SimpleAnimation.ExPguiStatus.START, null);
			componentInChildren4.transform.Find("Num").GetComponent<PguiTextCtrl>().text = total.ToString();
			transform3 = componentInChildren4.transform.Find("DamageUp_Info");
			foreach (object obj2 in transform3)
			{
				Transform transform5 = (Transform)obj2;
				transform5.gameObject.SetActive(transform5.name == text3);
			}
		}
		if (dmg > 0 && chr.dmgAE != null)
		{
			chr.dmgAE.playTime = 0f;
		}
		if (dmg <= 0)
		{
			SoundManager.Play("prd_se_attack_miss", false, false);
		}
	}

	private void SetTrainingScore(bool ini)
	{
		int num = 1;
		if (this._trainingScore >= 10000000L)
		{
			num = 6;
		}
		else if (this._trainingScore >= 1000000L)
		{
			num = 5;
		}
		else if (this._trainingScore >= 500000L)
		{
			num = 4;
		}
		else if (this._trainingScore >= 100000L)
		{
			num = 3;
		}
		else if (this._trainingScore >= 50000L)
		{
			num = 2;
		}
		bool flag = this._trainingScore > this._resultArgs.battleArgs.trainingScore;
		this.SetTrainingScore(this._guiData.TrainingScoreL, num, flag, ini);
		this.SetTrainingScore(this._guiData.TrainingScoreR, num, flag, ini);
		if (!ini && !this._trainingScoreNR && flag)
		{
			this.SetTrainingVoice(2, 0f);
			SoundManager.Play("prd_se_total_damage_achievement", false, false);
		}
		this._trainingScoreNR = flag;
	}

	private void SetTrainingScore(HorizontalLayoutGroup tmp, int typ, bool nr, bool ini)
	{
		int num = 1;
		for (;;)
		{
			Transform transform = tmp.transform.Find("Num_Score" + num.ToString("D2"));
			if (transform == null)
			{
				break;
			}
			transform.gameObject.SetActive(typ == num);
			transform.GetComponent<PguiTextCtrl>().ReplaceTextByDefault("Param01", this._trainingScore.ToString());
			num++;
		}
		PguiAECtrl aeCtrl = tmp.transform.parent.Find("AEImage_NewRecord").GetComponent<PguiAECtrl>();
		aeCtrl.gameObject.SetActive(nr);
		if (nr)
		{
			if (ini)
			{
				aeCtrl.PlayAnimation(PguiAECtrl.AmimeType.LOOP, null);
				return;
			}
			if (!this._trainingScoreNR)
			{
				aeCtrl.PlayAnimation(PguiAECtrl.AmimeType.START, delegate
				{
					aeCtrl.PlayAnimation(PguiAECtrl.AmimeType.LOOP, null);
				});
			}
		}
	}

	private void SetHeal(SceneBattle_Chara chr, int heal, bool eff = false)
	{
		chr.helHp = ((heal > 0) ? heal.ToString() : "MISS");
		if (heal <= 0)
		{
			SoundManager.Play("prd_se_attack_miss", false, false);
		}
		if (chr.type == CharaDef.Type.FRIENDS && this._backDeckAll.activeSelf)
		{
			return;
		}
		GameObject gameObject = Object.Instantiate<GameObject>(this._numHeal);
		gameObject.SetActive(true);
		gameObject.name = this.GetDmgName(chr.hpGage);
		gameObject.transform.SetParent(this._guiData.NumDamage, false);
		SimpleAnimation componentInChildren = gameObject.GetComponentInChildren<SimpleAnimation>();
		componentInChildren.ExPlayAnimation(SimpleAnimation.ExPguiStatus.START, null);
		componentInChildren.transform.Find("Num").GetComponent<PguiTextCtrl>().text = chr.helHp;
		if (eff)
		{
			SceneBattle_Enemy sceneBattle_Enemy = chr as SceneBattle_Enemy;
			if (chr.chara == null)
			{
				EffectData effectData = EffectManager.InstantiateEffect("Ef_buff_heal", this._effect, SceneBattle.effectLayer, 1f);
				effectData.effectObject.transform.position = sceneBattle_Enemy.parts.position;
				float num = 1f;
				if (chr.width < 1.5f)
				{
					num = 0.6f;
				}
				else if (chr.width >= 3f)
				{
					num = 1.5f;
				}
				effectData.effectObject.transform.localScale = Vector3.one * num;
				effectData.PlayEffect(false);
				this._effectDataList.Add(effectData);
				return;
			}
			EffectData effectData2 = EffectManager.InstantiateEffect("Ef_buff_heal", this._effect, chr.chara.GetLayer(), 1f);
			if (sceneBattle_Enemy != null)
			{
				effectData2.effectObject.transform.localPosition = new Vector3(sceneBattle_Enemy.hugeX, 0f, chr.offZ);
			}
			float num2 = 1f;
			if (chr.width < 1.5f)
			{
				num2 = 0.6f;
			}
			else if (chr.width >= 3f)
			{
				num2 = 1.5f;
			}
			effectData2.effectObject.transform.localScale = Vector3.one * num2;
			effectData2.PlayEffect(false);
			chr.chara.SetEffect(effectData2);
		}
	}

	private void DispWaitAction(Transform tmp)
	{
		if (this._noCaptain || SceneBattle.pvpTraining != 0)
		{
			return;
		}
		int i = 0;
		while (i < this._guiData.TouchWait.Count)
		{
			if (tmp == this._guiData.TouchWait[i])
			{
				int num = -1;
				SceneBattle_Friends sceneBattle_Friends = this._playerList.Find((SceneBattle_Friends itm) => itm.number == i + 1);
				if (sceneBattle_Friends == null)
				{
					break;
				}
				if (sceneBattle_Friends.waitAction.activationNum >= 0 && (num = sceneBattle_Friends.waitAction.activationNum - sceneBattle_Friends.waitCount) < 0)
				{
					num = 0;
				}
				if (this._tutorialStep == SceneBattle.TutorialStep.NONE && num != 0 && !this.IsStun(sceneBattle_Friends, false) && !this.IsSleep(sceneBattle_Friends, false) && !this.IsIce(sceneBattle_Friends, false) && !this.IsImpatience(sceneBattle_Friends, false))
				{
					sceneBattle_Friends.isWaitAct = !sceneBattle_Friends.isWaitAct;
					SoundManager.Play("prd_se_click", false, false);
					this.DispWaitAction(tmp, sceneBattle_Friends.isWaitAct, num, false);
					return;
				}
				break;
			}
			else
			{
				int j = i;
				i = j + 1;
			}
		}
	}

	private void DispWaitAction(SceneBattle_Friends ply)
	{
		int num = -1;
		if (ply.waitAction.activationNum >= 0 && (num = ply.waitAction.activationNum - ply.waitCount) < 0)
		{
			num = 0;
		}
		this.DispWaitAction(this._guiData.TouchWait[ply.number - 1], ply.isWaitAct, num, this.IsStun(ply, false) || this.IsSleep(ply, false) || this.IsIce(ply, false) || this.IsImpatience(ply, false));
	}

	private void DispWaitAction(Transform tmp, bool b, int n, bool dis)
	{
		tmp.Find("BaseImage").gameObject.SetActive(n != 0);
		tmp.Find("BaseImage").GetComponent<PguiReplaceSpriteCtrl>().Replace(this._noCaptain ? 3 : (b ? 2 : 1));
		tmp.Find("Txt_StaySkill").GetComponent<PguiGradientCtrl>().SetGameObjectById(b ? "ON" : "OFF");
		tmp.Find("Txt_StaySkill").GetComponent<PguiTextCtrl>().text = "<size=12>たいき </size> " + ((n < 0) ? "   " : n.ToString());
		tmp.Find("Img_Mugen").gameObject.SetActive(n < 0);
		tmp.Find("Mark_Lock_StaySkill").gameObject.SetActive(dis);
	}

	private SceneBattle_CardInfo GetCard(CharaStaticBase baseData)
	{
		SceneBattle_CardInfo sceneBattle_CardInfo;
		for (;;)
		{
			if (this._stackCardList.Count <= 0)
			{
				while (this._disCardList.Count > 0)
				{
					int num = Random.Range(0, this._disCardList.Count);
					this._stackCardList.Add(this._disCardList[num]);
					this._disCardList.RemoveAt(num);
				}
			}
			sceneBattle_CardInfo = null;
			int num2 = 0;
			if (baseData != null && !baseData.isSpecialFlagSupported && this._stackCardList[0].card.type == CharaDef.OrderCardType.SPECIAL)
			{
				int num3 = this._stackCardList.Count<SceneBattle_CardInfo>((SceneBattle_CardInfo item) => item.card.type == CharaDef.OrderCardType.SPECIAL);
				int num4 = this._stackCardList.Count<SceneBattle_CardInfo>((SceneBattle_CardInfo item) => item.card.type == CharaDef.OrderCardType.BEAT);
				int num5 = this._stackCardList.Count<SceneBattle_CardInfo>((SceneBattle_CardInfo item) => item.card.type == CharaDef.OrderCardType.BEAT);
				if (num3 >= this._stackCardList.Count || (num4 == 0 && num5 == 0))
				{
					for (int i = 0; i < this._stackCardList.Count; i++)
					{
						this._disCardList.Add(this._stackCardList[i]);
					}
					this._stackCardList.RemoveRange(0, this._stackCardList.Count);
					continue;
				}
				if (num4 == 0)
				{
					num2 = this._disCardList.FindIndex((SceneBattle_CardInfo item) => item.card.type == CharaDef.OrderCardType.BEAT);
				}
				else
				{
					num2 = this._stackCardList.FindIndex((SceneBattle_CardInfo item) => item.card.type == CharaDef.OrderCardType.BEAT);
				}
				sceneBattle_CardInfo = this._stackCardList[num2];
			}
			if (sceneBattle_CardInfo == null)
			{
				sceneBattle_CardInfo = this._stackCardList[0];
			}
			this._stackCardList.RemoveAt(num2);
			if (this._tutorialOrderList.Count <= 0)
			{
				return sceneBattle_CardInfo;
			}
			if (sceneBattle_CardInfo.card.type == this._tutorialOrderList[0])
			{
				break;
			}
			this._disCardList.Add(sceneBattle_CardInfo);
		}
		this._tutorialOrderList.RemoveAt(0);
		return sceneBattle_CardInfo;
	}

	private void DispCardInfo()
	{
		string text = "";
		string text2 = "";
		this._guiData.CardInfo.text = text;
		this._guiData.CardInfoV.text = text2;
	}

	private void SetPlayerTarget(int idx)
	{
		if (SceneBattle.pvpBattle || SceneBattle.friendsBattle)
		{
			if (idx >= 0)
			{
				SceneBattle_Friends sceneBattle_Friends = this._versusList.Find((SceneBattle_Friends itm) => itm.idx == idx && itm.nowHp > itm.escapeHp);
				if (sceneBattle_Friends != null)
				{
					this._playerTarget = sceneBattle_Friends;
				}
			}
			if (idx < 0 || this._playerTarget == null || this._playerTarget.nowHp <= this._playerTarget.escapeHp)
			{
				this._playerTarget = this._versusList.Find((SceneBattle_Friends itm) => itm.nowHp > itm.escapeHp);
				return;
			}
		}
		else
		{
			List<SceneBattle_Enemy> list = this._emyWaveList.FindAll((SceneBattle_Enemy itm) => itm.nowHp > itm.escapeHp);
			if (list.Find((SceneBattle_Enemy itm) => itm.huge > 1) != null)
			{
				list.RemoveAll((SceneBattle_Enemy itm) => itm.huge == 1);
			}
			if (idx >= 0)
			{
				SceneBattle_Enemy sceneBattle_Enemy = list.Find((SceneBattle_Enemy itm) => itm.idx == idx);
				if (sceneBattle_Enemy != null)
				{
					this._playerTarget = sceneBattle_Enemy;
				}
			}
			list.RemoveAll((SceneBattle_Enemy itm) => itm.body != null);
			if (idx < 0 || this._playerTarget == null || this._playerTarget.nowHp <= this._playerTarget.escapeHp)
			{
				this._playerTarget = ((list.Count > 0) ? list[0] : null);
			}
		}
	}

	private void SetEnemyTarget()
	{
		Dictionary<int, int> dictionary = new Dictionary<int, int>();
		int num = 0;
		foreach (SceneBattle_Friends sceneBattle_Friends in this._playerList)
		{
			if (sceneBattle_Friends.nowHp > sceneBattle_Friends.escapeHp)
			{
				int num2 = ((sceneBattle_Friends.inBack == 0) ? SceneBattle.hateBase : SceneBattle.hateWait);
				float num3 = 1f;
				int num4 = 0;
				this.GetBuffParam(CharaDef.ActionBuffType.HATE, sceneBattle_Friends, (CharaDef.AttributeMask)0, (CharaDef.HealthMask)0, (CharaDef.EnemyMask)0, out num3, out num4);
				int num5 = 0;
				if (this.GetBuffParam(CharaDef.ActionBuffType.HATE_HALF, sceneBattle_Friends, (CharaDef.AttributeMask)0, (CharaDef.HealthMask)0, (CharaDef.EnemyMask)0, out num3, out num5))
				{
					num4 /= 2;
				}
				if ((num2 += num4) < 1)
				{
					num2 = 1;
				}
				dictionary.Add(sceneBattle_Friends.idx, num2);
				num += num2;
			}
		}
		this._enemyTarget = null;
		if (num > 0)
		{
			num = Random.Range(0, num);
			foreach (KeyValuePair<int, int> keyValuePair in dictionary)
			{
				if ((num -= keyValuePair.Value) < 0)
				{
					this._enemyTarget = this._playerList[keyValuePair.Key];
					break;
				}
			}
		}
	}

	private void SetTimer(float tim)
	{
		this._timer = tim;
	}

	private bool IsTimeOut()
	{
		return this._timer <= 0f;
	}

	public override void OnStopControl()
	{
		this._tutorialPanel.SetActive(false);
		CanvasManager.HdlTutorialMaskCtrl.SetEnable(false);
		CanvasManager.HdlTutorialMaskCtrl.SetBlackMask(false);
		CanvasManager.HdlTutorialMaskCtrl.SetFrame(0, false, null, true, null);
