	public override bool OnDisableSceneWait()
	{
		bool flag = !DataManager.IsServerRequesting();
		if (this._debugDataReload != null)
		{
			flag = false;
			if (!this._debugDataReload.MoveNext())
			{
				this._debugDataReload = null;
			}
		}
		if (flag && this._autoOrder >= 0 && ((this._autoOrder > 0) ^ DataManager.DmUserInfo.optionData.battleAutoFlag[(int)this._questCategory]))
		{
			DataManager.DmUserInfo.RequestActionUpdateBattleAutoFlag(this._questCategory, DataManager.DmUserInfo.optionData.battleAutoFlag[(int)this._questCategory] = this._autoOrder > 0);
		}
		if (flag && this._timeScale >= 0 && ((this._timeScale > 0) ^ DataManager.DmUserInfo.optionData.battleSpeedFlag[(int)this._questCategory]))
		{
			DataManager.DmUserInfo.RequestActionUpdateBattleSpeedFlag(this._questCategory, DataManager.DmUserInfo.optionData.battleSpeedFlag[(int)this._questCategory] = this._timeScale > 0);
		}
		if (flag)
		{
			PlayerPrefs.DeleteKey(SceneBattle.battleRestartKey);
		}
		return flag;
	}

